/* characters q22 (44 mục) — R2.6 bồi tiểu sử Hình Phạt Lục Mặc */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q22"]=window.__LIBQ["tien-nghich"]["q22"]||{};window.__LIBQ["tien-nghich"]["q22"]["characters"]={"updatedAt":"2026-07-17","count":44,"chars":[{"id":"vuong-lam","name":"Vương Lâm","cn":"王林","aliases":["Thiết Trụ","Hứa Mộc"],"gioiTinh":"nam","canhGioiCaoNhat":"Phân Thần Kiếp — lần đầu phân thần thành (hoàn mỹ) @c1944","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Đưa Tống Trí trở về Hắc Thạch Thành, suốt gần hai năm đi đường đã dùng tu vi tách tàn hồn Lý Mộ Uyển khỏi thân thể Tống Trí mà không tổn thương nàng. Để lại ngọc giản có thần niệm bảo đảm Tống Trí bình an cả đời, dặn Kế Đô xử lý. Vào mật thất hành cung Kế Đô bế quan, bố trí cấm chế mạnh mẽ khiến Đại Thiên Tôn cũng không thể lén vào. Suy tính cần thêm Hồn Huyết cho Lý Mộ Uyển chịu áp lực Thái Cổ Thần Cảnh, mục tiêu tới Tổ Miếu Cổ Tộc vượt tam tổn kiếp cuối cùng để cổ Tổ tán thành lần nữa nhận Hồn Huyết, quyền mở Tổ Miếu thuộc hoàng tôn nên giúp Kế Đô. Triệu xuất quan tài trong suốt chứa Lý Mộ Uyển, lấy tàn hồn từ mi tâm mình đưa vào mi tâm nàng, hoàn chỉnh hồn phách. Lông mi nàng run rẩy như sắp tỉnh rồi yên tĩnh, hai hàng nước mắt chảy xuống. Tự nhủ: năm trăm năm cuối cùng.","anchor":"Uyển nhi, Từ nay về sau hồn phách của nàng đã hoàn chỉnh rồi","bridge":true,"khoang":"@c1930"},{"importance":"normal","mucCt":"ky","chuong":"@c1931","tieuDe":"Bế quan chín năm, phân tách sát lục lôi đình","text":"Chia tay Lý Mộ Uyển trong quan tài, lau nước mắt, hôn lên đôi môi tái nhợt của nàng rồi thì thầm bên tai nàng, sau đó thu quan tài đi. Lấy hồn Tiên Hoàng ra dùng lửa linh hồn luyện hóa nhằm trừ Trớ Thuật. Bế quan chín năm trong mật thất hành cung Kế Đô: ba năm đầu tu vi và sức mạnh Cổ Tộc lưu chuyển hoàn mỹ, ngũ hành chân thân viên mãn gần cực hạn chỉ thiếu một bước thành chân thần. Năm thứ sáu sát lục lôi đình chân thân tách khỏi bản thể, năm thứ chín hư ảnh thứ ba xuất hiện nhưng chưa ngưng tụ hình dáng. Đẩy tu vi và sức mạnh Cổ Tộc lên đỉnh điểm, xác nhận tu vi hiện tại là Không Kiếp đại viên mãn. Tự đánh giá có thể đánh ngang hoặc dồn ép Đạo Nhất Đại Thiên Tôn, gần bằng Võ Phong, không hơn Cửu Đế, có thể đánh Tống Thiên nhưng thắng bại chưa biết. Nhận ra Thiên Tôn và Dược Thiên Tôn thực chất đều là Không Kiếp đại viên mãn, bước tiếp theo khi sát lục lôi đình chân thân đại thành có thể là Đại Thiên Tôn. Phân tách sát lục lôi đình chân thân thành năm bản nguyên: lôi đình đã thành chân thân, sát lục, cấm chế, thái sơ, mặc diệt mới đại thành. Biến trần mật thất thành bầu trời, ném thái sơ bản nguyên lên hóa mặt trời hào quang vạn trượng bắt đầu luyện theo quy tắc thiên địa. Quyết tâm không xuất quan nếu tu vi chưa tăng, mục tiêu chiến thắng Tống Thiên, buộc Kế Đô thành hoàng tôn để vào Tổ Miếu.","anchor":"Hiện giờ hắn có lòng tin có thể đánh một trận với Đạo Nhất Đại Thiên Tôn vào lúc sung sức nhất mà không bị rơi vào thế hạ phong"},{"mucCt":"ky","text":"Dùng Lưu Nguyệt Thuật tạo chu kỳ ngày đêm luân phiên trên trần mật thất, tách nguyên thần dung nhập để cảm ngộ thái sơ và mặc diệt bản nguyên. Sai ngũ hành chân thân hóa năm luồng sáng dung nhập cấm chế bản nguyên, thay hắn dung hợp lượng lớn cấm chế trận pháp. Cho lôi đình chân thân nuốt sát lục bản nguyên, toàn thân hóa đen, rồi chồng sát lục lôi đình chân thân lên bản thể, liên tục bắt quyết điểm chỉ cho tới khi dung hợp hoàn toàn không còn hư ảnh. Cắn lưỡi phun máu thi triển huyết luyện để luyện hóa Lục Mặc — lần thứ hai luyện hóa sát lục lôi đình. Bế quan nhiều năm rồi xuất quan, luồng khí tức phóng lên chín tầng trời gây thiên địa dị tượng, bầu trời sụp đổ xuất hiện vô số mảnh vỡ.","anchor":"Sát lục lôi đình lại một lần nữa giáng xuống!","bridge":true,"khoang":"@c1932"},{"mucCt":"ky","text":"Sau một trăm năm bế quan tại hành cung Kế Đô hoàng tử trong La Miên Quận, Vương Lâm phát ra uy áp kinh thiên bao phủ cả quận khiến gần ngàn thị vệ run rẩy. Tiến hành dung hợp chân thân — năm đạo cầu vồng (ngũ hành chân thân) lao ra hợp nhất thành hư ảnh hình Vương Lâm, hút sức mạnh ngũ hành thiên địa bành trướng lên ngàn trượng. Quá trình ban đầu gặp bất ổn khi ba đạo bản nguyên (cấm chế, thái sơ, mặc diệt) có dấu hiệu tan vỡ, ký hiệu cấm chế bắt đầu tan rã, nhưng ngũ hành chân thân ổn định lại. Tống Thiên Đại Thiên Tôn ra ấn ký Giải phong can thiệp từ xa. Từ sâu lòng đất, mãnh thú La Miên gào thét xuất hiện, nhìn ngũ hành chân thân với vẻ tham lam.","anchor":"Hình dáng hư ảnh này bất ngờ chính là Vương Lâm!","bridge":true,"khoang":"@c1933"},{"mucCt":"ky","text":"Mở mắt sau mấy trăm năm bế quan trong mật thất hành cung, tiết lộ hai mươi ngày trước đã dùng Hồn Diễn Đạo suy tính ra phương pháp dung hợp sát lục lôi đình chân thân: cần hồn phách đại hung ác làm vật dẫn. Thi triển Định Thân Thuật uy lực kinh thiên trấn La Miên, mượn hồn lực La Miên lần lượt rút ra ba bản nguyên chân thân (cấm chế, thái sơ, mặc diệt) rồi sát lục lôi đình chân thân. Dùng uy áp bản thể, thần niệm khổng lồ và ngũ hành chân thân ngàn trượng cưỡng chế năm chân thân dung hợp hoàn toàn vào sát lục chân thân tóc đen. Tuyên bố ban cho chân thân thứ hai tên Lục Mặc, đạo danh Hình Phạt — từ nay thay mình trừng phạt kẻ thù, truyền ý niệm hủy diệt, sát lục hồn phách bất lợi.","anchor":"Thuật Hồn Diễn Đạo này quả nhiên huyền diệu!","bridge":true,"khoang":"@c1934"},{"mucCt":"ky","text":"Thu ngũ hành chân thân và sát lục chân thân về mật thất hành cung. Dung hợp ngũ hành chân thân trước, tu vi đạt Không Kiếp đại viên mãn. Tiếp tục dung hợp sát lục chân thân đã tu luyện trăm năm mới ngưng tụ, tu vi bạo tăng vượt Thiên Tôn, đạt Dược Thiên Tôn, xông tới giới hạn Đại Thiên Tôn. Linh hồn thoát xác bay lên bầu trời, nhìn thấy vô số đường nét quy tắc thiên đạo chi chít. Phóng vào biển đường nét, phát hiện chín Đạp Thiên Kiều hư ảo tỏa khí tức cổ xưa. Đọc bia đá trước cầu thứ nhất khắc ba chữ Đạp Thiên Kiều và bốn câu Đạp Thiên Lộ, Không Diệt Đạo, Bất Hủ Hồn, Chúng Sinh Bái. Bước lên cầu thứ nhất, cảm nhận thân thể linh hồn thăng hoa, rất nhiều phép tắc thiên địa được hiểu rõ và khắc sâu vào tâm thần. Đi hết cầu thứ nhất, hướng tới cầu thứ hai. Suy đoán Tiên Tổ và Cổ Tổ có thể là bước thứ tư, nhớ lại từng nghe bước thứ tư tên Đạp Thiên. Mong muốn nâng tu vi để trừ bỏ hết Trớ Thuật trong hồn phách Tiên Hoàng Liên Đạo Chân.","anchor":"Tu hành suốt trăm năm cuối cùng cũng ngưng tụ được sát lục chân thân này","bridge":true,"khoang":"@c1935"},{"mucCt":"ky","text":"Đang bế quang công kích cảnh giới sau Không Kiếp, thần thức và linh hồn như bị chia lìa, không cảm thụ được sự tồn tại bản thân. Từ trên cao nhìn xuống toàn bộ Tiên Cương đại lục — bên trái bảy mươi hai châu, bên phải ba mươi sáu quận, trung gian là hải dương mênh mông với chín cây cột hợp thành cánh cửa đóng chặt. Khi nhìn về phía Tiên Tộc, bảy mươi hai châu hóa thành bảy mươi hai mãnh thú gầm thét cầu khẩn tự do. Nhìn thấy Đạo Nhất, Võ Phong, Song Tử, Cửu Đế, Hải Tử và Liên Đạo Phi nhưng họ không cảm thụ được sự tồn tại của hắn. Từng có ý niệm muốn cứu Thiên Ngưu và Liên Đạo Phi nhưng lúc này không làm được.","anchor":"Hắn thấy bọn họ nhưng bọn họ lại không cảm thụ được sự tồn tại của hắn","bridge":true,"khoang":"@c1936"},{"mucCt":"ky","text":"Vượt qua tự vấn Đạo Tâm ở cuối Đạp Thiên Kiều thứ hai nhờ chấp niệm bảo vệ sinh mệnh và ý niệm nghịch thiên. Bước lên cầu thứ ba — cầu tâm ma ký ức, mỗi chín bước xuất hiện ảo ảnh người thân. Thay vì nhắm mắt phủ nhận tình cảm để giữ Đạo Tâm, Vương Lâm mở mắt đối diện lần lượt cha mẹ phàm nhân, Mộc Băng Mi, Lý Thiên Mai, Lý Mộ Uyển, Vương Bình, Tư Đồ Nam, Thanh Thủy, Độn Thiên, lão Chu Tước, Đại Ngưu, Hồng Điệp, Thanh Lâm, Chu Dật, Thanh Sương. Ngộ ra triết lý mới: tình cảm là thứ quý giá nhất, mở rộng Đạo Tâm dung nạp tất cả thay vì phong bế. Khóc cười đau đớn bi thương, cuối cùng vượt cầu ba thành công. Bước lên cầu thứ tư nhưng chân xuyên qua cầu, thất bại ngay bước đầu. Tỉnh lại trong mật thất hành cung Kế Đô, sát lục chân thân đã hoàn toàn dung hợp với thân thể, hư bản nguyên lơ lửng phía sau.","anchor":"Tinh cảm chính là thứ quý giá nhất trong cuộc đời của Vương Lâm ta, ta cần gì phải nhắm mắt lại, ta phải mở to hai mắt nhìn hết thảy, mở rộng Đạo Tâm dung nạp tất cả!","bridge":true,"khoang":"@c1937"},{"mucCt":"ky","text":"Mở mắt trong mật thất sau bế quan, cảm thụ tu vi xác định mình đạt nửa bước Đạp Thiên, vượt Không Kiếp đại viên mãn, cao hơn Đại Thiên Tôn nửa bước mà nửa bước này là vực sâu khó vượt. Dùng một chữ Tán xua sạch Trớ Thuật còn sót trên hồn phách Tiên Hoàng Liên Đạo Chân, bóp chết hồn phách hắn hoàn toàn. Triệu đầu lâu Tiên Tổ, dùng bảy đạo hồn phách Liên Đạo Chân làm vật dẫn đưa vào thất khiếu, phun hồn hỏa xanh thiêu đốt. Lần đầu điều khiển quy tắc thiên địa — nắm sợi tơ vô hình mà Đại Thiên Tôn chỉ mơ hồ cảm thụ, phải bước lên Đạp Thiên Kiều thứ nhất mới sử dụng được — ném vào đầu lâu cùng máu tươi, khiến đầu lâu hòa tan tốc độ cao. Đại Thiên Tôn chi dương từ hai màu đen trắng xuất hiện thêm màu vàng kim thứ ba. Cảm thán đây là sức mạnh khiến Cổ Đạo Đại Thiên Tôn giết được Đại Thiên Tôn.","anchor":"Cảnh giới nửa bước Đạp Thiên sao.","bridge":true,"khoang":"@c1938"},{"chuong":"@c1939","importance":"normal","mucCt":"ky","tieuDe":"Chính thức thành Đại Thiên Tôn — Mười mặt trời","text":"Hòa tan hoàn toàn đầu Tiên Tổ, Đại Thiên Tôn chi dương ba màu thực chất hóa trọn vẹn. Thu hồi ba đạo hư bản nguyên sinh tử, nhân quả, chân giả dung nhập trở lại thân thể, phun khí tức bản nguyên phá tan phần đầu cuối cùng. Trở thành Đại Thiên Tôn mạnh thứ hai trên Tiên Cương sau Cổ Đạo, có khả năng điều khiển quy tắc thiên địa chứ không chỉ mượn. Dùng Định Thân Thuật chỉ bằng ánh mắt khóa cứng Cổ Ma chứa thần niệm Tống Thiên, sợi tơ pháp tắc thiên địa quấn quanh đông cứng. Đưa mặt trời ba màu lên bầu trời Tiên Cương, dẫn phát dị tượng mười mặt trời đồng hiện, mặt trời của hắn xếp thứ hai chỉ sau Cổ Đạo.","anchor":"hắn chính là người mạnh thứ hai trong những Đại Thiên Tôn"},{"chuong":"@c1940","importance":"major","mucCt":"ky","tieuDe":"Áp đảo Tống Thiên, thu chiến phủ","text":"Chính thức xác nhận trở thành Đại Thiên Tôn, mặt trời ba màu hắc-bạch-kim xuất hiện trên Tiên Cương đại lục, tàn ảnh vĩnh viễn tồn tại thành dấu hiệu. Thu mặt trời, điểm một chỉ vào mi tâm Cổ Ma xóa thần niệm Tống Thiên, khiến Cổ Ma khôi phục thần trí quỳ phục. Mang Kế Đô cưỡi Cổ Ma tới Nguyên Thủy Sơn đối đầu Tống Thiên. Dùng ba chỉ: chỉ thứ nhất nghiền nát thiên quân vạn mã, chỉ thứ hai phá hủy Nguyên Thủy Trận khiến nhiều cường giả phun máu, chỉ thứ ba tạo nắm tay quy tắc đánh vỡ chiến phủ do Cổ Đạo Đại Thiên Tôn ban cho Tống Thiên. Tống Thiên phun máu lui trăm trượng, Vương Lâm chỉ bị vệt trắng trên ngón tay. Chụp tay thu hồi mảnh vỡ chiến phủ khôi phục nguyên trạng, thể hiện sự thống trị tuyệt đối.","anchor":"Chỉ thứ nhất điểm tới thiên quân vạn mã đang lao tới ở cách Vương Lâm trăm trượng lập tức phát ra tiếng nổ vang"},{"chuong":"@c1941","importance":"normal","mucCt":"ky","tieuDe":"Phá Nguyên Thủy Sơn, nhận Kế Đô làm nghĩa tử","text":"Dùng một chỉ của Cổ Tổ chặn đứng Nguyên Thủy Sơn đang giáng xuống, rồi một chưởng đẩy Tống Thiên phun máu. Vung tay áo thu nhỏ Nguyên Thủy Sơn bằng lòng bàn tay, điều lịch đại Đại Thiên Tôn Thủy Cổ chưa ai làm được. Khẳng định ngoài Cổ Đạo ra không ai trong thiên địa khiến hắn kiêng kỵ. Kế Đô quỳ trước mặt mọi người gọi nghĩa phụ, Vương Lâm chính thức nhận Kế Đô làm nghĩa tử. Được Thủy Cổ hoàng tôn mời ở lại và đồng ý cho vào Tổ Miếu.","anchor":"ngọn núi này từ vạn cổ vẫn to lớn như thường, các đời Đại Thiên Tôn của Thủy Cổ nhất mạch chưa có ai có đủ trình độ thu nhỏ ngọn núi này lại như thế này"},{"mucCt":"ky","text":"Đứng trước pho tượng Cổ Tổ tại Thủy Cổ hoàng thành, nhận ra vẻ bi ai ẩn sau thần sắc khinh miệt. Được Tống Thiên mở Tổ Miếu, bước vào bế quan với mục đích vượt đệ Tam Tổn Kiếp lấy hai giọt Hồn Huyết để Lý Mộ Uyển có tư cách tiến vào Thái Cổ Thần Cảnh. Năm mươi năm trôi qua, thân thể héo rũ mục nát như khô cốt nhưng mắt vẫn sáng ngời. Hồi tưởng hệ thống Tam Tổn thất kiếp: đã vượt nhị tổn tứ kiếp và đệ nhất kiếp Tam Tổn (Cổ Mạch thương khung huyết, đạt một giọt Hồn Huyết), đang đối diện đệ nhị kiếp (Cổ Đạo tam phân thần). Từ Tổ Miếu phát lời hứa với Kế Đô rằng ngày hắn trở thành tân hoàng sẽ tới.","anchor":"Sâu trong Tổ Miếu, Vương Lâm đang ngồi khoanh chân nơi đó. Từ thân thể hắn tỏa ra vẻ mục nát đang héo rũ một mảng lớn, cả người trông như một bộ khô cốt.","bridge":true,"khoang":"@c1942"},{"mucCt":"ky","text":"Vương Lâm ngồi khoanh chân trong Tổ Miếu Thủy Cổ, tiến hành lần đầu phân thần Nguyên Thần trong kiếp thứ hai của Tam Tổn Kiếp. Nguyên Thần từ tầng sáng đầy vết nứt dần tan nát hoàn toàn, vỡ thành mảnh nhỏ rồi thành hạt, ba phần biến thành tro bụi. Sinh cơ gần như không còn, máu huyết ngừng chảy, lạnh như băng, mất hết thần trí, chỉ còn một luồng ý niệm kiên trì. Trong đầu vang vọng tiếng gầm thét chiến ý của Cổ Tổ. Kiên trì suốt 36 tháng, vượt xa kỷ lục Tống Thiên (11 tháng) và kỷ lục Cực Cổ nhất mạch (28 tháng). Cuối cùng vô số điểm sáng ngưng tụ dung hợp thành thân ảnh khổng lồ hơn trước mấy lần, chín tầng sáng dung hợp làm một rồi chia thành tám quầng sáng. Lần đầu phân thần thành công hoàn mỹ, phá kỷ lục toàn Cổ Tộc.","anchor":"Hoàn toàn tan nát, dung hợp hoàn mỹ","bridge":true,"khoang":"@c1944"},{"mucCt":"ky","text":"Hoàn thành lần phân thần đầu tiên sau ba năm, Nguyên Thần tầng sáng khổng lồ hơn trước mấy lần, tu vi mạnh hơn vài phần dù chưa lên cảnh giới mới. Tự nhủ nếu hoàn thành viên mãn độ kiếp Cổ Tộc và đạt Hồn Huyết thì có thể thử vượt cây cầu thứ tư trên Đạp Thiên Kiều. Nhận ra Cổ Đạo tam phân thần liên quan tới vận khí và ý chí, xác định ý chí cường đại có thể nghịch chuyển vận khí. Bắt đầu lần phân thần thứ hai, kéo dài mười ba năm rưỡi, Nguyên Thần phân liệt hoàn toàn. Nửa năm cuối dung hợp mười ba lần đều thất bại, ý chí cạn kiệt dần, mất thần trí và ý thức, thân thể không còn sinh cơ. Tiến hành lần dung hợp thứ mười bốn khi năm thứ mười lăm tới, quầng sáng bắt đầu biến mất — mười một quầng bị nghiền nát, chỉ còn bảy, tình trạng nguy kịch cực điểm.","anchor":"Vương Lâm đã không còn thần trí và ý thức, dựa vào ý chí không nhiều lắm triển khai lần dung hợp thứ mười bốn","bridge":true,"khoang":"@c1945"},{"mucCt":"ky","text":"Trong Tổ Miếu Thủy Cổ, thân thể Vương Lâm khô héo như xương khô, ý chí gần bị xóa tan sau vô số lần dung hợp thất bại, quầng sáng tắt dần chỉ còn một. Hắn rơi vào cảnh giới kỳ dị — đống đổ nát bầu trời hôn ám, mất hết ký ức. Nhìn thấy thân ảnh nam tử ôm thi thể tóc dài trên ngọn núi tuyết bảy màu, gầm thét bi ai, cảm thấy vô cùng quen thuộc và run rẩy. Tiếng gọi của Huyền La xuyên tới đánh thức, Vương Lâm nhớ ra tất cả, phân thần lần hai thành công. Bắt quyết, 27 quầng sáng đồng loạt bùng nổ bao phủ pho tượng Cổ Tổ, ánh sáng lan ra ngoài Nguyên Thủy Sơn, lớn hơn mấy chục lần lần phân thần đầu. Gọi Huyền La là sư tôn, cảm kích ân tình hộ pháp. Bắt đầu chuẩn bị phân thần lần ba (cuối cùng).","anchor":"Hắn nhớ ra hắn là Vương Lâm. Hắn đang độ kiếp trong Tổ Miếu, tiến hành dung hợp trong lần phân thần thứ hai.","bridge":true,"khoang":"@c1946"},{"mucCt":"ky","text":"Vương Lâm bắt đầu phân thần lần ba (Cổ Đạo tam phân thần) trong Tổ Miếu, Nguyên Thần phân liệt suốt khoảng 25 năm rồi vỡ hoàn toàn. Hắn rút kinh nghiệm lần trước, để lại một tia thần thức có thể thức tỉnh bản thân ở thời điểm mấu chốt. Từ năm 95 bắt đầu dung hợp từng bộ phận thay vì cùng lúc, năm 96 hoàn thành ba phần, năm 97 năm phần, năm 99 dung hợp xong hoàn chỉnh. Dù dung hợp thuận lợi, hắn cảm thấy vẫn thiếu sót, không chấm dứt mà chìm đắm bên trong để tìm lại vùng thiên địa mơ hồ với ngọn núi tuyết bảy màu và thân ảnh bí ẩn. Sau hơn một năm suy tư thử nghiệm, hắn lờ mờ thấy được thế giới đã từng gặp.","anchor":"Hắn lờ mờ thấy được thế giới đã từng gặp kia!","bridge":true,"khoang":"@c1947"},{"mucCt":"ky","text":"Tâm thần đi vào vùng thiên địa tối tăm hoang phế trong Tổ Miếu, chứng kiến một thân ảnh bí ẩn ôm thi thể gầm thét trên ngọn núi tuyết bảy màu, nghe lời thề hủy diệt thiên địa khiến trái tim đau đớn cực điểm, thân thể tan rã bị xua đuổi ra khỏi huyễn cảnh. Tỉnh lại trầm mặc nửa ngày, cắn răng điểm chỉ vào Nguyên Thần khiến Nguyên Thần bành trướng bao phủ cả pho tượng Cổ Tổ, tướng mạo pho tượng mơ hồ biến đổi có phần tương tự hắn — chính thức vượt qua Cổ Đạo tam phân thần thành công. Hai mươi bảy quầng sáng trên pho tượng bộc phát, Cửu Khúc vang lên, Cổ Tổ ban thưởng giọt Hồn Huyết thứ hai — tổng cộng hai trên ba giọt sáng tạo Cổ Thần.","anchor":"Sẽ không đâu. không phải. không.","bridge":true,"khoang":"@c1948"},{"chuong":"@c1949","importance":"major","mucCt":"ky","tieuDe":"Nhận ba giọt hồn huyết Cổ Tổ, nguyên thần dung hợp, bước cầu thứ tư","text":"Sau khi hoàn toàn vượt qua Cổ Đạo Tam Phần Thần, pho tượng Cổ Tổ ban thưởng tổng cộng ba giọt hồn huyết tím dung nhập vào thân thể, theo truyền thuyết đủ sáng tạo ra một mạch cổ. Nguyên thần sau ba lần tan vỡ rồi dung hợp đạt mức gần bất diệt, thần thức bao trùm toàn bộ lãnh thổ cổ tộc và vùng trũng biển, có thể cảm nhận quy tắc thiên địa và quỹ đạo lưu chuyển thời gian. Thân thể cường hãn phi thường, tự đánh giá có thể so với Cổ Đạo Đại Thiên Tôn. Ra khỏi tổ miếu sau trăm năm, bước vào hoàng cung dùng thần lực triệu mũ vua đặt lên đầu Kế Đô, chính thức phong hoàng tôn rồi biến mất. Tới hậu sơn Đạo Cổ Điện bái kiến sư tôn Huyền La, ở lại ba năm lắng đọng tâm linh hoàn toàn điều khiển thực lực mới. Tuyên bố muốn mang Uyển Nhi về nhà, thời gian tới Thái Cổ Thần Cảnh mở ra còn ba trăm năm. Tiến vào vùng đất Đạp Thiên, đứng trước cây cầu thứ tư rồi giơ chân hạ xuống một bước.","anchor":"nhìn cây cầu thứ tư khổng lồ ở dưới chân, giơ chân phải lên. hạ xuống một bước!"},{"mucCt":"ky","text":"Vương Lâm rời vùng đất Cổ Tộc sau khi vượt Đạp Thiên Kiều lần hai, ít nhất tới cầu thứ năm, thân thể trông như phàm nhân không dấu vết tu vi. Bay về phía tiên tộc, niệm khởi về Người Điên (lời thề cứu khỏi hoàng cung tổ thành), Tư Đô, Thanh Thủy, Thập Tam, Đầu To, Hồng Diệp đã chuyển thế trên mặt đất tiên tộc, cùng Lý Thiến Mai. Tới cơn lốc trung tâm biển rộng nơi có chín cây cột hình thành cửa Thái Cổ Thần Cảnh, dự định ba trăm năm sau mang Lý Mộ Uyển vào dùng lực lượng luân hồi hồi sinh nàng. Bị Cổ Đạo Đại Thiên Tôn chặn lại, đây là lần đầu hai cường giả nửa bước đạp thiên cảnh đối mặt trực tiếp. Kể ba ân của Cổ Đạo: mượn uy áp giúp dung hợp tiên cổ trên Cổ Đạo Sơn, trầm mặc khi hắn giết Diệp Đạo trong Đạo Cổ Hoàng thành, không ngăn Kế Đô lên tân hoàng tôn ở Thủy Cổ Nhất Mạch. Đồng ý ở lại một trăm năm nhưng Cổ Đạo đòi ba trăm năm, thương lượng bất thành. Chấp nhận giao chiến trong trận đỉnh cao đầu tiên trên Tiên Cương sau khi Tiên Tổ, Cổ Tổ biến mất.","anchor":"Vương Lâm ta cả đời ân oán rõ ràng","bridge":true,"khoang":"@c1950"},{"mucCt":"ky","text":"Đối đầu trực diện với Cổ Đạo Đại Thiên Tôn, người mạnh nhất Tiên Cương Đại Lục. Một chỉ thăm dò bất phân thắng bại, cả hai cùng lùi ba bước. Phá hủy toàn bộ tơ quy tắc thiên địa xung quanh, biến không gian thành nơi không tồn tại quy tắc. Chủ động tiến công, lần lượt thi triển bảy trong tám cực của Bát Cực Đạo: Ngũ hành Cực Đạo (Cực Thủy, Cực Kim, Cực Mộc, Cực Thổ, Cực Hỏa), Cực Địa Đạo và Cực Thiên Đạo, trình độ gần ngang Tiên Tổ nhờ đã bước nửa bước vào cảnh giới Đạp Thiên. Tam Cực cuối cùng được giác ngộ khi bước lên Đạp Thiên Kiều lần thứ hai qua cây cầu thứ năm. Dùng Tốc Thần Mạch bạo tăng tốc độ, đánh hai quyền trước-sau lấy vụ thú chín đầu làm trung tâm, xé rách thân thể vụ thú. Bị hơn vạn quả cầu sương đánh trúng, điểm lên mi tâm thi triển Cực Mệnh Đạo — đạo thứ tám, u quang từ mắt hóa vòng sáng u ám phòng hộ bốn phía.","anchor":"Bát Cực Đạo của riêng Vương Lâm hiện giờ ngoài một đạo cuối cùng, thì toàn bộ đều đã hoàn thành","bridge":true,"khoang":"@c1951"},{"mucCt":"ky","text":"Phun máu bị đẩy lùi mấy trăm trượng sau vòng giao đấu trước, cố ý chịu thương để phá sương mù nhìn rõ tướng mạo Cổ Đạo. Nhận ra Cổ Đạo chính là Cổ Tổ qua tướng mạo giống hệt pho tượng trong Ba Hoàng Thành. Hé lộ nguồn gốc chiêu thức Đạp Thiên Nhất Bộ — lĩnh ngộ từ thân ảnh Cổ Tổ bước về phía bầu trời trong tổ miếu Thủy Cổ Hoàng Thành, cùng lúc cảm ngộ Bát Cực Đạo trên Đạp Thiên Kiều thứ năm. Bị tín thuật Cổ Hóa Thiên Địa tác động — mắt chảy máu, tay run, thân muốn biến thành đất trời. Không phá thuật mà nhắm mắt nhập cảnh giới bi thương phẫn nộ của thân ảnh Cổ Tổ, hạ một bước chân Đạp Thiên Nhất Bộ đáp lại.","anchor":"Luồng phẫn nộ này khiến một bước này của Vương Lâm bỗng nhiên hạ xuống!","bridge":true,"khoang":"@c1952"},{"mucCt":"ky","text":"Dậm bước Đạp Thiên nhất bộ phá sụp toàn bộ thiên địa do Cổ Hóa Thiên Địa tạo thành, đánh Cổ Đạo phun máu lui hơn trăm trượng. Đối diện thức Đạp Thiên độc sáng của Cổ Đạo, sau hai trăm năm lần đầu lại cảm nhận nguy cơ sinh tử mãnh liệt. Trong khoảnh khắc nguy hiểm, nhớ lại câu trên Đạp Thiên Kiều thứ tám và ba vấn đề của Lý Thiến Mai trong động phủ giới, đốn ngộ hư bổn nguyên thứ tư — luân hồi chính là thiên địa, dùng tấm lưới nhân quả tìm bản ngã. Toàn bộ Cửu Khúc chín âm vang lên từ thân thể, nhất tướng Kim thiên Hắc địa và nhị tướng hào quang bạc hiện ra. Gọi phần thân hư vô (ngồi trên đài đá trong hư vô gần ngàn năm) dung hợp với bản thể, đệ tam tướng anh đề (tiếng trẻ con khóc) xuất hiện. Tiếng khóc chấn động Tiên Cương đại lục, ba pho tượng Cổ Tổ và pho tượng Tiên Tổ đồng thời nứt khe, thân ảnh thứ ba trong bình nguyên vượt qua cả tiên cổ bay vọt lên.","anchor":"Trong cơ thể hắn vốn có tam đại hư bổn nguyên, giờ phút này bất ngờ có thêm một bổn Nguyên","bridge":true,"khoang":"@c1953"},{"chuong":"@c1954","importance":"normal","mucCt":"ky","tieuDe":"Dung hợp tiên cổ, đệ nhất cường giả Tiên Cương","text":"Cửu Khúc Tam Tướng (Kim Thiên, Hắc Địa, Ngân Mục) đồng thời xuất hiện trên thân, trở thành tồn tại thứ ba ngoài Tiên và Cổ. Lực lượng tiên cổ trong thân hoàn thành dung hợp một vòng chỉ thiên, tạo ra lực lượng kỳ dị thuộc về bản thân. Tu vi vượt qua mọi tồn tại trên Tiên Cương, dù Tiên Tổ Cổ Tổ tái thế cũng có tư cách đánh một trận. Giơ tay điểm một chỉ phá sụp Đạp Thiên Thuật của Cổ Đạo Đại Thiên Tôn. Gật đầu đồng ý ước định của Cổ Đạo: ba trăm năm sau từ bên Cổ Tổ bước vào Thái Cổ Thần Cánh. Xuyên qua cơn lốc nước biển tiến vào phạm vi tiên tộc, trở thành đệ nhất cường giả Tiên Cương đại lục. Mười hai ngày sau, bảy Đại Thiên Tôn hợp lực dùng thần thông nghịch chuyển chứng kiến trận đánh, cả bảy chấn động thừa nhận đệ nhất cường giả là Vương Lâm.","anchor":"tu vi của hắn đã vượt qua tất cả tồn tại trên tiên cương"},{"chuong":"@c1955","importance":"normal","mucCt":"ky","tieuDe":"Trở lại tiên tộc tìm người quen — mất dấu Lý Thiến Mai","text":"Trở lại Bắc châu tiên tộc, khuếch tán thần thức bao phủ toàn bộ bảy mươi hai châu rồi mở rộng ra cả Cổ tộc và toàn Tiên Cương đại lục. Tìm được hầu hết người quen cũ: Chu Dật, Thanh Sương, Hồng Sam Tử, Chu Như, Thập Tam, Đồng tử đầu to, Thân Công Hổ, Hồng Điệp, Thanh Thủy. Duy nhất KHÔNG tìm được ấn ký Lý Thiến Mai dù quét nhiều lần, ôm ngực đau đớn ngửa mặt gầm thét phẫn nộ với trời. Suy đoán Lý Thiến Mai giống Thanh Thủy đã tự khôi phục trí nhớ kiếp trước khiến ấn ký tiêu tán, nàng tránh mặt không gặp. Sau đó tới Lô Kim tông tại Vân Đào châu tìm Thập Tam (Vương Thạch), điểm ngón tay vào mi tâm khôi phục ký ức cho hắn.","anchor":"Ngươi cho ta tìm được hồn của Lý Mộ Uyển nhưng lại khiến ta phái vứt bỏ thân ảnh Lý Thiến Mai"}],"tuViMoc":[{"chuong":"@c1935","canhGioi":"Không Kiếp đại viên mãn","text":"Dung hợp ngũ hành chân thân, tu vi đạt Không Kiếp đại viên mãn, tinh thần sung túc sau trăm năm bế quan.","importance":"minor"},{"chuong":"@c1935","canhGioi":"Xông tới giới hạn Đại Thiên Tôn (đang đột phá)","text":"Tiếp tục dung hợp sát lục chân thân, tu vi bạo tăng vượt Thiên Tôn → Dược Thiên Tôn → xông tới giới hạn Đại Thiên Tôn. Linh hồn thoát xác phát hiện chín Đạp Thiên Kiều, bước lên cầu thứ nhất lĩnh ngộ phép tắc thiên địa, đang hướng tới bước thứ tư Đạp Thiên Đạo.","importance":"major"},{"chuong":"@c1936","canhGioi":"Đạp Thiên (đang công kích)","text":"Bế quang công kích cảnh giới sau Không Kiếp — Đạp Thiên. Thần thức và linh hồn bị chia lìa, từ trên cao nhìn xuống toàn bộ Tiên Cương đại lục, chưa hoàn thành đột phá.","importance":"major"},{"chuong":"@c1938","canhGioi":"Nửa bước Đạp Thiên","text":"Sau bế quan cảm thụ tu vi, xác định đã đột phá Không Kiếp đại viên mãn nhưng không thuộc Đại Thiên Tôn mà cao hơn nửa bước, tự gọi nửa bước Đạp Thiên. Cảm thấy Đại Thiên Tôn còn kém cảnh giới hiện giờ nửa bước, nửa bước này là vực sâu khó vượt.","importance":"major"},{"chuong":"@c1939","canhGioi":"Đại Thiên Tôn (hoàn chỉnh)","text":"Đại Thiên Tôn chi dương ba màu thực chất hóa trọn vẹn sau khi hòa tan hoàn toàn đầu Tiên Tổ và thu hồi ba đạo hư bản nguyên. Chính thức trở thành Đại Thiên Tôn hoàn chỉnh, mạnh thứ hai trên Tiên Cương sau Cổ Đạo.","importance":"major"},{"chuong":"@c1944","canhGioi":"Phân Thần Kiếp — lần đầu phân thần thành (hoàn mỹ)","text":"Hoàn thành lần đầu phân thần trong kiếp thứ hai Tam Tổn Kiếp. Kiên trì 36 tháng để Nguyên Thần hoàn toàn tan nát rồi dung hợp, đạt mức hoàn mỹ. Chín tầng sáng dung hợp rồi chia thành tám quầng sáng.","importance":"major"},{"chuong":"@c1949","canhGioi":"Nguyên thần gần bất diệt","text":"Nguyên thần sau ba lần tan vỡ rồi dung hợp đạt mức gần bất diệt, thần thức bao trùm toàn bộ lãnh thổ cổ tộc, cảm nhận được quy tắc thiên địa và quỹ đạo thời gian, thân thể cường hãn có thể so với Cổ Đạo Đại Thiên Tôn.","importance":"major"},{"chuong":"@c1953","canhGioi":"Hư bổn nguyên thứ tư — Luân hồi","text":"Đốn ngộ bổn nguyên luân hồi, ngoài tam đại hư bổn nguyên vốn có giờ thêm bổn nguyên thứ tư. Luân hồi chính là thiên địa, dùng tấm lưới nhân quả tung lên trời tìm bản ngã.","importance":"major"},{"chuong":"@c1954","canhGioi":"Dung hợp tiên cổ hoàn thành — lực lượng riêng","text":"Lực lượng tiên cổ trong thân hoàn thành một vòng chỉ thiên, tạo ra lực lượng kỳ dị thuộc bản thân. Tu vi vượt qua tất cả tồn tại trên Tiên Cương, dù Tiên Tổ Cổ Tổ tái thế cũng có tư cách đánh một trận. Thuộc hệ dung hợp tiên cổ, không phải tu vi tiên hay cổ đơn thuần.","importance":"major"},{"chuong":"@c1954","canhGioi":"Dung hợp tiên cổ hoàn thành","text":"Lực lượng tiên cổ trong thân thể hoàn thành dung hợp, tạo ra lực lượng kỳ dị không còn là tiên hay cổ mà thuộc về bản thân. Tu vi vượt qua mọi tồn tại trên Tiên Cương, trở thành đệ nhất cường giả.","importance":"major"},{"chuong":"@c1954","canhGioi":"Vượt mọi tồn tại trên Tiên Cương (dung hợp tiên cổ hoàn thành)","text":"Lực lượng tiên cổ trong thân thể hoàn thành dung hợp một vòng chỉ thiên, tạo ra lực lượng kỳ dị không còn là tiên hay cổ mà thuộc về bản thân. Tu vi vượt qua tất cả tồn tại trên Tiên Cương, dù Tiên Tổ Cổ Tổ tái thế cũng có tư cách đánh.","importance":"major"}],"nhanMach":[{"ten":"Kế Đô hoàng tử","tag":"khac","quanHe":"Nghĩa tử","ghiChu":"Chính thức nhận Kế Đô làm nghĩa tử trước mặt mọi cao thủ Thủy Cổ nhất mạch @c1941"},{"ten":"Tống Ngọc","tag":"khac","quanHe":"Con dâu nghĩa tử Kế Đô, hậu nhân Tống Thiên","ghiChu":"Kế Đô dẫn Tống Ngọc quỳ trước Tổ Miếu bái kiến nghĩa phụ Vương Lâm"},{"ten":"Lý Thiến Mai","tag":"khac","quanHe":"Người Vương Lâm không thể quên, phân thân/chuyển thế của Lý Mộ Uyển","ghiChu":"Quét toàn bộ Tiên Cương đại lục không tìm được ấn ký, suy đoán nàng đã tự khôi phục trí nhớ và tránh mặt"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Phàm nhân tư chất kém, nhờ Nghịch Thiên Châu khai mở Mộng Cảnh, chính thức bước vào con đường tu tiên","chuong":"@c0023"},{"text":"Đoạt xá thân Mã Lương sau khi tự nổ thân thể xuyên Vực Ngoại, tái sinh từ tuyệt cảnh","chuong":"@c0103"},{"text":"Nhận truyền thừa Cổ Thần Đồ Ti, trọng tổ thân thể Cổ Thần, nền tảng cho toàn bộ con đường thể tu sau này","chuong":"@c0176"},{"text":"Dung hợp bổn tôn và phân thân thành một, đạt tam tinh Cổ Thần, xác lập hình thái chiến đấu hoàn chỉnh","chuong":"@c0365"},{"text":"Chính thức thành Đại Thiên Tôn, Đại Thiên Tôn Chi Dương ba màu thực chất hóa trọn vẹn, mười mặt trời hiện trên Tiên Cương","chuong":"@c1939"},{"text":"Diệt Thiên Vận Tử, hồi sinh Lý Mộ Uyển, thu La Bàn Định Giới, đạt cảnh giới Đạp Thiên — hoàn tất hành trình nghịch thiên","chuong":"@c1976"}]},"nguon":["@c1930","@c1931","@c1932","@c1933","@c1934","@c1935","@c1936","@c1937","@c1938","@c1939","@c1940","@c1941","@c1942","@c1943","@c1944","@c1945","@c1946","@c1947","@c1948","@c1949","@c1950","@c1951","@c1952","@c1953","@c1954","@c1955"],"vaiTro":"Nhân vật chính — phàm nhân nghịch thiên, Đại Thiên Tôn tam cổ cửu tinh đệ nhất cường giả Tiên Cương","tinhCach":"Kiên nghị bất khuất, nhiều lần từ tuyệt cảnh tán công vươn lên đột phá; Thâm trầm mưu trí, giỏi ẩn nhẫn bố cục và phản kích trong thế yếu; Quyết đoán tàn nhẫn với kẻ thù nhưng nặng tình với cố nhân; Không chịu khuất phục trước hoàng quyền và trật tự áp đặt","blurb":"Vương Lâm xuất thân là thiếu niên phàm nhân tư chất kém ở Thạch Thôn, nhờ Nghịch Thiên Châu khai mở Mộng Cảnh, ý chí khổ tu và vô số lần sinh tử — từ đoạt xá thân Mã Lương, truyền thừa Cổ Thần Đồ Ti, dung hợp bổn tôn với phân thân, vượt mười bảy tầng Thiên Tôn Niết — mà từng bước vươn tới đỉnh cao tu đạo. Sau khi được sắc phong Dược Thiên Tôn, đạt Không Kiếp hậu kỳ với thân thể tam cổ cửu tinh và ngưng hình dáng ban đầu của Đại Thiên Tôn Chi Dương, hắn đối diện trực tiếp áp lực hoàng quyền Đạo Cổ mà vẫn không quỳ gối, vượt Tam Tổn Kiếp tại Tổ Miếu Thủy Cổ, chính thức thành Đại Thiên Tôn, dung "},{"id":"ly-mo-uyen","name":"Lý Mộ Uyển","cn":"李慕婉","aliases":["Uyển nhi","Mộc Băng Mi"],"gioiTinh":"nu","canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","tabs":{"kinhLich":[{"chuong":"@c1930","importance":"normal","mucCt":"ky","tieuDe":"Hồn phách hoàn chỉnh","text":"Nằm trong quan tài trong suốt như ngủ say. Tàn hồn đã được Vương Lâm tách khỏi thân thể Tống Trí suốt gần hai năm, nay đưa vào mi tâm nàng. Hồn phách hoàn chỉnh, lông mi run rẩy như sắp thức tỉnh rồi lại yên tĩnh, hai hàng nước mắt chảy xuống khóe mắt.","anchor":"Chỉ là ở khóe mắt nàng có hai hàng nước mắt chảy xuống"},{"importance":"bridge","mucCt":"vua","chuong":"@c1931","tieuDe":"Nằm trong quan tài, Vương Lâm chia tay","text":"Nằm trong quan tài, hàng lông mi run rẩy và rơi nước mắt trong suốt. Vương Lâm lau nước mắt, hôn lên đôi môi tái nhợt và thì thầm bên tai nàng rồi thu quan tài đi.","anchor":"nhìn hàng lông mi run rẩy cùng những giọt nước mắt trong suốt của nàng"},{"chuong":"@c1942","importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1942","text":"Được nhắc đến: Vương Lâm tiến vào Tổ Miếu với mục tiêu lấy hai giọt Hồn Huyết để nàng có tư cách vào Thái Cổ Thần Cảnh.","anchor":"Hắn có thể khiến Lý Mộ Uyển có tư cách tiến vào bên trong Thái Cổ Thần Cảnh hay không đều phải xem bản thân trong đệ Tam Tổn Kiếp này có lấy được hai giọt Hồn Huyết hay không."},{"chuong":"@c1950","importance":"bridge","mucCt":"gon","text":"Vương Lâm dự định ba trăm năm sau khi cửa Thái Cổ Thần Cảnh mở, mang Lý Mộ Uyển vào dùng lực lượng luân hồi hồi sinh nàng.","anchor":"mang theo Lý Mộ Uyển tiến vào bên trong, dùng lực lượng luân hồi khiến Lý Mộ Uyển sống lại"},{"chuong":"@c1955","importance":"normal","mucCt":"gon","tieuDe":"Vương Lâm tìm được hồn nhưng mất thân ảnh Lý Thiến Mai","text":"Vương Lâm phẫn nộ gầm thét rằng trời cho hắn tìm được hồn Lý Mộ Uyển nhưng lại khiến hắn mất thân ảnh Lý Thiến Mai.","anchor":"Ngươi cho ta tìm được hồn của Lý Mộ Uyển nhưng lại khiến ta phái vứt bỏ thân ảnh Lý Thiến Mai"}],"tuViMoc":[],"nhanMach":[{"ten":"Lý Thiến Mai","tag":"ho-hang","quanHe":"Thân ảnh chuyển thế của Lý Mộ Uyển tại Tiên Cương đại lục","ghiChu":"Vương Lâm tìm được hồn Mộ Uyển nhưng mất dấu thân ảnh Thiến Mai"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Dùng Bách Thú Linh Lô và Ma Huyết đằng luyện thành công linh đan trong lúc động phủ bị mười tu sĩ Kết Đan kỳ công phá","chuong":"@c0127"},{"text":"Chia tay Vương Lâm sau bốn năm đồng hành tại Tu Ma Hải, để lại hơn 18.000 ngọc giản đan phương và bản mệnh tinh huyết kèm thần thức hộ thể","chuong":"@c0137"},{"text":"Ba lần Kết Anh thất bại, thọ nguyên cạn kiệt, thân xác hóa xương khô, kim đan nứt vỡ; nguyên anh đầu thai thành bé gái Chu Như qua bức tranh Sinh Tử Luân Hồi","chuong":"@c0313"},{"text":"Sau chín mươi năm trong thân Chu Như, thức tỉnh rồi tự đẩy nguyên anh ra, từ bỏ cơ hội tái sinh để bảo toàn sinh mệnh Chu Như","chuong":"@c0381"},{"text":"Tàn hồn được Vương Lâm tách khỏi thân Tống Trí suốt gần hai năm, hồn phách hoàn chỉnh trở lại","chuong":"@c1929"},{"text":"Được hồi sinh nhờ Vương Lâm nghịch chuyển năm tháng, mở mắt tỉnh lại và cùng hắn rời đi sống bình thường","chuong":"@c1975"}]},"nguon":["@c1930","@c1931","@c1943","@c1949","@c1950","@c1955","@c1942"],"vaiTro":"Nhân vật nữ chính — thê tử Vương Lâm, tu sĩ tài hoa luyện đan và trận pháp","tinhCach":"Tài hoa xuất chúng về luyện đan và trận pháp, sáng tạo linh hoạt trong chiến đấu; nặng tình sâu sắc với Vương Lâm, kiên trinh suốt trăm năm ly biệt; kiên cường chịu đựng trước thọ nguyên cạn kiệt và ba lần Kết Anh thất bại; giàu lòng trắc ẩn, tự từ bỏ cơ hội tái sinh để bảo toàn sinh mệnh Chu Như","blurb":"Lý Mộ Uyển là tu sĩ Kết Đan hậu kỳ, nổi bật với thiên phú luyện đan và trận pháp, từng bị Song Tu Môn truy sát vì Thiên Ly đan rồi được Vương Lâm cứu giúp, cùng hắn trải qua bốn năm đồng hành tại Tu Ma Hải trước khi chia tay. Hơn trăm năm sau, ba lần Kết Anh thất bại khiến thọ nguyên cạn kiệt, thân xác hóa xương khô; nguyên anh nhờ bức tranh Sinh Tử Luân Hồi đầu thai thành bé gái Chu Như, nhưng nàng tự đẩy nguyên anh ra để bảo toàn sinh mệnh Chu Như, rồi được Vương Lâm gìn giữ nguyên anh suốt gần bảy trăm năm. Tàn hồn nàng sau đó được phát hiện dung nhập trong thân Tống Trí, trải qua gần hai n"},{"id":"ke-do","name":"Kế Đô hoàng tử","cn":"纪都","aliases":[],"gioiTinh":"nam","canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"ky","text":"Chờ sẵn ở Thủy Cổ nhất mạch vì phân tích Vương Lâm sẽ tới. Quỳ gối gọi Vương Lâm là nghĩa phụ. Báo cáo đã thông báo thành chủ Hắc Thạch Thành bảo vệ Tống Trí và phái thị vệ ở lại. Trình bày tình hình: Đại Thiên Tôn Tống Thiên không thích hắn, hoàng đệ Hoàng Man được Tống Thiên nhận làm đệ tử đang ở Nguyên Thủy Sơn, hoàng huynh sinh ra có thiên địa dị tượng được Cổ Đạo Đại Thiên Tôn chú ý. Được Vương Lâm nhận xét kiêu nhã, biết che giấu tâm tính, làm việc đúng mực. Biến khu vực mật thất thành cấm địa, điều hộ vệ bảo vệ ngày đêm.","anchor":"Hài nhi dù là tài trí hay tâm tính đều vượt qua Hoàng Man","bridge":true,"khoang":"@c1930"},{"importance":"bridge","mucCt":"vua","chuong":"@c1931","tieuDe":"Túc trực ngoài mật thất chín năm","text":"Trong chín năm Vương Lâm bế quan, Kế Đô bố trí trong hành cung, mỗi sáng sớm đều đích thân tới ngoài mật thất nhìn cuồng nhiệt nửa canh giờ rồi cung kính rời đi. Thi thoảng có người đến mật đàm rồi vội vã rời khỏi.","anchor":"Kế Đô hoàng tử bất kể nắng mưa, bất luận là chuẩn bị làm một việc gì quan trọng đều đích thân đi tới bên ngoài mật thất"},{"mucCt":"vua","text":"Bái phỏng Tống Thiên Đại Thiên Tôn nhiều lần bất thành, bị ngăn ngoài Nguyên Thủy Sơn. Từ chối nhờ nghĩa phụ Vương Lâm giúp đỡ, bộc lộ sát ý tuyên bố nếu các hoàng huynh chết thì Tống Tôn chẳng còn lựa chọn. Cuối chương kích động khi cảm nhận Vương Lâm xuất quan.","anchor":"Còn cả hoàng huynh kia của ta không biết nếu bọn họ chết thì Tống Tôn còn lựa chọn một người chết làm hoàng tôn hay không!","bridge":true,"khoang":"@c1932"},{"mucCt":"vua","text":"Suốt một trăm năm không dám quấy rầy Vương Lâm bế quan, cắn răng sống sót dù gặp nguy cơ sinh tử. Khi La Miên xuất hiện từ lòng đất, phun ra máu tươi. Hé lộ: khi sinh ra có dị tượng hung ác bị hoàng tộc giấu giếm, xây hành cung ở La Miên Quận theo sắp xếp của quốc sư (đã chết) để trấn áp La Miên và nuôi dưỡng vận khí.","anchor":"Nghe đồn hoàng tử này khi sinh ra cũng có dị tượng xuất hiện, nhưng là một hư ảnh biểu hiện cho sự hung ác","bridge":true,"khoang":"@c1933"},{"mucCt":"vua","text":"Ngay khi hồn La Miên đại hung ác bị Vương Lâm nuốt, Kế Đô phun máu tươi. Một đạo phong ấn vô hình trong thân thể bỗng tan vỡ, luồng sức mạnh bí ẩn thức tỉnh tràn ngập toàn thân.","anchor":"trong thân thể hắn dường như có một đạo phong ấn vô hình bỗng nhiên tan vỡ","bridge":true,"khoang":"@c1935"},{"chuong":"@c1939","importance":"normal","mucCt":"vua","tieuDe":"Kích động trước nghĩa phụ thành Đại Thiên Tôn","text":"Trong hành cung La Miên Quận, ngây ra trước cảnh Vương Lâm thành Đại Thiên Tôn, kích động mãnh liệt chưa từng có, cười ha hả gọi nghĩa phụ Đại Thiên Tôn.","anchor":"Nghĩa phụ Đại Thiên Tôn!"},{"mucCt":"vua","text":"Dẫn đầu cùng thiếu phụ, phu quân và thị vệ hành cung quỳ bái chúc mừng Vương Lâm thành Đại Thiên Tôn, gọi nghĩa phụ. Được Vương Lâm mang theo cưỡi Cổ Ma tới Nguyên Thủy Sơn gặp Tống Thiên. Nhìn bóng lưng Vương Lâm cảm thấy như ngọn núi, ý thức rằng chỉ khi có Vương Lâm mình mới có thể trở thành Thủy Cổ hoàng tôn.","anchor":"Hắn nhìn bóng lưng Vương Lâm phía trước. Bóng lưng này không cao lớn nhưng lại khiến hắn cảm thấy như một ngọn núi","bridge":true,"khoang":"@c1940"},{"chuong":"@c1941","importance":"major","mucCt":"ky","tieuDe":"Công khai bái Vương Lâm làm nghĩa phụ, được tuyên bố kế vị hoàng tôn","text":"Được Tống Thiên tuyên bố trăm năm sau sẽ là hoàng tôn của Thủy Cổ nhất mạch. Lờ đi phụ hoàng và Tống Thiên, quỳ trước mặt mọi cao thủ nhận Vương Lâm làm nghĩa phụ, gây xôn xao lớn vì ở Cổ Tộc hoàng quyền chí thượng, hoàng tử quỳ trước người khác là chuyện chưa từng có. Bị Đại hoàng tử và Hoàng Man phản đối nhưng kiên định. Xin phụ hoàng cho Vương Lâm vào Tổ Miếu và được chấp thuận.","anchor":"Trước đây Vương Lâm thủy chung vẫn không tán thành việc này nhưng bản thân Kế Đô hắn vẫn luôn gọi đối phương là nghĩa phụ"},{"chuong":"@c1942","importance":"major","mucCt":"ky","tieuDe":"Xác lập hoàng tôn, đại hôn Tống Ngọc","text":"Trong ba mươi năm, tất cả hoàng tử khác lần lượt phong vương rời đi trấn thủ biên cương, chỉ Kế Đô ở lại hoàng cung, dần tiếp xúc quyền lực ẩn giấu của các đời hoàng tôn và bắt đầu quá độ quyền lực với phụ hoàng. Giữ thói quen sáng sớm nhìn về Tổ Miếu. Tuân lời Vương Lâm phái nhiều cường giả ẩn thế tới Hắc Thạch Thành bảo vệ Tống Trí suốt hơn trăm năm. Năm thứ năm mươi tổ chức đại hôn với Tống Ngọc (hậu nhân Tống Thiên). Đêm đó đưa thê tử tới trước Tổ Miếu quỳ lạy cách đại môn mười trượng bái kiến nghĩa phụ Vương Lâm, bày tỏ lòng biết ơn sâu sắc. Nghe được lời hứa của Vương Lâm từ trong Tổ Miếu, lộ nụ cười.","anchor":"Hắn vĩnh viễn nhớ rõ tất cả mọi thứ mình đạt được hôm này đều là nhờ Vương Lâm."},{"chuong":"@c1949","importance":"normal","mucCt":"vua","tieuDe":"Được phong hoàng tôn chính thức","text":"Chứng kiến nghĩa phụ Vương Lâm nhận hồn huyết Cổ Tổ, vô cùng kinh ngạc. Vương Lâm bước vào hoàng cung dùng thần lực triệu mũ vua đặt lên đầu, chính thức phong làm hoàng tôn, dặn dò dẫn dắt tộc nhân hùng mạnh rồi biến mất. Đau thương gọi nghĩa phụ.","anchor":"Làm một hoàng tôn tốt, dẫn dắt tộc nhân của ngươi ngày càng hùng mạnh!"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Nghĩa phụ","ghiChu":"Chính thức quỳ bái Vương Lâm làm nghĩa phụ trước mặt mọi người @c1941"},{"ten":"Tống Ngọc","tag":"the-thiep","quanHe":"Thê tử, hoàng hậu tương lai","ghiChu":"Hậu nhân Tống Thiên, đại hôn sau 50 năm Vương Lâm vào Tổ Miếu"},{"ten":"Thê tử Kế Đô","tag":"the-thiep","quanHe":"Thê tử","ghiChu":"Nắm tay Kế Đô cùng nhìn về Tổ Miếu khi Vương Lâm phân thần (@c1943)"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Xuất hiện trên đầu cổ Yêu Đà Lạc, khiến Hắc Thạch thành đồng loạt quỳ lạy, lập tức ra lệnh giết Vương Lâm vì không quỳ","chuong":"@c1902"},{"text":"Phân tích đúng hướng đi của Vương Lâm, chờ sẵn ở Thủy Cổ nhất mạch rồi quỳ gối nhận làm nghĩa phụ","chuong":"@c1930"},{"text":"Túc trực ngoài mật thất chín năm, mỗi sáng sớm đều đích thân tới chầu trong lúc Vương Lâm bế quan","chuong":"@c1931"},{"text":"Suốt trăm năm cắn răng sống sót qua nguy cơ sinh tử, không dám quấy rầy nghĩa phụ bế quan; khi hồn La Miên bị nuốt, phong ấn vô hình trong thân thể phát tác khiến phun máu tươi","chuong":"@c1935"},{"text":"Được Tống Thiên tuyên bố kế vị hoàng tôn Thủy Cổ nhất mạch, công khai bái Vương Lâm làm nghĩa phụ trước đông đảo cường giả","chuong":"@c1941"},{"text":"Đại hôn cùng Tống Ngọc, xác lập vị trí hoàng tôn duy nhất ở lại hoàng cung khi các hoàng tử khác đều phong vương trấn thủ biên cương","chuong":"@c1942"}]},"nguon":["@c1930","@c1931","@c1932","@c1933","@c1935","@c1939","@c1940","@c1941","@c1942","@c1943","@c1949"],"vaiTro":"Hoàng tử cổ tộc — nghĩa tử của Vương Lâm, được phong hoàng tôn Thủy Cổ nhất mạch","tinhCach":"cơ mưu tính toán, biết thời thế mà quy phục; trung thành kiên nhẫn với nghĩa phụ, chịu đựng trăm năm bế quan không dám quấy rầy; háo danh quyền lực, chủ động bám víu kẻ mạnh để thăng tiến","blurb":"Kế Đô hoàng tử ban đầu xuất hiện trên đầu cổ Yêu Đà Lạc, ra lệnh giết Vương Lâm vì hắn không quỳ, nhưng sau khi nhận ra sức mạnh và địa vị của Vương Lâm đã lập tức chuyển sang quỳ gối nhận làm nghĩa phụ. Hắn túc trực ngoài mật thất suốt chín năm, cắn răng chịu đựng trăm năm nguy cơ sinh tử không dám quấy rầy Vương Lâm bế quan, nhờ đó được Tống Thiên tuyên bố kế vị hoàng tôn Thủy Cổ nhất mạch và đại hôn cùng Tống Ngọc, trở thành hoàng tử duy nhất ở lại hoàng cung trong khi các hoàng tử khác đều phong vương trấn thủ biên cương."},{"id":"tong-tri","name":"Tống Trí","cn":"宋智","aliases":[],"gioiTinh":"nu","theLuc":[{"ten":"Thủy Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Tống Trí là nữ tử xuất thân từ Thủy Cổ nhất mạch, người đầu tiên sau nhiều trăm năm dung hợp thành công tàn hồn — trong đó có tàn hồn Lý Mộ Uyển. Nàng bị Đạo Cổ hoàng tôn sắc phong hoàng hậu nhằm phục vụ mục đích chính trị, sau đó được Vương Lâm cứu khỏi hoàng cung và đưa đi suốt gần hai năm đường trường về Hắc Thạch Thành, trong quá trình đó tàn hồn Lý Mộ Uyển bên trong nàng dần được tách ra. Nàng sống yên ổn tại Hắc Thạch Thành hơn trăm năm dưới sự bảo vệ ngầm của các cường giả mà bản thân không hề hay biết, cuối cùng qua đời tại đây khi tuổi thọ phàm nhân năm trăm năm đã tới cực hạn.","vaiTro":"Nữ tử Thủy Cổ nhất mạch dung hợp tàn hồn, bị lập làm hoàng hậu Đạo Cổ","tinhCach":"tĩnh tại, cam chịu; mê man giữa bản ngã và ký ức tàn hồn; không hay biết thế sự xung quanh","tabs":{"diem":[{"text":"Là nữ tử Thủy Cổ nhất mạch đầu tiên sau nhiều trăm năm dung hợp thành công tàn hồn, bao gồm tàn hồn Lý Mộ Uyển","chuong":"@c1910"},{"text":"Tỉnh dậy trong hoàng cung Đạo Cổ sau chuỗi mộng ký ức hỗn loạn từ tàn hồn, bị sắc phong hoàng hậu và đưa ra trước đại yến","chuong":"@c1911"},{"text":"Được Vương Lâm mang đi khỏi hoàng cung Đạo Cổ trong trạng thái đang dung nhập tàn hồn Lý Mộ Uyển","chuong":"@c1922"},{"text":"Theo Vương Lâm đi suốt gần hai năm về Hắc Thạch Thành, tàn hồn Lý Mộ Uyển trong người dần được tách ra","chuong":"@c1929"},{"text":"Sống yên ổn hơn trăm năm tại Hắc Thạch Thành dưới sự bảo vệ ngầm của nhiều cường giả ẩn thế mà bản thân không hề hay biết","chuong":"@c1942"},{"text":"Qua đời tại Hắc Thạch Thành khi tuổi thọ phàm nhân năm trăm năm đã tới cực hạn, dặn dò Đông Mai trước lúc lâm chung","chuong":"@c1972"}],"kinhLich":[{"mucCt":"vua","text":"Được Vương Lâm đưa về Hắc Thạch Thành sau gần hai năm đi đường, trong thời gian đó Vương Lâm đã từ từ tách tàn hồn Lý Mộ Uyển khỏi thân thể nàng mà không gây tổn thương. Trở về nơi ở thấy Thường Di và Đông Mai đợi sẵn, cắn môi mỉm cười nói đã về rồi.","anchor":"Trong thân thể nàng có tàn hồn của Uyển nhi","bridge":true,"khoang":"@c1930"},{"chuong":"@c1942","importance":"normal","mucCt":"gon","tieuDe":"Được bảo vệ ẩn ở Hắc Thạch Thành","text":"Ở Hắc Thạch Thành hơn trăm năm, đã có dấu vết năm tháng, không hề biết có nhiều cường giả ẩn thế (cả thành chủ) suốt đời bảo vệ nàng theo lệnh Kế Đô (gốc từ Vương Lâm).","anchor":"Nữ tử đó tên là Tống Trí Hơn một trăm năm qua Tống Trí không còn giống năm xưa mà đã có dấu vết của năm tháng."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Người bảo hộ, tách tàn hồn cứu nàng","ghiChu":"@c1930"},{"ten":"Thường Di","tag":"khac","quanHe":"Bà lão hầu hạ, đợi nàng trở về","ghiChu":"@c1930"},{"ten":"Đông Mai","tag":"khac","quanHe":"Nha hoàn, đợi nàng trở về","ghiChu":"@c1930"},{"ten":"Lý Mộ Uyển","tag":"khac","quanHe":"Tàn hồn Lý Mộ Uyển dung hợp trong thân thể nàng","ghiChu":"@c1930"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Ngọc giản (thần niệm Vương Lâm)","trangThai":"dang-co","moTa":"Ngọc giản có thần niệm của Vương Lâm bảo đảm bình an cả đời","nguon":"@c1930"}]}},"nguon":["@c1930","@c1942"]},{"id":"tong-thien","name":"Tống Thiên","cn":"宋天","aliases":["Tống Tôn","Tống Thiên Đại Thiên Tôn"],"gioiTinh":"nam","theLuc":[{"ten":"Thủy Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Đại Thiên Tôn","trangThai":"song","blurb":"Tống Thiên là Đại Thiên Tôn đả tọa tại Nguyên Thủy Sơn, trấn thủ Thủy Cổ nhất mạch trong nội bộ Cổ Tộc, từng nhận Đông Man hoàng tử Hoàng Man làm đệ tử và thiên vị hắn trong cuộc tranh đoạt hoàng tôn. Khi Vương Lâm tiến vào lãnh địa Cổ Tộc, Tống Thiên nghênh chiến bằng toàn lực — tung cả Nguyên Thủy Sơn và Nguyên Thủy trấn áp — nhưng bại trận, sau đó chủ động mở Tổ Miếu, hộ pháp ba năm cho Vương Lâm để bồi thường chuyện cũ, và cuối cùng cung kính tôn xưng Vương Lâm là \"Vương tôn\" tại Thái Cổ Thần Cảnh.","vaiTro":"Đại Thiên Tôn trấn thủ Thủy Cổ nhất mạch — từ đối thủ chuyển thành đồng minh của Vương Lâm","tinhCach":"Lạnh lùng quyết đoán, dám nghênh chiến dù biết bất lợi; biết thời thế, chịu nhận thua trước kẻ mạnh hơn; trọng lời hứa, sẵn sàng bồi thường lỗi lầm năm xưa","tabs":{"diem":[{"text":"Đả tọa tại Nguyên Thủy Sơn với tư cách Đại Thiên Tôn Thủy Cổ nhất mạch, nhận Hoàng Man làm đệ tử","chuong":"@c1930"},{"text":"Khai mở Nguyên Thủy Trận trên Nguyên Thủy Sơn để đối phó Vương Lâm khi bị khóa cứng","chuong":"@c1939"},{"text":"Tung Nguyên Thủy Sơn và thi triển Nguyên Thủy trấn áp nhưng bại trận trước Vương Lâm, chấp nhận thua","chuong":"@c1941"},{"text":"Mở Tổ Miếu cho Vương Lâm, giới thiệu pho tượng Cổ Tổ do Cổ Đạo Đại Thiên Tôn điêu khắc","chuong":"@c1942"},{"text":"Khoanh chân trước Tổ Miếu hộ pháp cho Vương Lâm suốt ba năm để bồi thường chuyện năm xưa","chuong":"@c1945"},{"text":"Cùng Cực Cổ Đại Thiên Tôn cung kính gọi Vương Lâm là Vương tôn tại Thái Cổ Thần Cảnh","chuong":"@c1970"}],"kinhLich":[{"chuong":"@c1930","importance":"bridge","mucCt":"gon","text":"Được nhắc tên là Đại Thiên Tôn Thủy Cổ nhất mạch, không thích Kế Đô nhưng nhận Hoàng Man làm đệ tử; Vương Lâm hứa xuất quan sẽ gặp hắn giúp Kế Đô.","anchor":"Đại Thiên Tôn Tống Thiên của Thủy Cổ nhất mạch chú ý tới ngươi"},{"chuong":"@c1933","importance":"normal","mucCt":"ky","tieuDe":"Ra ấn Giải phong can thiệp dung hợp chân thân","text":"Ngồi tại Nguyên Thủy Sơn cùng đệ tử Đông Man hoàng tử, cảm nhận uy áp Vương Lâm từ xa. Nhận ra Vương Lâm đang dung hợp chân thân, nhận xét chân thân có chút bất phàm. Hé lộ quá khứ: hơn trăm năm trước Vương Lâm đại náo hoàng cung Đạo Cổ giết Đạo Cổ hoàng tôn, toàn mạng nhờ Huyền La không ra tay. Cổ Đạo Đại Thiên Tôn im lặng sau sự kiện đó khiến Tống Thiên lo ngại, vì thế chưa vội chỉ định Đông Man làm hoàng tôn. Cho rằng Vương Lâm không nể mặt khi dung hợp chân thân trên lãnh thổ Thủy Cổ mà không bẩm báo, quyết định giáo huấn, ra ấn ký Giải phong hướng về phía Vương Lâm.","anchor":"Nhưng hiện giờ nếu hắn đã chọn Thủy Cổ nhất mạch ta là nơi dung hợp chân thân, mà lại không bẩm báo với bổn tôn thì đúng là đã không nể mặt bổn tôn rồi"},{"mucCt":"gon","text":"Đang đả tọa tại Nguyên Thủy Sơn bên ngoài Thủy Cổ hoàng thành, bị ánh mắt Hình Phạt Lục Mặc xuyên không gian chiếu tới, thần sắc đại biến, vội túm Hoàng Man bay lên, mỏm đá nơi vừa ngồi lập tức sụp đổ hóa đá vụn.","anchor":"Thân thể Tống Thiên run lên hít sâu một hơi, theo tiềm thức đứng dậy, thần sắc đại biến","bridge":true,"khoang":"@c1934"},{"mucCt":"vua","text":"Sắc mặt tái nhợt suy tư kịch biến ba mươi sáu quận Cổ Tộc có liên quan Vương Lâm không, quát Hoàng Man im lặng. Xé khe không gian triệu Cổ Ma vạn trượng, truyền thần niệm qua đám tơ xanh từ mi tâm vào Cổ Ma để điều khiển từ xa rồi bản thân ngồi bất động. Qua Cổ Ma cảm nhận Vương Lâm đang điều khiển quy tắc thiên địa, thần sắc đại biến kinh hãi.","anchor":"Điều khiển quy tắc thiên địa! Là. là.","bridge":true,"khoang":"@c1938"},{"chuong":"@c1939","importance":"normal","mucCt":"ky","tieuDe":"Bị khóa cứng — mở Nguyên Thủy Trận đối phó","text":"Thần niệm trong thân Cổ Ma kinh hãi trước sức mạnh Vương Lâm điều khiển quy tắc thiên địa, nhớ chỉ Cổ Đạo Đại Thiên Tôn từng làm được. Định bỏ chạy qua khe trời nhưng bị Vương Lâm dùng Định Thân Thuật khóa cứng cả thân Cổ Ma lẫn thần niệm, dẫn động Nguyên Thần bản thể ở Nguyên Thủy Sơn. Bản thể mở mắt tái nhợt, hạ lệnh mở Nguyên Thủy Trận, quát Hoàng Man rằng nếu thất bại hoàng tôn sẽ là Kế Đô. Bay lên trời rút chiến phủ loang lổ chứa tàn hồn từ Nguyên Thủy Sơn chuẩn bị toàn lực. Mặt trời Đại Thiên Tôn của hắn không chịu kiểm soát tự bay lên trong dị tượng.","anchor":"Tống Thiên đang ngồi khoanh chân ở nơi đó mở mạnh hai mắt, sắc mặt hắn tái nhợt"},{"chuong":"@c1940","importance":"normal","mucCt":"ky","tieuDe":"Đại chiến Vương Lâm, bại nhưng không khuất","text":"Trên Nguyên Thủy Sơn cảm nhận thần niệm trên Cổ Ma bị Vương Lâm xóa, biết đối phương sẽ tới. Thầm than không chắc thắng nhưng thân là Đại Thiên Tôn không thể khuất phục mà không chiến. Kích hoạt Nguyên Thủy Trận bao phủ ngọn núi, cầm chiến phủ do Cổ Đạo Đại Thiên Tôn ban. Đề nghị Vương Lâm đánh một trận, nếu Vương Lâm thắng sẽ chỉ định Kế Đô làm hoàng tôn trăm năm tới. Khai chiến: phóng thiên quân vạn mã từ trận pháp, tay phải chém chiến phủ. Bị Vương Lâm ba chỉ phá tan tất cả, chiến phủ vỡ vụn, phun máu lui trăm trượng đạp lên đỉnh Nguyên Thủy Sơn. Không chịu thua, cười lớn bay lên bầu trời, chụp tay nhổ cả Nguyên Thủy Sơn lên khỏi mặt đất tiếp tục chiến. Tu vi cao hơn Đạo Nhất một chút, không kém Võ Phong mấy.","anchor":"Tống Thiên thầm than. Một trận chiến này hắn không chắc thắng nhưng nếu muốn hắn không chiến mà chịu khuất phục thì thân hắn là Đại Thiên Tôn lại không thể làm được"},{"chuong":"@c1941","importance":"normal","mucCt":"ky","tieuDe":"Tung Nguyên Thủy Sơn thất bại, nhận thua trước Vương Lâm","text":"Nhấc Nguyên Thủy Sơn ném về phía Vương Lâm, phun máu thi triển Nguyên Thủy trấn áp nhưng bị Vương Lâm dùng một chỉ của Cổ Tổ chặn đứng. Bị một chưởng đẩy phun máu lảo đảo, chứng kiến Vương Lâm thu nhỏ Nguyên Thủy Sơn thì đau khổ bỏ kháng cự, ôm quyền nhận thua. Dùng thân phận Đại Thiên Tôn bảo vệ Thủy Cổ tuyên bố Kế Đô một trăm năm sau sẽ là hoàng tôn.","anchor":"Tống mỗ thân là người bảo vệ cho Thủy Cổ nhất mạch, thân là Đại Thiên Tôn, hôm nay thừa nhận Kế Đô hoàng tử một trăm năm sau sẽ là hoàng tôn của Thủy Cổ nhất mạch ta!"},{"chuong":"@c1942","importance":"normal","mucCt":"vua","tieuDe":"Mở Tổ Miếu tiễn Vương Lâm","text":"Đứng bên Vương Lâm trước pho tượng Cổ Tổ, giới thiệu tượng do Cổ Đạo Đại Thiên Tôn điêu khắc từ ba ngọn núi sau khi Cổ Tổ biến mất. Ôm quyền tiễn biệt Vương Lâm khi Tổ Miếu mở, sau đó đứng hồi lâu mới than nhẹ rời đi.","anchor":"Vương huynh, Tổ Miếu đã mở. Tống mỗ không tiễn nữa. Bảo trọng!"},{"mucCt":"vua","text":"Khoanh chân trước Tổ Miếu hộ pháp cho Vương Lâm suốt 36 tháng. Phân tích Vương Lâm có thể kiên trì khoảng một năm, nhớ bản thân năm xưa kiên trì 11 tháng. Khi Vương Lâm vượt 18 tháng thì biến sắc, tới 30 tháng đứng dậy cho rằng Vương Lâm là kẻ điên cuồng. Khi phân thần thành công, lui lại ngàn trượng, thì thào kết luận: lần đầu phân thần — thành, hoàn toàn tan nát, dung hợp hoàn mỹ.","anchor":"Một kẻ điên cuồng! Hắn có thể có tu vi như vậy có quan hệ rất lớn với sự điên cuồng này","bridge":true,"khoang":"@c1944"},{"mucCt":"vua","text":"Đã hộ pháp cho Vương Lâm ba năm trong lần phân thần đầu, tới vì muốn bồi thường chuyện năm xưa, sẵn sàng ra tay nếu Vương Lâm gặp nguy. Lần phân thần đầu xong, cất bước rời đi về Nguyên Thủy Sơn tiếp tục đả tọa. Năm thứ mười ba rưỡi khi luồng lực lượng Hồn Huyết Cổ Tổ xuất hiện, bất ngờ mở mắt kinh nghi. Khi quầng sáng bắt đầu biến mất, nhận định nếu mười tám quầng tiêu tán hết mà Vương Lâm chưa dung hợp thì phải hồn phi phách tán.","anchor":"Tống Thiên hít sâu một hơi nhíu mày nhìn về phía Tổ Miếu","bridge":true,"khoang":"@c1945"},{"importance":"bridge","mucCt":"gon","chuong":"@c1948","text":"Đứng trên Nguyên Thủy Sơn chứng kiến sự kiện pho tượng Cổ Tổ, kinh ngạc nhận ra Vương Lâm đã có giọt Hồn Huyết thứ hai trong tổng ba giọt sáng tạo Cổ Thần.","anchor":"Không ngờ lại là Hồn Huyết! Ba giọt Hồn Huyết đã sáng tạo ra Cổ Thần."},{"chuong":"@c1951","importance":"bridge","mucCt":"gon","text":"Cảm nhận chấn động thiên địa từ trận chiến Cổ Đạo – Vương Lâm, cùng Huyền La lao tới bồn địa.","anchor":"Huyền La. Tống Thiên, còn có Đại Thiên Tôn của Cực Cổ nhất mạch"},{"importance":"bridge","mucCt":"gon","chuong":"@c1952","text":"Một trong ba Đại Thiên Tôn Cổ Tộc bị kinh động bởi trận chiến, khiếp sợ khi cảm nhận luồng hút Cổ Hóa Thiên Địa.","anchor":"chuyện tương tự cũng phát sinh tại mặt đất cổ Tộc với ba người Tống Thiên"},{"chuong":"@c1954","importance":"bridge","mucCt":"gon","text":"Bay tới chiến trường cùng các Đại Thiên Tôn, thì thào nhận xét dấu vết chiến đấu mấy trăm năm không tiêu tán, đồng ý hợp lực thi triển thần thông nghịch chuyển.","anchor":"Dấu vết chiến đấu này mấy trăm năm cũng không tiêu tan"}],"tuViMoc":[],"nhanMach":[{"ten":"Hoàng Man","tag":"su-mon","quanHe":"Đệ tử, được Tống Thiên coi trọng","ghiChu":"@c1930"},{"ten":"Kế Đô hoàng tử","tag":"khac","quanHe":"Hoàng tử không được ưa thích","ghiChu":"@c1930"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1930","@c1933","@c1934","@c1938","@c1939","@c1940","@c1941","@c1942","@c1943","@c1944","@c1945","@c1948","@c1951","@c1952","@c1954"]},{"id":"hoang-man","name":"Hoàng Man","cn":"荒蛮","aliases":["Đông Man"],"gioiTinh":"nam","theLuc":[{"ten":"Thủy Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Hoàng Man là hoàng đệ của Kế Đô tại Thủy Cổ hoàng tộc, được Đại Thiên Tôn Tống Thiên nhận làm đệ tử và thường trú trên Nguyên Thủy Sơn. Nhờ sư tôn và phụ hoàng thiên vị, hắn từng là ứng viên sáng giá cho ngôi hoàng tôn đời kế, song sau biến cố Vương Lâm đến Nguyên Thủy Sơn, thế cục đảo chuyển — mười lăm năm sau hắn chỉ được phong vương và bị điều đi trấn thủ biên cương.","vaiTro":"Hoàng đệ Kế Đô — đệ tử Đại Thiên Tôn Tống Thiên, tranh đoạt ngôi hoàng tôn Thủy Cổ","tinhCach":"Không cam chịu khuất phục, có tâm tranh đoạt; biết nhẫn nhịn trước cường giả nhưng chớp thời cơ phản đối","tabs":{"diem":[{"text":"Được Đại Thiên Tôn Tống Thiên nhận làm đệ tử, thường trú trên Nguyên Thủy Sơn","chuong":"@c1930"},{"text":"Đứng sau sư tôn tại Nguyên Thủy Sơn, cảm nhận uy áp Vương Lâm qua phương thức kỳ dị của Tống Thiên","chuong":"@c1933"},{"text":"Bị Tống Thiên quát im lặng và dọa mất ngôi hoàng tôn nếu thất bại","chuong":"@c1939"},{"text":"Trong lòng không cam, lợi dụng lúc Kế Đô quỳ trước Vương Lâm để phản đối, tuyên bố hoàng tôn tương lai chỉ có thể quỳ trước chính mình","chuong":"@c1941"},{"text":"Sau mười lăm năm chỉ được phong vương, rời hoàng thành Thủy Cổ đi trấn thủ biên cương","chuong":"@c1942"}],"kinhLich":[{"chuong":"@c1930","importance":"bridge","mucCt":"vua","text":"Được nhắc là hoàng đệ Kế Đô, đã được Đại Thiên Tôn Tống Thiên nhận làm đệ tử và thường ở trên Nguyên Thủy Sơn, phụ hoàng cũng thiên vị hắn.","anchor":"hoàng đệ Hoàng Man lại được Tống Tôn coi trọng, lúc nào cũng ở trên Nguyên Thủy Sơn"},{"chuong":"@c1933","importance":"bridge","mucCt":"vua","tieuDe":"Cảm nhận uy áp Vương Lâm tại Nguyên Thủy Sơn","text":"Đứng sau sư tôn Tống Thiên tại Nguyên Thủy Sơn, cảm nhận uy áp Vương Lâm qua phương thức kỳ dị của sư tôn, tướng mạo thô ráp dữ tợn nhưng đầy khiếp sợ. Hỏi sư tôn về Vương Lâm, hé lộ Tống Thiên thủy chung chưa chỉ định hắn làm hoàng tôn.","anchor":"Sư tôn thủy chung vẫn không chỉ định đệ tử là hoàng tôn chẳng lẽ chính là vì người này?"},{"chuong":"@c1934","importance":"bridge","mucCt":"gon","text":"Đang cùng Tống Thiên tại Nguyên Thủy Sơn, bị Tống Thiên túm lấy bay lên khi mỏm đá sụp đổ trước uy hiếp của Hình Phạt Lục Mặc.","anchor":"giơ tay túm lấy Hoàng Man, thân thể bỗng nhiên bay lên"},{"chuong":"@c1938","importance":"bridge","mucCt":"gon","text":"Gọi sư tôn nhưng bị Tống Thiên quát im lặng.","anchor":"Phía sau hắn truyền tới tiếng nói do dự của HoàngMan."},{"chuong":"@c1939","importance":"normal","mucCt":"vua","tieuDe":"Bị Tống Thiên quát — dọa mất ngôi hoàng tôn","text":"Đứng trên Nguyên Thủy Sơn không biết chuyện gì xảy ra, bị Tống Thiên quát câm miệng và dọa nếu thất bại thì hoàng tôn trăm năm sau sẽ là Kế Đô chứ không phải hắn.","anchor":"nếu cuối cùng phải thất bại thì Thủy Cổ hoàng tôn một trăm năm sau sẽ không phải là ngươi mà là Kế Đô kia"},{"chuong":"@c1940","importance":"bridge","mucCt":"gon","text":"Đứng phía sau Tống Thiên trên Nguyên Thủy Sơn, vẻ mặt khổ sở trầm mặc. Khi Tống Thiên nhổ Nguyên Thủy Sơn bay lên, bay ra khỏi ngọn núi cùng những người khác.","anchor":"Vẻ mặt Hoàng Man phía sau lộ vẻ khổ sở trầm mặc không nói"},{"chuong":"@c1941","importance":"bridge","mucCt":"gon","text":"Trong lòng không cam, lợi dụng lúc Kế Đô quỳ trước Vương Lâm để phản đối, nói hoàng tôn tương lai chỉ có thể quỳ trước Cổ Đạo Đại Thiên Tôn, nhưng cuối cùng sắc mặt tái nhợt bất lực.","anchor":"Kế Đô ngươi thân là hoàng tử sao có thể tùy tiện nhận nghĩa phụ!"},{"chuong":"@c1942","importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1942","text":"Sau 15 năm được phong vương, rời khỏi Thủy Cổ hoàng thành trấn thủ biên cương."}],"tuViMoc":[],"nhanMach":[{"ten":"Tống Thiên","tag":"su-mon","quanHe":"Sư phụ, Đại Thiên Tôn Thủy Cổ","ghiChu":"@c1930"},{"ten":"Kế Đô hoàng tử","tag":"ho-hang","quanHe":"Hoàng huynh, đối thủ tranh hoàng tôn","ghiChu":"@c1930"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1930","@c1933","@c1934","@c1938","@c1939","@c1940","@c1941","@c1942"]},{"id":"dai-hoang-tu","name":"Đại hoàng tử","cn":"","aliases":["Hoàng Man"],"gioiTinh":"nam","theLuc":[{"ten":"Thủy Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Hoàng huynh của Kế Đô ở Thủy Cổ nhất mạch. Lúc sinh có thiên địa dị tượng khiến Cổ Đạo Đại Thiên Tôn chú ý gửi lễ vật, là đối thủ lớn trong tranh đoạt hoàng tôn.","vaiTro":"Hoàng tử Thủy Cổ, đối thủ tranh đoạt hoàng tôn của Kế Đô","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Lúc sinh có thiên địa dị tượng khiến Cổ Đạo Đại Thiên Tôn chú ý gửi lễ vật.","chuong":"@c1930"}],"kinhLich":[{"chuong":"@c1930","importance":"bridge","mucCt":"gon","text":"Được Kế Đô nhắc tới: lúc sinh có thiên địa dị tượng khiến Cổ Đạo Đại Thiên Tôn chú ý gửi lễ vật, là đối thủ lớn trong tranh đoạt hoàng tôn.","anchor":"Đại Thiên Tôn Tống Thiên của Thủy Cổ nhất mạch chú ý tới ngươi"},{"chuong":"@c1941","importance":"bridge","mucCt":"gon","text":"Phản đối Kế Đô quỳ nhận Vương Lâm làm nghĩa phụ nhưng cuối cùng sắc mặt tái nhợt không dám nói thêm.","anchor":"Kế Đô ngươi thân là hoàng tử sao có thể tùy tiện nhận nghĩa phụ!"}],"tuViMoc":[],"nhanMach":[{"ten":"Kế Đô hoàng tử","tag":"ho-hang","quanHe":"Hoàng đệ, đối thủ tranh hoàng tôn","ghiChu":"@c1930"},{"ten":"Cổ Đạo Đại Thiên Tôn","tag":"khac","quanHe":"Cổ Đạo Đại Thiên Tôn chú ý gửi lễ vật khi sinh","ghiChu":"@c1930"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1930","@c1941","@c1942"]},{"id":"huyen-la","name":"Huyền La","cn":"玄罗","aliases":[],"gioiTinh":"nam","canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1932","tieuDe":"Hoãn chuyển thế chờ bình yên","text":"Sau khi La Trần lên hoàng tôn liền bế quan, thời gian chuyển thế đã tới gần nhưng gặp Thái Cổ Thần Cảnh nên áp chế chờ đợi bình yên.","anchor":"Thời gian chuyển thế của hắn đã tới gần, lại gặp Thái Cổ Thần Cảnh xuất hiện"},{"chuong":"@c1933","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được Tống Thiên nhắc đến: là sư tôn Vương Lâm, Vương Lâm toàn mạng rời hoàng cung Đạo Cổ vì Huyền La không ra tay.","anchor":"Sở dĩ hắn có thể toàn mạng đi ra khỏi hoàng cung Đạo Cổ đó là vì Huyền La không ra tay!"},{"chuong":"@c1940","importance":"bridge","mucCt":"gon","text":"Trong hoàng thành Đạo Cổ nhất mạch bế quan, cảm nhận khí tức Vương Lâm thành Đại Thiên Tôn, ha hả cười lớn vui mừng.","anchor":"Huyền La đang bế quan cảm nhận được khí tức thuộc về Vương Lâm khuôn mặt lộ ra nụ cười rất vui vẻ ha hả cười lớn"},{"chuong":"@c1944","importance":"bridge","mucCt":"vua","tieuDe":"Hộ pháp cho Vương Lâm phân thần","text":"Ngồi trên bầu trời hộ pháp cho Vương Lâm suốt quá trình phân thần. Tới tháng 35 lộ vẻ lo lắng, muốn nhắc nhở nhưng sợ xảy ra ngoài ý muốn. Khi phân thần thành công, đứng dậy kích động nhìn.","anchor":"trong nội tâm Huyền La, đệ tử duy nhất của hắn vẫn là đứa trẻ được hắn mang ra khỏi động phủ giới"},{"mucCt":"vua","text":"Ngồi trên bầu trời Thủy Cổ hoàng thành hộ pháp cho Vương Lâm suốt quá trình phân thần, vừa bảo vệ Đạo Cổ nhất mạch vừa bảo vệ đệ tử lúc suy yếu. Khi quầng sáng biến mất, thần sắc đại biến, lao xuống Tổ Miếu muốn cứu đệ tử nhưng bị luồng lực lượng Hồn Huyết Cổ Tổ đẩy bắn ngược ra, không cách nào vào được.","anchor":"Huyền La trên bầu trời trong nháy mắt nhìn thấy cảnh tượng này thần sắc đột nhiên đại biến","bridge":true,"khoang":"@c1945"},{"chuong":"@c1946","importance":"normal","mucCt":"ky","tieuDe":"Trả giá lão hóa để cứu Vương Lâm trong Tổ Miếu","text":"Bị ngăn bên ngoài Tổ Miếu, liên tục truyền thần niệm và vung quyền phát tiếng rống kinh thiên cố xông vào nhưng nhiều lần bị bắn ngược ra. Tự xưng sư tôn Huyền La trước cả Thủy Cổ hoàng thành, tiếng vang khiến tộc nhân nhận ra người độ kiếp là Vương Lâm. Cuối cùng lọt được vào sâu Tổ Miếu gầm gọi Vương Lâm tỉnh lại, nhưng hình dáng đã biến từ thanh niên thành lão già tóc bạc trắng, bị năm tháng bao phủ — cái giá phải trả khi cưỡng ép xông vào. Bị phân lực đánh bay ra ngoài, mỉm cười khi thấy 27 quầng sáng bùng nổ, bay lên trời khoanh chân tiếp tục hộ pháp cho lần phân thần cuối cùng.","anchor":"Chẳng qua hình dáng Huyền La không còn vẻ thanh niên mà đã bị năm tháng bao phủ!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1948","text":"Chứng kiến Vương Lâm vượt qua Cổ Đạo tam phân thần và đạt giọt Hồn Huyết thứ hai, kinh ngạc không thể ngờ.","anchor":"Dù là hắn cũng không thể ngờ nổi là Vương Lâm có thể đạt được giọt Hồn Huyết thứ hai!"},{"chuong":"@c1949","importance":"normal","mucCt":"vua","tieuDe":"Lặng lẽ rời đi rồi đón Vương Lâm ba năm","text":"Ngay khi giọt hồn huyết thứ hai giáng xuống, không muốn gặp mặt Vương Lâm nên yên lặng xoay người rời đi về Đạo Cổ. Sau đó đón Vương Lâm ở hậu sơn Đạo Cổ Điện, sư đồ ở bên nhau ba năm rồi từ biệt, biết có lẽ ba trăm năm sau mới gặp lại.","anchor":"Hắn không muốn gặp Vương Lâm, yên lặng xoay người rời đi, đi về phía Đạo cổ"},{"chuong":"@c1951","importance":"bridge","mucCt":"gon","text":"Cảm nhận chấn động thiên địa từ trận chiến Cổ Đạo – Vương Lâm, cùng Tống Thiên và Đại Thiên Tôn Cực Cổ nhất mạch bay về phía bồn địa.","anchor":"Huyền La. Tống Thiên, còn có Đại Thiên Tôn của Cực Cổ nhất mạch"},{"chuong":"@c1954","importance":"bridge","mucCt":"gon","text":"Bay tới chiến trường cùng các Đại Thiên Tôn, thần thức cảm nhận dấu vết chiến đấu, chấn động, nghi ngờ người giao chiến là Vương Lâm.","anchor":"Là. Vương Lâm sao"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Triệu hồi Tứ Đại Linh, hoàn thành con đường chuyển thế đầu thai thông tới Tiên Cương","chuong":"@c1696"},{"text":"Nhận Vương Lâm làm đệ tử duy nhất trên con đường mình rồng, dùng máu Cửu Dương bảo hộ và giao phó trọng trách bảo vệ Đạo Cổ nhất mạch","chuong":"@c1699"},{"text":"Âm thầm chuẩn bị ba nơi tạo hóa và pháp bảo cho đệ tử nhiều năm, đích thân dẫn Vương Lâm cầu kiến Cổ Đạo","chuong":"@c1909"},{"text":"Can thiệp trước hoàng quyền Đạo Cổ, bảo vệ địa vị đệ tử duy nhất khi Thường Thị ép Vương Lâm quỳ","chuong":"@c1908"},{"text":"Trả giá lão hóa thân thể, vung quyền xông vào Tổ Miếu cứu Vương Lâm trong lúc phân thần","chuong":"@c1946"},{"text":"Lặng lẽ rời đi sau khi chứng kiến đệ tử vượt tam phân thần Cổ Đạo, ba năm sau đón Vương Lâm và nhận ngọc giản chuẩn bị chuyển thế","chuong":"@c1949"}]},"nguon":["@c1932","@c1933","@c1940","@c1943","@c1944","@c1945","@c1946","@c1948","@c1949","@c1951","@c1954"],"vaiTro":"Đại Thiên Tôn Cửu Dương — sư tôn duy nhất của Vương Lâm tại Cổ Tộc","tinhCach":"Uy nghiêm nhưng nội tâm trọng nghĩa tình, sẵn sàng trả giá vì đệ tử; kiên nhẫn âm thầm chờ đợi và che chở nhiều năm không cần đệ tử biết; thận trọng biết tiến thoái trước thân phận nhạy cảm giữa các thế lực; cương quyết bảo vệ người mình nhận trước hoàng quyền và cường giả","blurb":"Huyền La là Đại Thiên Tôn cảnh Cửu Dương trấn giữ động phủ giới tại La Thiên tinh vực, người mở con đường chuyển thế đầu thai thông tới Tiên Cương và nhận Vương Lâm làm đệ tử duy nhất, dùng máu Cửu Dương bảo hộ và giao phó trọng trách bảo vệ Đạo Cổ nhất mạch. Suốt nhiều năm ông âm thầm chú ý mọi chuyện của đệ tử, chuẩn bị tạo hóa và pháp bảo, đích thân dẫn Vương Lâm cầu kiến Cổ Đạo, can thiệp trước hoàng quyền để bảo vệ hắn, và thậm chí trả giá lão hóa thân thể để xông vào Tổ Miếu cứu đệ tử. Sau khi chứng kiến Vương Lâm đột phá Đại Thiên Tôn và vượt qua tam phân thần Cổ Đạo, ông lặng lẽ rời đi"},{"id":"la-tran","name":"La Trần","cn":"罗尘","aliases":[],"gioiTinh":"nam","canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Tân hoàng tôn Đạo Cổ nhất mạch, nhân vật Đạo Cổ hoàng tộc","tinhCach":"Chưa rõ, mới lên vị còn xa lạ với Đạo Cổ nhất mạch","blurb":"Trở thành tân hoàng tôn Đạo Cổ nhất mạch, nhưng vẫn còn xa lạ với thế lực này, cần thời gian thích ứng. Thánh Hoàng Tổ Diệp Vi tạm thay xử lý mọi việc.","tabs":{"diem":[{"text":"Tân hoàng tôn Đạo Cổ nhất mạch, vừa lên vị còn xa lạ","chuong":"@c1932"}],"kinhLich":[{"importance":"normal","mucCt":"gon","chuong":"@c1932","tieuDe":"Trở thành tân hoàng tôn Đạo Cổ","text":"Trở thành tân hoàng tôn Đạo Cổ nhất mạch, nhưng còn xa lạ với thế lực, Thánh Hoàng Tổ Diệp Vi tạm quyền xử lý.","anchor":"La Trần trở thành tân hoàng tôn"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"theLuc":[{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"}],"nguon":["@c1932"]},{"id":"diep-vi","name":"Diệp Vi","cn":"叶微","aliases":[],"gioiTinh":"nam","canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Thánh Hoàng Tổ Đạo Cổ — nữ tử duy nhất trong lịch sử từng trở thành hoàng tôn Đạo Cổ","tinhCach":"uy nghiêm, thận trọng trước cường giả; biết tiến biết thoái; trách nhiệm với tông môn","blurb":"Diệp Vi là nữ tử duy nhất trong lịch sử từng trở thành Đạo Cổ hoàng tôn, được hậu bối tôn xưng là Thánh Hoàng Tổ. Bà hiện thân từ quan tài tím dưới quảng trường hoàng cung Đạo Cổ, dung hợp đại trận Cổ Tổ uy hiếp Vương Lâm nhưng cuối cùng không thể ngăn y rời đi. Sau biến cố, bà tạm thay hoàng tôn La Trần xử lý mọi chuyện Đạo Cổ nhất mạch.","tabs":{"diem":[{"text":"Hiện thân từ quan tài tím dưới quảng trường hoàng cung Đạo Cổ, lộ hình dạng bà lão khô héo mặc hoàng bào","chuong":"@c1922"},{"text":"Dung hợp đại trận Cổ Tổ uy hiếp Vương Lâm nhưng không thể ngăn y rời đi","chuong":"@c1929"},{"text":"Bay ra khỏi hoàng cung, đứng cạnh Huyền La và khiếp sợ nhìn bầu trời","chuong":"@c1928"},{"text":"Tạm thay hoàng tôn La Trần xử lý mọi chuyện Đạo Cổ nhất mạch","chuong":"@c1932"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1932","tieuDe":"Tạm quyền Đạo Cổ nhất mạch","text":"Tạm thay hoàng tôn La Trần xử lý mọi chuyện Đạo Cổ nhất mạch khi La Trần chưa thích ứng.","anchor":"Thánh Hoàng Tổ Diệp Vi tạm thời thay thế hoàng tôn xử lý tất cả mọi chuyện"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"theLuc":[{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"}],"nguon":["@c1932"]},{"id":"em-gai-ke-do","name":"Em gái Kế Đô","cn":"","aliases":[],"gioiTinh":"nu","canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Em gái Kế Đô hoàng tử, thiếu phụ Thủy Cổ nhất mạch","tinhCach":"Lo lắng cho hoàng huynh; thực tế, khuyên nhủ","blurb":"Em gái Kế Đô hoàng tử, đã lập gia đình với thiên tài cường giả Thủy Cổ nhất mạch. Khuyên Kế Đô nhờ Vương Lâm hỗ trợ tranh ngôi nhưng bị từ chối.","tabs":{"diem":[{"text":"Em gái Kế Đô, lo lắng trước sự biến đổi tính cách của hoàng huynh","chuong":"@c1932"}],"kinhLich":[{"importance":"bridge","mucCt":"vua","chuong":"@c1932","tieuDe":"Khuyên Kế Đô nhờ Vương Lâm","text":"Ngồi trong hành cung cùng Kế Đô và phu quân, khuyên hoàng huynh nhờ Vương Lâm tiền bối hỗ trợ tranh ngôi nhưng bị từ chối. Lo lắng khi cảm nhận hoàng huynh biến đổi tính cách lớn.","anchor":"Hoàng huynh, Vương Lâm tiền bối đã bế quan suốt mấy trăm năm rồi"}],"tuViMoc":[],"nhanMach":[{"ten":"Kế Đô hoàng tử","tag":"ho-hang","quanHe":"Hoàng huynh","ghiChu":"Khuyên nhủ nhờ Vương Lâm nhưng bị từ chối"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"theLuc":[{"ten":"Thủy Cổ nhất mạch","trangThai":"gan-bo"}],"nguon":["@c1932"]},{"id":"thanh-nien-tu-y","name":"Thanh niên tử y","cn":"","aliases":["Thanh niên mặc tử bào"],"gioiTinh":"nam","canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1932","tieuDe":"Nghi ngờ Vương Lâm bị thương","text":"Tâm phúc Kế Đô, nghi ngờ Vương Lâm bị thương sau khi bế quan liên tục và liệu có đủ ảnh hưởng Tống Tôn.","anchor":"Nghe đồn vị tiền bối này là Đệ Thập Dương của Tiên Cương, nhưng năm đó hắn sau khi rời khỏi Đạo Cổ nhất mạch liền lập tức bế quan ở nơi này xem ra hẳn là bị thương rồi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1932"]},{"id":"co-dao-dai-thien-ton","name":"Cổ Đạo Đại Thiên Tôn","cn":"古道大天尊","aliases":["Cổ Đạo","Cổ Tổ","Tiên Hoàng Liên Đạo Chân","Tiên Hoàng đời nay"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Ngồi trên tầng cao nhất ngọn tháp tại Cổ Đạo Sơn, nhắm mắt tu luyện. Cảm ứng được Vương Lâm dung hợp chân thân, mở mắt nhìn về Thủy Cổ, nói 'Chân thân dung hợp?' giọng khàn bình tĩnh không lộ tâm tình. Được Tống Thiên nhắc đến với sự lo ngại — sau vụ Vương Lâm giết Đạo Cổ hoàng tôn, Cổ Đạo Đại Thiên Tôn không nói gì khiến Tống Thiên khó hiểu.","anchor":"Hồi lâu sau, hư ảnh kia truyền ra tiếng tự nói khàn khàn","bridge":true,"khoang":"@c1933"},{"chuong":"@c1938","importance":"bridge","mucCt":"gon","text":"Được Cửu Đế và Vương Lâm nhắc tới là cường giả đệ nhất Tiên Cương, đã đạt cảnh giới truyền thuyết, từng giết mấy Đại Thiên Tôn nhờ điều khiển quy tắc thiên địa.","anchor":"Cổ Đạo Đại Thiên Tôn sở dĩ là cường giả đệ nhất Tiên Cương chính là do hắn nhất định đã đạt tới bước kia!"},{"chuong":"@c1950","importance":"major","mucCt":"ky","tieuDe":"Đối mặt Vương Lâm, khai chiến đỉnh cao","text":"Xuất hiện từ khe hở bầu trời trong sương mù, lần đầu đối mặt trực tiếp Vương Lâm — hai cường giả nửa bước đạp thiên cảnh. Yêu cầu Vương Lâm lưu lại Cổ Tộc ba trăm năm cho tới khi Thái Cổ Thần Cảnh mở ra. Khi Vương Lâm hỏi tại sao không diệt tiên tộc, tiết lộ lý do: Cổ Tổ ban thưởng cho hắn, khác với Vương Lâm. Thương lượng bất thành, ra tối hậu thư rồi khai chiến. Hóa thành vụ thú khổng lồ chín đầu giống Cát Cùng ở vùng đất Cổ Thần, mang khí tức tang thương cổ xưa. Điểm một ngón tay triệu tập quy tắc thiên địa, vận dụng Phong Vân Lôi Điện cùng ngũ hành, ngưng tụ thành ngón tay hư ảo mang lực hủy diệt nhắm vào mi tâm Vương Lâm.","anchor":"Lão phu đã rất lâu không ra tay với người khác rồi"},{"chuong":"@c1951","importance":"normal","mucCt":"ky","tieuDe":"Giao chiến trực diện với Vương Lâm","text":"Với tư cách người mạnh nhất Tiên Cương Đại Lục, lần đầu giao phong trực diện với Vương Lâm. Xuất một chỉ ngưng tụ phong vũ lôi điện cùng ngũ hành, sức mạnh đủ giết chết một Đại Thiên Tôn, thăm dò bất phân thắng bại, cả hai cùng lùi ba bước. Điều khiển vụ thú chín đầu bằng sương mù phóng hào quang chín màu đối kháng Bát Cực Đạo. Triệu mấy trăm quả cầu sương (mỗi quả đủ giết Dược Thiên Tôn), phân liệt thành hơn vạn quả đồng loạt đánh Vương Lâm. Bị hai quyền của Vương Lâm xé rách vụ thú, tay áo bốc khói xám. Trận chiến chấn động toàn Tiên Cương, dẫn động quy tắc thiên địa, khiến các Đại Thiên Tôn hai tộc nhất tề kéo tới.","anchor":"Cổ Đạo Đại Thiên Tôn là người mạnh nhất Tiên Cương Đại Lục"},{"importance":"normal","mucCt":"ky","chuong":"@c1952","tieuDe":"Lộ danh tính Cổ Tổ, thi triển Cổ Hóa Thiên Địa","text":"Sương mù tan hoàn toàn, lộ dung mạo thật: thân gầy, mặc thanh bào, tay phải cụt, tóc xám, tướng mạo giống hệt pho tượng Cổ Tổ trong Ba Hoàng Thành. Xác nhận mình vừa là Cổ Đạo vừa là Cổ Tổ — đã đạt được một phần ký ức và ý chí của Cổ Tổ, tướng mạo dần biến đổi theo. Hé lộ hạn chế: không thể rời xa mặt đất Cổ Tộc, quá xa thì tu vi tan biến — giải thích lý do Tiên Tộc vẫn tồn tại vô số năm. Nói cảm nhận được một chuyện bí ẩn từ ký ức Cổ Tổ suốt vô số năm, không giải thích được. Thách Vương Lâm giao đấu, thi triển Cổ Hóa Thiên Địa lần đầu tiên — thân ảnh ánh sáng khổng lồ hút sạch lực lượng thiên địa toàn Tiên Cương đại lục, biến mắt thành nhật nguyệt, máu thành sông biển, xương thành núi non, tay thành bầu trời, thân thành mặt đất.","anchor":"Ta là Cổ Đạo. cùng là cổ Tổ."},{"importance":"normal","mucCt":"ky","chuong":"@c1953","tieuDe":"Thi triển thức Đạp Thiên độc sáng, bại trước Cửu Khúc Tam Tướng","text":"Bị bước Đạp Thiên của Vương Lâm đánh phun máu, lảo đảo lui hơn trăm trượng, kinh hãi xác nhận đây hoàn toàn là Đạp Thiên Cảnh. Thừa nhận có lẽ không giữ được Vương Lâm nhưng không bỏ cuộc. Tiết lộ tín niệm bất đồng với Cổ Tổ: Cổ Tổ muốn hóa thiên địa, còn Cổ Đạo muốn thiên địa không ngăn được tầm mắt, thân thể, tâm hắn — lấy tâm làm đạo, dùng thiên làm thang. Thi triển một thức Đạp Thiên dùng cả đời cảm ngộ, tạo dòng xoáy khổng lồ bao phủ bình nguyên với bàn chân khổng lồ đạp xuống Vương Lâm, tuyên bố Ngươi là thiên. Cuối cùng thì thào nhận ra đệ tam tướng của Cửu Khúc Tam Tướng là anh đề.","anchor":"Ta dùng Thời gian suốt đời để nghĩ ra một thức Đạp Thiên!"},{"chuong":"@c1954","importance":"major","mucCt":"vua","tieuDe":"Bại trận, ước định ba trăm năm với Vương Lâm","text":"Đạp Thiên Thuật bị Vương Lâm một chỉ phá sụp hoàn toàn. Thừa nhận không thể ngăn bước chân Vương Lâm, hai tay ôm quyền vái sâu, đề nghị ước định ba trăm năm sau khi Thái Cổ Thần Cánh mở ra, Vương Lâm từ bên Cổ Tổ bước vào. Sương mù bao phủ thân, bay về phương hướng cổ tộc.","anchor":"vẻ tang thương trên mặt thoáng cái càng nhiều hơn. mơ hồ lộ ra một tia uể oải và giải thoát"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Được công nhận là đệ nhất nhân Cửu Dương Tiên Cương, từng giết Đại Thiên Tôn trong đại chiến, khiến Tiên Tộc kiêng dè không dám tùy tiện tiến công Cổ Tộc","chuong":"@c1866"},{"text":"Là chỗ dựa then chốt giúp hoàng quyền Đạo Cổ áp chế các Đại Thiên Tôn khác trong tộc, từng truyền khẩu dụ thừa nhận quyền kế vị hoàng hậu Diệp Vi","chuong":"@c1922"},{"text":"Dùng ý chí đặt thử thách một ngàn một trăm mười bậc trên Cổ Đạo Sơn để thử Vương Lâm, đồng thời giữ lời hóa bàn tay đen như Ngũ Chỉ Sơn xuống núi trấn áp lực lượng Tiên Tộc","chuong":"@c1914"},{"text":"Lộ danh tính chính là Cổ Tổ khi sương mù tan hoàn toàn: thân gầy, thanh bào, tay phải cụt, tóc xám, tướng mạo giống hệt Cổ Tổ; thi triển Cổ Hóa Thiên Địa trong trận chiến đỉnh cao với Vương Lâm","chuong":"@c1952"},{"text":"Thi triển thức Đạp Thiên độc sáng nhưng bại trước Cửu Khúc Tam Tướng của Vương Lâm, bị đánh phun máu lảo đảo lui hơn trăm trượng","chuong":"@c1953"},{"text":"Thừa nhận bại trận, Đạp Thiên Thuật bị Vương Lâm một chỉ phá sụp hoàn toàn; chủ động đặt ước định ba trăm năm với Vương Lâm","chuong":"@c1954"}]},"nguon":["@c1933","@c1938","@c1943","@c1950","@c1951","@c1952","@c1953","@c1954"],"canhGioiCaoNhat":"Đạp Thiên cảnh (cầu thứ sáu)","vaiTro":"Đệ nhất cường giả Cổ Tộc — lão tổ trấn giữ hoàng quyền Đạo Cổ, chính thể Cổ Tổ","tinhCach":"Uy nghiêm áp đảo, lấy sức mạnh tuyệt đối làm lẽ trị tộc; thận trọng quan sát, không vội hành động khi chưa thấu triệt đối phương; trọng lời hứa, nói xuống núi thì xuống núi; biết tiến thoái, thừa nhận bại trận và chủ động đặt ước định","blurb":"Cổ Đạo Đại Thiên Tôn là đệ nhất nhân trong Cửu Dương Tiên Cương, cư ngụ trên đỉnh Cổ Đạo Sơn, được xưng là lão tổ Cổ Tộc và bậc tiền bối cùng thời Cổ Tổ — thực chất chính là Cổ Tổ bản thân. Uy thế lịch sử từng giết Đại Thiên Tôn trong đại chiến khiến Tiên Tộc dù chiếm ưu thế số lượng vẫn không dám tùy tiện tiến công Cổ Tộc; hắn là chỗ dựa then chốt giúp hoàng quyền Đạo Cổ nhất mạch áp chế các thế lực trong tộc, từng truyền khẩu dụ thừa nhận quyền kế vị hoàng hậu Diệp Vi. Sau khi trực tiếp giao phong với Vương Lâm, hắn lộ dung mạo thật và danh tính Cổ Tổ, thi triển Cổ Hóa Thiên Địa cùng thức Đạ"},{"id":"thanh-nien-tu-bao","name":"Thanh niên mặc tử bào","cn":"","aliases":[],"gioiTinh":"nam","vaiTro":"Thị vệ tại hành cung Kế Đô hoàng tử, từng bái kiến Tống Thiên","tinhCach":"Có chút kiến thức, biết so sánh uy áp","blurb":"Thanh niên mặc tử bào trong hành cung Kế Đô, từng bái kiến Tống Thiên Đại Thiên Tôn. Không chịu nổi uy áp Vương Lâm khi xuất quan.","trangThai":"song","theLuc":[{"ten":"Thủy Cổ nhất mạch","trangThai":"gan-bo"}],"tabs":{"diem":[{"text":"Từng bái kiến Tống Thiên nhưng chưa bao giờ sợ hãi bằng khi cảm nhận uy áp Vương Lâm","chuong":"@c1933"}],"kinhLich":[{"mucCt":"gon","text":"Toát mồ hôi ướt hết quần áo dưới uy áp Vương Lâm, so sánh uy áp này ngang Tống Thiên Đại Thiên Tôn. Khi nghe Kế Đô nói La Miên thì sắc mặt tái nhợt, nhớ tới dị tượng khi Kế Đô sinh ra.","anchor":"Trong mắt hắn người có thể tản ra luồng uy áp này đủ để có thể so sánh với Tống Thiên Đại Thiên Tôn!","bridge":true,"khoang":"@c1933"}],"tuViMoc":[],"nhanMach":[{"ten":"Kế Đô hoàng tử","tag":"cap-tren","quanHe":"Chủ nhân hành cung","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1933"]},{"id":"la-mien","name":"La Miên","cn":"罗棉","aliases":[],"gioiTinh":"khac","vaiTro":"Mãnh thú bị Cổ Tổ đánh bại và phong ấn trong La Miên Quận","tinhCach":"Hung tàn, điên cuồng, tham lam","blurb":"Mãnh thú năm xưa đại bại trong tay Cổ Tổ, bị phong ấn sâu trong lòng đất La Miên Quận. Hình dạng là quả cầu thịt tròn xoe với một con mắt rất lớn.","trangThai":"tu-vong","theLuc":[],"tabs":{"diem":[{"text":"Mãnh thú bị Cổ Tổ đánh bại và phong ấn, hình dạng quả cầu thịt một mắt","chuong":"@c1933"},{"text":"Khi Vương Lâm dung hợp chân thân, La Miên gào thét xuất hiện từ lòng đất, nhìn ngũ hành chân thân với vẻ tham lam","chuong":"@c1933"}],"kinhLich":[{"chuong":"@c1933","importance":"normal","mucCt":"vua","tieuDe":"Xuất hiện khi Vương Lâm dung hợp chân thân","text":"Khi Vương Lâm dung hợp chân thân, La Miên gào thét điên cuồng từ sâu trong lòng đất La Miên Quận. Hư ảnh xuất hiện là quả cầu thịt tròn xoe với một con mắt lớn, nhìn ngũ hành chân thân và bản nguyên hư ảo Vương Lâm với vẻ hung tàn tham lam. Tiếng thét khiến Kế Đô phun máu.","anchor":"Đó là một quả cầu thịt tròn xoe trên đó có một con mắt rất lớn lộ ra một sự hung tàn và điên cuồng"},{"chuong":"@c1934","importance":"normal","mucCt":"vua","tieuDe":"Bị Vương Lâm trấn, hồn phách làm vật dẫn dung hợp chân thân","text":"Hóa quả cầu thịt hư ảo bùng hắc khí lao tới ngũ hành chân thân, bị Vương Lâm Định Thân Thuật trấn giữa không trung. Bị hút hồn lực làm vật dẫn để rút lần lượt các bản nguyên chân thân, thân thể thu nhỏ dần rồi biến mất chỉ còn con mắt khổng lồ rồi nổ tung, hoàn tất vai trò vật dẫn cho năm chân thân dung hợp.","anchor":"hồn phách đại hung ác này sẽ tự mình đưa tới cửa"}],"tuViMoc":[],"nhanMach":[{"ten":"Cổ Tổ","tag":"doi-thu","quanHe":"Bị Cổ Tổ đánh bại và phong ấn","ghiChu":""},{"ten":"Kế Đô hoàng tử","tag":"khac","quanHe":"Bị Kế Đô trấn áp bằng hành cung theo sắp xếp quốc sư","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1933","@c1934"]},{"id":"quoc-su","name":"Quốc sư","cn":"","aliases":["Quốc sư Thủy Cổ"],"gioiTinh":"nam","trangThai":"tu-vong","tabs":{"kinhLich":[{"chuong":"@c1933","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được nhắc đến: năm xưa bưng bít dị tượng khi Kế Đô sinh ra, sắp xếp cho Kế Đô xây hành cung ở La Miên Quận trước khi chết.","anchor":"Đây là chuyện mà quốc sư đã chết kia sắp xếp trước khi chết"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Được Đạo Cổ hoàng tôn nhắc là người từng khẳng định tàn hồn trong Tống Trí có thể giúp hắn trở thành Cổ Hoàng thống nhất Tam Tộc Cổ","chuong":"@c1911"},{"text":"Muốn tự mình tham dự đại lễ phong hậu, cho thấy sự quan tâm trực tiếp đến đại sự chính trị của Đạo Cổ","chuong":"@c1916"},{"text":"Được Diệp Đạo xác nhận là người ban đầu đưa tàn hồn đã bị phong ấn cho hắn","chuong":"@c1919"},{"text":"Bị Vương Lâm xác định là kẻ lấy hồn Lý Mộ Uyển từ động phủ giới, giao cho Diệp Đạo và thúc giục toàn bộ kế hoạch — chủ mưu đích thực","chuong":"@c1921"},{"text":"Năm xưa bưng bít dị tượng khi Kế Đô sinh ra, sắp xếp cho Kế Đô xây hành cung ở La Miên Quận, bố cục từ rất sớm","chuong":"@c1933"}]},"nguon":["@c1933"],"vaiTro":"Mưu sĩ thần bí của Đạo Cổ — chủ mưu thao túng tàn hồn Lý Mộ Uyển","tinhCach":"mưu tính thâm sâu, hành sự bí ẩn sau màn; chủ động can dự đại sự dù ít lộ diện; bố cục lâu dài, kiên nhẫn giật dây từ xa","blurb":"Quốc sư là nhân vật thần bí đứng sau Đạo Cổ hoàng tôn, từng khẳng định tàn hồn trong Tống Trí có thể giúp hoàng tôn trở thành Cổ Hoàng thống nhất Tam Tộc Cổ. Hắn chính là kẻ lấy hồn Lý Mộ Uyển từ động phủ giới, giao cho Diệp Đạo và thúc giục toàn bộ kế hoạch, cuối cùng bị Vương Lâm xác định là chủ mưu. Ngoài ra, năm xưa hắn còn bưng bít dị tượng khi Kế Đô sinh ra và sắp xếp cho Kế Đô xây hành cung ở La Miên Quận, cho thấy tầm bố cục sâu rộng."},{"id":"dao-co-hoang-ton","name":"Đạo Cổ hoàng tôn","cn":"","aliases":[],"gioiTinh":"nam","trangThai":"tu-vong","tabs":{"kinhLich":[{"chuong":"@c1933","importance":"bridge","mucCt":"gon","tieuDe":"","text":"Được Tống Thiên nhắc lại: hơn trăm năm trước bị Vương Lâm giết khi đại náo hoàng cung Đạo Cổ.","anchor":"Ngoài Vương Lâm một trăm năm trước đã đại náo hoàng cung Đạo Cổ, giết Đạo Cổ hoàng tôn"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[]},"nguon":["@c1933"]},{"id":"luc-mac","name":"Hình Phạt Lục Mặc","cn":"刑罚陆墨","aliases":["Lục Mặc","Lục"],"gioiTinh":"nam","theLuc":[{"ten":"Đạo Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","vaiTro":"Sát lục chân thân tóc đen của Vương Lâm — phân thân mang khí tức hủy diệt","tinhCach":"Lạnh lùng, quyết đoán; sắc bén trong quan sát và phán đoán; mang bản chất hủy diệt thuần túy","blurb":"Lục Mặc là sát lục chân thân tóc đen do Vương Lâm tạo ra, ngưng tụ từ hắc khí sau khi bản thể phá lỗ hổng trên tấm lưới không gian rồi xâm nhập trận pháp. Hắn trực tiếp chất vấn Đạo Cổ quốc sư, dung hợp với bản thể từ hình chiếu hư ảo trở thành tồn tại chân thật, và sau khi năm chân thân dung hợp, tái xuất dưới danh xưng Hình Phạt Lục Mặc với khí tức hủy diệt. Cuối cùng hắn bị xóa linh trí và dung hợp trở lại thân Vương Lâm bên ngoài Tiên Cương đại lục.","tabs":{"diem":[{"text":"Ngưng thành từ hắc khí, hiện thân trong không gian trận pháp trước mặt Đạo Cổ quốc sư","chuong":"@c1926"},{"text":"Chất vấn Đạo Cổ quốc sư, nhận ra đối phương ở không gian khác với trận pháp","chuong":"@c1927"},{"text":"Dung hợp với bản thể Vương Lâm, từ hình chiếu hư ảo trở thành tồn tại chân thật","chuong":"@c1928"},{"text":"Năm chân thân dung hợp, Hình Phạt Lục Mặc ra đời, phát ra khí tức hủy diệt","chuong":"@c1934"},{"text":"Mộng đạo của Lục Mặc khiến Thiên Vận Tử sụp đổ, mọi chuyện không phải giấc mộng của Vương Lâm","chuong":"@c1975"},{"text":"Bị xóa linh trí, dung hợp trở lại thân Vương Lâm bên ngoài Tiên Cương đại lục","chuong":"@c1976"}],"kinhLich":[{"chuong":"@c1934","importance":"normal","mucCt":"ky","tieuDe":"Năm chân thân dung hợp, Hình Phạt Lục Mặc ra đời","text":"Sát lục chân thân tóc đen xuất hiện sau khi La Miên nổ tung, phát ra khí tức hủy diệt, tự xưng Lục rồi Lục Mặc, ánh mắt khiến toàn bộ thị vệ hành cung và Kế Đô hoàng tử sợ hãi. Cố giãy giụa phản kháng sự chế ngự nhưng bị Vương Lâm bản thể hừ lạnh trấn áp, lôi đình, cấm chế, thái sơ, mặc diệt bản nguyên chân thân lần lượt dung nhập, ngũ hành chân thân ngàn trượng hóa bàn tay khổng lồ đè xuống. Hư ảnh La Miên dung hợp lại, bốn chân thân hoàn toàn hòa vào thân. Được Vương Lâm ban tên Lục Mặc, đạo danh Hình Phạt — từ nay thay Vương Lâm trừng phạt kẻ thù. Dung hợp hoàn toàn, bình tĩnh tuyên bố danh xưng, lạnh lùng vô tình tới cực điểm, khiến Thương Khung run rẩy, đại địa chấn động. Liếc mắt xuyên khoảng cách vô tận tới Nguyên Thủy Sơn, ánh mắt rơi lên Tống Thiên, mỏm đá nơi Tống Thiên đả tọa ầm ầm sụp đổ hóa đá vụn.","anchor":"Ta là Hình Phạt Lục Mặc!"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Bản thể — Hình Phạt Lục Mặc là chân thân thứ hai của Vương Lâm, bị bản thể chế ngự hoàn toàn","ghiChu":"@c1934"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1934"]},{"id":"ke-do-hoang-tu","name":"Kế Đô hoàng tử","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1934","importance":"bridge","mucCt":"gon","text":"Trong đại điện hành cung, run rẩy toàn thân vì nỗi sợ hãi khi sát lục chân thân quét ánh mắt qua.","anchor":"Dù là Kế Đô hoàng tử giờ phút này cũng run rẩy toàn thân, bị nỗi sợ hãi bao phủ"},{"chuong":"@c1944","importance":"bridge","mucCt":"gon","tieuDe":"Lo lắng cho nghĩa phụ Vương Lâm","text":"Được Thủy Cổ hoàng tôn thường xuyên gọi tới trong tháng 30, phát hiện điều gì đó nhưng chỉ lo lắng cho an nguy nghĩa phụ Vương Lâm. Khi phân thần thành, tự tới bên ngoài Tổ Miếu nhìn.","anchor":"lúc này hắn bất chấp việc này mà lòng tràn đầy lo lắng"},{"mucCt":"gon","text":"Được Thủy Cổ hoàng tôn chuyển giao ngôi vị hoàng đế, từ từ nắm giữ bí mật Thủy Cổ nhất mạch, thời gian kế vị chưa tới bốn mươi năm. Khi quầng sáng biến mất, sững lại giữa không trung, khẩn trương nhìn lại.","anchor":"Thân thể Kế Đô cũng sững lại ở giữa không trung, khẩn trương nhìn lại không biết rằng bàn tay mình đang nắm chặt","bridge":true,"khoang":"@c1945"},{"mucCt":"ky","text":"Kế Đô hoàn thành quá trình quá độ, được hoàng tôn cũ giao toàn bộ quân đội và quyền lực. Dù chưa làm đại lễ nhưng đã mặc hoàng bào xử lý mọi việc, sáng sớm ngày nào cũng nhìn Tổ Miếu. Năm thứ 97 hắn bỏ mọi thứ, một mình ngồi khoanh chân ngoài Tổ Miếu suốt ba năm cuối làm bạn với nghĩa phụ. Ngày đăng cơ năm thứ 100, hắn quỳ dập đầu ba lạy trước Tổ Miếu nói với nghĩa phụ rồi xoay người đi làm lễ, sứ đoàn hai tộc tới chứng kiến.","anchor":"Nghĩa phụ hài nhi đi đây.","bridge":true,"khoang":"@c1947"},{"importance":"major","mucCt":"vua","chuong":"@c1948","tieuDe":"Đăng cơ hoàng tôn Thủy Cổ","text":"Mặc hoàng bào tiến hành đại lễ đăng cơ hoàng tôn Thủy Cổ, châm Hoàng Quyền Hương khai mở nghi thức, bay lên đánh trống trận chín lần trước vạn tộc nhân quỳ bái. Trong lòng hướng về nghĩa phụ Vương Lâm, sửng sốt mừng rỡ khi thấy ánh sáng bộc phát từ pho tượng Cổ Tổ nhận ra nghĩa phụ đã thành công.","anchor":"Nghĩa phụ, hài nhi sắp trở thành hoàng tôn rồi!"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]},"diem":[{"text":"Ban đầu muốn xử trí Vương Lâm vì không quỳ, sau đó chuyển thái độ cung kính khi thấy Cổ Yêu sợ hãi","chuong":"@c1903"},{"text":"Quỳ xin Vương Lâm nhận làm nghĩa phụ, thừa nhận đã tra ra thân phận kép của Vương Lâm qua nhiều nguồn suy đoán","chuong":"@c1905"},{"text":"Tặng Vương Lâm ngọc giản chứa thần thông một chỉ cực mạnh của Cổ Tổ, sau đó phát huy tác dụng trọng yếu trong thực chiến","chuong":"@c1921"},{"text":"Được Thủy Cổ hoàng tôn chuyển giao ngôi vị hoàng đế cùng toàn bộ quân đội và quyền lực, nắm giữ bí mật Thủy Cổ nhất mạch","chuong":"@c1945"},{"text":"Mặc hoàng bào tiến hành đại lễ đăng cơ hoàng tôn Thủy Cổ, châm Hoàng Quyền Hương khai mở nghi thức","chuong":"@c1948"}]},"nguon":["@c1934","@c1943","@c1944","@c1945","@c1947","@c1948","@c1949"],"cn":"纪都","aliases":["Kế Đô"],"canhGioiCaoNhat":"Không rõ","vaiTro":"Hoàng tử cổ tộc — mưu lược gia chủ động kết giao Vương Lâm, sau đăng cơ hoàng tôn Thủy Cổ","tinhCach":"quyết đoán, thấy thế bất lợi lập tức chuyển thái độ; mưu trí, chủ động tra thân phận đối phương trước khi hành động; biết nhún mình, sẵn sàng quỳ lạy để đạt mục đích chính trị; trọng tình nghĩa, lo lắng cho an nguy nghĩa phụ","blurb":"Kế Đô hoàng tử xuất thân hoàng tộc Thủy Cổ, cưỡi cổ Yêu Đà Lạc tới Hắc Thạch thành, ban đầu coi Vương Lâm bất kính vì không quỳ trước hoàng quyền nhưng lập tức chuyển sang cung kính khi nhận ra thực lực đối phương, chủ động quỳ xin nhận làm nghĩa phụ và tặng ngọc giản chứa sức mạnh một chỉ của Cổ Tổ. Nhờ mưu lược và mối quan hệ với Vương Lâm, hắn được Thủy Cổ hoàng tôn cũ chuyển giao ngôi vị, hoàn thành quá trình quá độ quyền lực và chính thức đăng cơ hoàng tôn Thủy Cổ."},{"id":"lien-dao-chan","name":"Liên Đạo Chân","cn":"莲道真","aliases":["Tiên Hoàng Liên Đạo Chân","Tiên Hoàng đời nay"],"gioiTinh":"nam","trangThai":"tu-vong","nguon":["@c1935","@c1938"],"tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1935","text":"Hồn Tiên Hoàng vẫn bị lửa linh hồn thiêu đốt trong mật thất sau trăm năm, sự hư thối ngưng tụ thành đám nhỏ nhưng chưa trừ bỏ hoàn toàn.","anchor":"hồn này lóe lên kim quang, sự hư thối trong đó đã không còn lan tràn nữa"},{"chuong":"@c1938","importance":"normal","mucCt":"ky","tieuDe":"Bị Vương Lâm bóp chết, hồn phách dung hợp đầu lâu Tiên Tổ","text":"Hồn phách bị Vương Lâm luyện hóa trăm năm, Trớ Thuật xám còn cỡ nắm tay. Sau khi Vương Lâm xua tan Trớ Thuật, tỉnh dậy phát thần niệm oán độc nhưng vô hiệu. Bị Vương Lâm bóp chết hoàn toàn, hồn phách tan thành sương mù. Bảy đạo hồn phách bị dùng làm vật dẫn đưa vào thất khiếu đầu lâu Tiên Tổ.","anchor":"Tiên Hoàng đời nay - Liên Đạo Chân hoàn toàn tử vong"}],"diem":[{"text":"Là Tiên Hoàng đời này, đặt tên Đạo Môn cho tông phái thần bí truyền thừa từ xa xưa của quốc sư hoàng tộc","chuong":"@c1867"},{"text":"Từ trong Tiên Đạo Điện quát Đạo Phi, khẳng định La Công khiêu chiến ân công của hắn thất bại, không liên quan Đạo Phi","chuong":"@c1874"},{"text":"Cái chết trong biến cố hoàng cung bị Cửu Đế áp chế tin tức, bên ngoài chỉ biết Tiên Hoàng mất tích","chuong":"@c1898"},{"text":"Được Vương Lâm dùng làm thước đo khi nhận xét Đạo Cổ Hoàng không sánh được Tiên Hoàng về tu vi","chuong":"@c1907"},{"text":"Xuất hiện dưới dạng linh hồn suy yếu bị Vương Lâm nắm giữ, vẫn có uy áp cấp Đại Thiên Tôn","chuong":"@c1915"},{"text":"Hồn phách bị Vương Lâm luyện hóa trăm năm rồi bóp chết, dung hợp vào đầu lâu Tiên Tổ","chuong":"@c1938"}]},"vaiTro":"Tiên Hoàng đương triều — người đặt tên Đạo Môn, biến số tại đại lễ Tiên Đạo Điện","tinhCach":"uy quyền, uy áp vượt trội; quả quyết, can thiệp trực tiếp vào triều cục","blurb":"Liên Đạo Chân là Tiên Hoàng đời này, người đặt tên Đạo Môn cho tông phái thần bí truyền thừa từ xa xưa của quốc sư hoàng tộc. Hắn chết trong biến cố hoàng cung nhưng tin tức bị Cửu Đế áp chế, bên ngoài chỉ biết Tiên Hoàng mất tích. Linh hồn suy yếu của hắn bị Vương Lâm nắm giữ và luyện hóa suốt trăm năm, vẫn còn uy áp cấp Đại Thiên Tôn; cuối cùng bị Vương Lâm bóp chết, hồn phách dung hợp vào đầu lâu Tiên Tổ."},{"id":"cuu-de","name":"Cửu Đế","cn":"九帝","aliases":["Chu Lạc Cửu"],"gioiTinh":"nam","canhGioiCaoNhat":"Đại Thiên Tôn","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Đứng trên Đế Sơn quan sát bảy mươi hai thú hồn thiên ngoại gầm thét, bề ngoài bình thản nhưng nội tâm chấn kinh. Khi Hải Tử xác nhận có tồn tại Đạp Thiên nhìn xuống, sắc mặt đại biến, tu vi mất kiểm soát khiến diện mạo biến hóa bất thường. Lần đầu tiên kể từ khi thành Đại Thiên Tôn, cung kính vái lạy bầu trời, tự xưng vãn bối Chu Lạc Cửu xin toàn lực phục vụ nhưng không nhận hồi âm.","anchor":"Vãn bối Chu Lạc Cửu tham kiến tiền bối","bridge":true,"khoang":"@c1936"},{"chuong":"@c1940","importance":"normal","mucCt":"gon","tieuDe":"Chấn động trước Vương Lâm thành Đại Thiên Tôn","text":"Trên Đế Sơn Tổ Thành chấn động khi Vương Lâm thành Đại Thiên Tôn, phân tích mặt trời ba màu hắc-bạch-kim, kinh ngạc vì trăm năm hòa tan đầu lâu Tiên Tổ chưa tới Thái Cổ Thần Cảnh mà thành Đại Thiên Tôn. Liên tưởng tới ánh mắt trong vụ hỗn loạn bảy mươi hai châu, lờ mờ nghi liên quan Vương Lâm nhưng tự phủ nhận.","anchor":"Hắn là người duy nhất trong Đại Thiên Tôn của Tiên Tộc biết chân tướng khi hồn phách trong bảy mươi hai châu hỗn loạn"},{"chuong":"@c1954","importance":"normal","mucCt":"vua","tieuDe":"Chủ đạo thần thông nghịch chuyển tại chiến trường","text":"Bay tới chiến trường mười hai ngày sau trận chiến, hoài nghi người giao chiến với Cổ Đạo là Vương Lâm. Đề nghị bảy Đại Thiên Tôn hợp lực thi triển thần thông nghịch chuyển, xuất ngọc giản cho sáu người xem, cùng bắt quyết. Sau khi chứng kiến Vương Lâm thắng, nhớ lại cảnh tượng bảy mươi hai sinh linh thiên ngoại một trăm năm trước.","anchor":"Trong đầu Cửu Đế hiện lên hình ảnh bảy mươi hai sinh linh thiên ngoại một trăm năm trước ngửa mật lên trời gầm thét cầu khản"},{"chuong":"@c1955","importance":"minor","mucCt":"gon","text":"Đám người Cửu Đế đang dùng thần thông bí thuật quan sát trận chiến khi Vương Lâm đã đi tới mặt đất tiên tộc.","anchor":"Khi đám người Cửu Đế dùng thần thông bí thuật quan sát trận chiến"}],"nhanMach":[],"tuiDo":{},"tuViMoc":[],"diem":[{"text":"Hóa mặt trời trắng thành bạch lang chặn Vương Lâm, bị đánh bại bởi một cước Đại Thiên Tôn Chi Dương","chuong":"@c1896"},{"text":"Dùng Trớ Thuật trong thân làm lợi thế uy hiếp Vương Lâm, bác bỏ khả năng quy phục","chuong":"@c1897"},{"text":"Phong tỏa tin Tiên Hoàng tử vong, đưa Hài Tử về Đế Sơn bế quan ổn định đại cục","chuong":"@c1898"},{"text":"Đích thân tới Thái Cổ Thần Cảnh thăm dò, phối hợp Hải Tử ước đoán thời hạn gần 500 năm","chuong":"@c1929"},{"text":"Chấn động trước Vương Lâm thành Đại Thiên Tôn, phân tích mặt trời ba màu hắc-bạch-kim chưa có tiền lệ","chuong":"@c1940"},{"text":"Chủ đạo thần thông nghịch chuyển tại chiến trường, hoài nghi người giao chiến với Cổ Đạo là Vương Lâm","chuong":"@c1954"}]},"nguon":["@c1936","@c1940","@c1954","@c1955"],"vaiTro":"Đại Thiên Tôn tiên tộc — cường giả cao nhất phe tiên tộc tại Đế Sơn","tinhCach":"thâm trầm tính toán, biết dùng thế áp người; kiên nhẫn bế quan áp chế nội hoạn; cẩn trọng che giấu tin tức bất lợi cho đại cục; nội tâm dao động trước biến cố vượt ngoài dự liệu nhưng bề ngoài giữ bình thản","blurb":"Cửu Đế là Đại Thiên Tôn mạnh nhất trong nhóm cường giả tiên tộc trú tại Đế Sơn Tổ Thành, thân mang Trớ Thuật khó áp chế, vừa duy trì tu vi bản thân vừa gánh vác đại cục tiên tộc. Từ việc phong tỏa tin Tiên Hoàng tử vong, đưa Hài Tử bế quan, đích thân thăm dò Thái Cổ Thần Cảnh, đến chủ đạo thần thông nghịch chuyển tại chiến trường — ông tính toán từng bước nhằm ổn định cục diện. Khi Vương Lâm đột phá thành Đại Thiên Tôn với mặt trời ba màu hắc-bạch-kim chưa từng có tiền lệ, Cửu Đế chấn động sâu sắc, và cuối cùng tới Thái Cổ Thần Cảnh ôm quyền hướng Vương Lâm mà không nói lời nào."},{"id":"hai-tu","name":"Hải Tử","cn":"海子","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Ngồi phía sau Cửu Đế trên Đế Sơn, thi triển thuật bói toán — bắt quyết tạo người tí hon, cắn lưỡi phun máu tươi vào để gia tăng suy tính. Phát hiện bảy mươi hai sinh linh cảm nhận được đôi mắt của tồn tại Đạp Thiên trên bầu trời, thân thể chấn động sắc mặt tái nhợt. Sau khi Vương Lâm thu ánh mắt, run rẩy xác nhận người đó đã đi.","anchor":"Chúng cảm nhận được đôi mắt của một tồn tại Đạp Thiên đang ở trên bầu trời Tiên Cương đại lục chúng ta nhìn về phía chúng","bridge":true,"khoang":"@c1936"},{"chuong":"@c1938","importance":"bridge","mucCt":"gon","text":"Mặc bạch y đứng trên Đế Sơn, cảm nhận luồng khí tức quen thuộc nhưng hoài nghi bản thân cảm nhận sai, giữ bí mật không nói với Cửu Đế.","anchor":"Lúc trước trong khi nàng suy tính lại cảm nhận được một luồng khí tức quen thuộc."},{"chuong":"@c1940","importance":"bridge","mucCt":"gon","text":"Ngồi trên đỉnh Đế Sơn nhìn bầu trời, thần sắc phức tạp ẩn chứa tia minh ngộ khi Vương Lâm thành Đại Thiên Tôn.","anchor":"Nàng nhìn bầu trời thần sắc phức tạp lại ẩn chứa một tia minh ngộ"}],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Được Cửu Đế gọi ra tay cứu Đạo Nhất, mượn lực lượng Điệu Vong tộc can thiệp chiến cục","chuong":"@c1896"},{"text":"Dùng Liên Đạo Phi trấn áp linh hồn bảy mươi hai châu, giải thích cơ chế cấm cung cần đầu tiên tổ","chuong":"@c1897"},{"text":"Trợ giúp Cửu Đế hóa giải Trớ Thuật bằng thần thông Điệu Vong tộc sau khi trở về Đế Sơn","chuong":"@c1898"},{"text":"Tính toán ra thời hạn Thái Cổ Thần Cảnh mở hoàn toàn, thừa nhận không thể suy tính toàn bộ","chuong":"@c1928"},{"text":"Thi triển thuật bói toán trên Đế Sơn — bắt quyết tạo người tí hon, cắn lưỡi phun máu tươi","chuong":"@c1936"},{"text":"Lộ thần sắc phức tạp ẩn chứa tia minh ngộ khi Vương Lâm thành Đại Thiên Tôn","chuong":"@c1940"}]},"nguon":["@c1936","@c1938","@c1940"],"vaiTro":"Truyền nhân Điệu Vong tộc — trợ thủ bói toán và tính toán bên cạnh Cửu Đế","tinhCach":"Lạnh tĩnh, giỏi tính toán mưu lược; trung thành với Cửu Đế; hành sự có nguyên tắc, tuân thủ thỏa thuận","blurb":"Hài Tử (còn gọi Hải Tử) là thành viên Điệu Vong tộc, thường trực bên cạnh Cửu Đế trên Đế Sơn với vai trò vừa chiến đấu vừa thi triển thuật bói toán suy tính đại sự. Nàng từng mượn sức mạnh tộc mình cứu viện Đạo Nhất, dùng Liên Đạo Phi trấn áp linh hồn, trợ giúp Cửu Đế hóa giải Trớ Thuật, và phối hợp tính toán thời hạn Thái Cổ Thần Cảnh mở ra. Khi Vương Lâm thành Đại Thiên Tôn, Hài Tử trên đỉnh Đế Sơn lộ thần sắc phức tạp ẩn chứa tia minh ngộ, còn tại Tổ thành nàng được Vương Lâm lặng lẽ nhìn từ xa rồi rời đi."},{"id":"dao-nhat","name":"Đạo Nhất","cn":"道一","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1936","importance":"bridge","mucCt":"gon","text":"Vọt lên khỏi Đạo Nhất Tông hoảng sợ nhìn cây đại thụ thiên ngoại tưởng đã chết ở Sơn Hải Châu huyễn hóa ra, tự hỏi có phải Liên Đạo Phi gặp vấn đề.","anchor":"Đáng chết, Thiên Ngoại yêu thụ này không phải đã chết rồi sao"},{"chuong":"@c1940","importance":"bridge","mucCt":"gon","text":"Trong Đạo Nhất Tông gầm thét phẫn nộ xen sợ hãi khi nhận ra Vương Lâm đã trở thành Đại Thiên Tôn, nhớ lại cảnh tượng hoàng cung Tổ Thành.","anchor":"Đối với Vương Lâm, Đạo Nhất khó mà quên được cảnh tượng trong hoàng cung của Tổ Thành"},{"chuong":"@c1954","importance":"bridge","mucCt":"gon","text":"Bay tới chiến trường, do dự rồi đồng ý hợp lực thi triển thần thông nghịch chuyển, sau khi chứng kiến hình ảnh Vương Lâm thắng thì run rẩy sợ hãi.","anchor":"Tâm thần Đạo Nhất run rẩy. Hắn thân là Đại Thiên Tôn nhưng lại sợ hãi"}],"nhanMach":[],"tuiDo":{},"tuViMoc":[],"diem":[{"text":"Bị Trớ Thuật bộc phát toàn diện, huyết nhục bong tróc, phải giao đầu lâu trẻ con cho Vương Lâm để thoát thân","chuong":"@c1896"},{"text":"Mang thân thể tàn tạ về Đạo Nhất Tông bế quan, triệu tập Dược Tộc trị thương","chuong":"@c1898"},{"text":"Phẫn nộ xen sợ hãi khi nhận ra Vương Lâm đã trở thành Đại Thiên Tôn","chuong":"@c1940"},{"text":"Do dự rồi đồng ý hợp lực thi triển thần thông nghịch chuyển tại chiến trường","chuong":"@c1954"},{"text":"Run rẩy trước uy áp Vương Lâm, cảm nhận rõ sự yếu ớt của bản thân","chuong":"@c1966"},{"text":"Cung kính vái Vương Lâm, gọi Vương tôn, không chần chừ khuất phục","chuong":"@c1970"}]},"nguon":["@c1936","@c1940","@c1954"],"vaiTro":"Đại Thiên Tôn tiên tộc — tông chủ Đạo Nhất Tông, bí danh Đạo Khất","tinhCach":"Tàn nhẫn, toan tính vì lợi kỷ; kiêu ngạo nhưng biết khuất phục trước thế lực mạnh hơn; hay do dự khi đối mặt biến cố lớn","blurb":"Đạo Nhất (Đạo Khất) là Đại Thiên Tôn của tiên tộc, đứng đầu Đạo Nhất Tông. Bị Vương Lâm kích phát Trớ Thuật khiến huyết nhục bong tróc, hắn buộc phải giao đầu lâu trẻ con để thoát thân rồi về tông môn bế quan triệu tập Dược Tộc cứu chữa. Khi Vương Lâm đột phá Đại Thiên Tôn, Đạo Nhất từ phẫn nộ gầm thét chuyển sang sợ hãi, cuối cùng miễn cưỡng hợp lực thi triển thần thông nghịch chuyển tại chiến trường, rồi run rẩy trước uy áp của Vương Lâm và cung kính gọi Vương tôn."},{"id":"vo-phong","name":"Võ Phong","cn":"武峰","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1936","importance":"bridge","mucCt":"gon","text":"Ở Bắc Châu nhìn dòng sông băng khổng lồ xuất hiện giữa thiên địa, sắc mặt âm trầm hoảng sợ.","anchor":"Sự cầu khẩn đó hướng lên không trung. Nó cảm nhận được một sự tồn tại kỳ dị muốn cầu xin sự tự do"},{"chuong":"@c1940","importance":"bridge","mucCt":"gon","text":"Ở hàn băng cực bắc, hoảng hốt nhìn bầu trời rất lâu khi Vương Lâm thành Đại Thiên Tôn.","anchor":"thần sắc Võ Phong hoảng hốt nhìn bầu trời rất lâu rất lâu"},{"chuong":"@c1954","importance":"bridge","mucCt":"gon","text":"Bay tới chiến trường, nhìn dấu vết với ánh mắt phức tạp, đồng ý phát lời thề tham gia thần thông nghịch chuyển.","anchor":"Võ mỗ cũng có thể thề"}],"nhanMach":[],"tuiDo":{},"tuViMoc":[],"diem":[{"text":"Trở về dòng sông băng Bắc Châu, đóng băng toàn thân để xua trừ Trớ Thuật","chuong":"@c1898"},{"text":"Sớm phát hiện Thái Cổ Thần Cảnh trên đất Tiên Tộc, đứng trên băng sơn chờ mong dị tượng","chuong":"@c1928"},{"text":"Ở hàn băng cực bắc, hoảng hốt nhìn bầu trời khi Vương Lâm thành Đại Thiên Tôn","chuong":"@c1940"},{"text":"Bay tới chiến trường, phát lời thề tham gia thần thông nghịch chuyển, chính thức nhập cuộc","chuong":"@c1954"},{"text":"Tái ngộ Vương Lâm tại Thái Cổ Thần Cảnh, cung kính gọi Vương tôn, cảm thán tu vi của Vương Lâm","chuong":"@c1970"}]},"nguon":["@c1936","@c1940","@c1954"],"vaiTro":"Đại Thiên Tôn tiên tộc — ẩn tu tại dòng sông băng Bắc Châu, mang Trớ Thuật trong người","tinhCach":"thận trọng, ít ra tay; âm trầm, hay quan sát và suy tư trước biến cố lớn","blurb":"Võ Phong là một Đại Thiên Tôn của tiên tộc, mang trong mình Trớ Thuật nhưng có điều kiện hóa giải nhẹ hơn nhờ ít ra tay, nên chọn cách đóng băng toàn thân trong dòng sông băng tại Bắc Châu để xua trừ. Hắn là người sớm phát hiện Thái Cổ Thần Cảnh xuất hiện trên đất Tiên Tộc, âm thầm theo dõi các biến cố thiên địa từ hàn băng cực bắc. Tới giai đoạn cuối, hắn bay tới chiến trường, phát lời thề tham gia thần thông nghịch chuyển và tái ngộ Vương Lâm tại Thái Cổ Thần Cảnh."},{"id":"song-tu-dai-thien-ton","name":"Song Tử Đại Thiên Tôn","cn":"双子大天尊","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1936","importance":"bridge","mucCt":"gon","text":"Ở Tử Dương Tông bay ra nhìn thiên địa nhíu mày trước cảnh bảy mươi hai thú hồn thiên ngoại gầm thét.","anchor":"Tất cả tu sĩ trong Tiên Tộc đều nhìn thấy cảnh tượng kinh thiên động địa trên châu của mình"},{"chuong":"@c1954","importance":"bridge","mucCt":"gon","text":"Hai cô bé đã dung hợp thành một nữ tử xinh đẹp, bay tới chiến trường, thủy chung trầm mặc, cuối cùng đồng ý hợp lực thi triển thần thông nghịch chuyển.","anchor":"Nàng thủy chung trầm mặc"}],"nhanMach":[],"tuiDo":{},"tuViMoc":[],"diem":[{"text":"Được giới thiệu là Đại Thiên Tôn tọa trấn Tử Dương Tông, một trong cửu tông thập bát phái Đông Châu","chuong":"@c1822"},{"text":"Vốn là Thiên Tôn cường đại nhất nhưng sau chuyển thế linh hồn phân liệt thành hai ấu nữ Hàm Hàm và Oa Oa, thực lực suy giảm nghiêm trọng","chuong":"@c1826"},{"text":"Một mình ép lui ba Đại Thiên Tôn — Cửu Đế, Võ Phong, Đạo Nhất — để tuyên bố giữ Vương Lâm","chuong":"@c1865"},{"text":"Trực tiếp giao chiến với Tiên Hoàng trên bầu trời, giữ chân đối phương không cho can dự chiến sự bên dưới","chuong":"@c1883"},{"text":"Sau đại chiến dung hợp thành bản thể, tuyên bố chỉ vì cứu Vương Lâm chứ không can dự kế hoạch của bất kỳ ai","chuong":"@c1892"},{"text":"Hai hồn dung hợp hoàn chỉnh thành một nữ tử, bay tới chiến trường rồi chọn ở lại mặt đất Tiên Tộc đề phòng thay vì vào Thái Cổ Thần Cảnh","chuong":"@c1970"}]},"nguon":["@c1936","@c1954"],"vaiTro":"Đại Thiên Tôn Tiên Tộc — cường giả bậc nhất Đông Châu, tọa trấn Tử Dương Tông","tinhCach":"uy áp tuyệt đối, một mình ép lui nhiều Đại Thiên Tôn; trọng nghĩa với người mình chọn, chỉ cứu Vương Lâm mà không can dự đại cục; hành sự kín đáo, ẩn thân dưới hình hài hai ấu nữ sau chuyển thế; trầm mặc quả đoán, không để ngoại lực chi phối lập trường","blurb":"Song Tử Đại Thiên Tôn là vị cường đại nhất trong năm Đại Thiên Tôn của Tiên Tộc, tọa trấn Tử Dương Tông thuộc cửu tông thập bát phái Đông Châu. Sau khi chuyển thế gặp biến cố, linh hồn phân liệt thành hai ấu nữ — Hàm Hàm và Oa Oa — khiến thực lực suy giảm nghiêm trọng, nhưng nàng vẫn đủ uy để một mình ép lui ba Đại Thiên Tôn nhằm bảo toàn Vương Lâm, rồi trực tiếp giao chiến với Tiên Hoàng cùng Cửu Đế để giữ chân đối phương. Sau đại chiến, nàng trở về Tử Dương Tông bế quan dung hợp hai hồn, cuối cùng khôi phục bản thể thành một nữ tử hoàn chỉnh và gia nhập chiến trường một lần nữa, nhưng chọn ở"},{"id":"lien-dao-phi","name":"Liên Đạo Phi","cn":"莲道非","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1936","importance":"bridge","mucCt":"gon","text":"Vẫn ngủ say trong Địa Cung hoàng cung Tổ Thành, hóa thành ngọn núi trấn áp bảy mươi hai hồn thiên ngoại bình thường, được Vương Lâm nhìn thấy và muốn cứu nhưng bất lực.","anchor":"Hắn thấy Hải Tử. Thấy ngọn núi do Liên Đạo Phi hóa thành ở trong Địa Cung trong hoàng cung của Tổ Thành"}],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Bị Phàn San Mộng dụ tới Thất Đạo Tông, một mình đánh tứ đại chiến tướng, bị thiên đạo nuốt nhưng nhờ bất diệt thể vẫn sống","chuong":"@c1600"},{"text":"Được Vương Lâm triệu hồi ra trận, chống đỡ lực hủy diệt ba trăm giới sụp đổ khiến suy yếu quá nửa","chuong":"@c1671"},{"text":"Tái xuất trong trạng thái mất ký ức cũ, lúc nhận lúc không nhận ra Vương Lâm","chuong":"@c1874"},{"text":"Bị Tiên Hoàng lợi dụng huyết mạch phản tổ biến thành mắt trái Tiên Tổ, là đường lui để đoạt xá, nhưng cuối cùng thoát khỏi","chuong":"@c1893"},{"text":"Được truyền thừa bí thuật đạt cảnh giới Đại Thiên Tôn","chuong":"@c1897"},{"text":"Trở thành Tiên Hoàng mới, ở lại mặt đất tiên tộc","chuong":"@c1970"}]},"nguon":["@c1936"],"vaiTro":"Cường giả bí ẩn mang bất diệt thể — bằng hữu chí thân và ân nhân của Vương Lâm","tinhCach":"Điên cuồng ngạo mạn, dám một mình chiến quần hùng; dễ bị mỹ nhân dụ dẫn; trọng tình nghĩa, coi Vương Lâm như tri kỷ; ý chí kiên cường, nhờ bất diệt thể mà bất tử","blurb":"Liên Đạo Phi là cường giả bí ẩn sở hữu bất diệt thể và huyết mạch phản tổ của tiên tộc, đồng thời là bằng hữu chí thân và ân nhân lớn của Vương Lâm. Hắn từng bị Phàn San Mộng dụ tới Thất Đạo Tông, một mình giao chiến tứ đại chiến tướng rồi bị thiên đạo nuốt mà không diệt vong, về sau bị Tiên Hoàng lợi dụng huyết mạch phản tổ biến thành mắt trái Tiên Tổ, nhưng cuối cùng thoát khỏi đoạt xá, được truyền thừa bí thuật đạt Đại Thiên Tôn rồi trở thành Tiên Hoàng. Tính tới chương gần nhất, hắn vừa trở thành Tiên Hoàng mới, ở lại mặt đất tiên tộc."},{"id":"cuu-de-dai-thien-ton","name":"Cửu Đế Đại Thiên Tôn","cn":"九帝大天尊","aliases":["Chu Lạc Cửu"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1938","importance":"bridge","mucCt":"gon","text":"Cảm nhận dấu vết kịch biến bảy mươi hai hồn, nội tâm bất an, khát vọng cảnh giới truyền thuyết mà Cổ Đạo Đại Thiên Tôn đã đạt nhưng bản thân chưa bước tới.","anchor":"Không biết khi nào thì ta cũng có thể đạt tới bước đó…"},{"importance":"bridge","mucCt":"gon","chuong":"@c1952","text":"Một trong bốn Đại Thiên Tôn Tiên Tộc bị kinh động, hóa cầu vồng bay đi rồi sững lại kinh sợ trước luồng hút Cổ Hóa Thiên Địa.","anchor":"bốn đạo cầu vồng do đám người Cửu Đế Đại Thiên Tôn hình thành bỗng nhiên sững lại"}],"nhanMach":[],"tuViMoc":[],"diem":[{"text":"Được lão tổ Đạo Ma Tông giới thiệu là Đại Thiên Tôn bá đạo nhất Trung Châu, một trong năm tuyệt thế cường giả Tiên Tộc","chuong":"@c1826"},{"text":"Xuất hiện cứu Hải Tử trên bầu trời Sơn Hải cùng Đạo Nhất và Võ Phong, xác lập thân phận sư tôn của Hải Tử Thiên Tôn","chuong":"@c1842"},{"text":"Trên Đế Sơn đánh giá Vương Lâm hơn Minh Đạo Tôn về đạo ngộ, chiến lực và tâm cơ, rồi trực tiếp muốn thu nhận Vương Lâm làm đệ tử","chuong":"@c1864"},{"text":"Đối đầu Tiên Hoàng, vạch trần mưu đồ lợi dụng quốc sư để hấp thu đầu lâu Tiên Tổ, đồng thời công khai kế hoạch Điệu Vong Tộc","chuong":"@c1890"},{"text":"Xác nhận Hải Tử là con gái ruột của mình trước mặt Tiên Hoàng","chuong":"@c1891"},{"text":"Bế quan tại Tổ Thành Đế Sơn, cảm ứng Thái Cổ Thần Cảnh mở sớm ở Cổ Tộc","chuong":"@c1928"}]},"nguon":["@c1938","@c1952"],"vaiTro":"Đại Thiên Tôn Trung Châu — cha của Hải Tử Thiên Tôn, một trong năm tuyệt thế cường giả Tiên Tộc","tinhCach":"bá đạo, uy áp tuyệt đối; trọng đạo ngộ và chiến lực khi đánh giá người; quyết đoán bảo hộ con gái; mưu lược thâm viễn, dám đối đầu Tiên Hoàng","blurb":"Cửu Đế Đại Thiên Tôn là một trong năm tuyệt thế cường giả Tiên Tộc tại Trung Châu, được lão tổ Đạo Ma Tông đánh giá là người bá đạo nhất. Ông là sư tôn đồng thời là cha ruột của Hải Tử Thiên Tôn, từng truyền thần thông ấn ký và ban ngọc giản bảo mệnh cho nàng; trên Đế Sơn, ông quan sát Vương Lâm vượt các tầng qua phiến lá thu, đánh giá Vương Lâm hơn Minh Đạo Tôn cả về đạo ngộ lẫn chiến lực rồi đích thân muốn thu nhận làm đệ tử. Ông công khai kế hoạch Điệu Vong Tộc, đối đầu trực diện với Tiên Hoàng để vạch trần mưu đồ hấp thu đầu lâu Tiên Tổ, và sau biến cố tại Tổ Thành tiếp tục bế quan chờ Thá"},{"id":"hai-co-be-tu-duong-tong","name":"Hai cô bé Tử Dương Tông","gioiTinh":"nu","tabs":{"kinhLich":[{"chuong":"@c1940","importance":"bridge","mucCt":"gon","text":"Trong Tử Dương Tông mừng rỡ kéo tay nhau nhìn bầu trời khi Vương Lâm thành Đại Thiên Tôn.","anchor":"Vẻ mặt hai cô bé lúc này lộ vẻ mừng rỡ. Hai người kéo tay nhau đồng thời nhìn về bầu trời"}]},"nguon":["@c1940"]},{"id":"thuy-co-hoang-ton","name":"Thủy Cổ hoàng tôn","cn":"","aliases":["lão già mặc hoàng bào"],"gioiTinh":"nam","vaiTro":"Đương kim hoàng tôn Thủy Cổ nhất mạch, phụ hoàng của Kế Đô và Đại hoàng tử","tinhCach":"Thận trọng, âm trầm; tính toán sâu xa; biết thời thế mà chấp nhận dù trong lòng bất cam","blurb":"Đương kim hoàng tôn của Thủy Cổ nhất mạch, lão già mặc hoàng bào già nua. Trước sức mạnh áp đảo của Vương Lâm, dù trong mắt lộ vẻ âm trầm nhưng vẫn sáng suốt chấp nhận để con trai Kế Đô bái Vương Lâm làm nghĩa phụ. Về sau bỏ qua những ý nghĩ không thực tế, chậm rãi chuyển giao ngôi vị hoàng đế cho Kế Đô rồi lui về phía sau.","theLuc":[{"ten":"Thủy Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","tabs":{"diem":[{"text":"Dù trong lòng âm trầm khi thấy con quỳ trước Vương Lâm, cuối cùng vẫn ca ngợi việc bái nghĩa phụ","chuong":"@c1941"},{"text":"Theo dõi Vương Lâm phân thần suốt thời gian dài, thán phục khi Vương Lâm kiên trì 14 tháng, than rằng 'Không hổ là Vương tôn'","chuong":"@c1944"},{"text":"Bỏ qua ý nghĩ không thực tế, chậm rãi chuyển ngôi vị hoàng đế cho Kế Đô","chuong":"@c1945"},{"text":"Già nua, dần giao quyền lực cho Kế Đô và tại đại lễ đăng cơ tuyên bố chính thức truyền ngôi","chuong":"@c1947"}],"kinhLich":[{"mucCt":"vua","text":"Ban đầu do dự, mắt lộ vẻ âm trầm khi thấy con quỳ trước Vương Lâm, nhưng cuối cùng ca ngợi việc bái nghĩa phụ là vinh quang của Thủy Cổ nhất mạch, tự nói không phải Đạo Cổ hoàng tôn không phân biệt thị phi. Mời Vương Lâm ở lại và đồng ý cho vào Tổ Miếu.","anchor":"Trẫm không phải là Đạo Cổ hoàng tôn kia không phân biệt được thị phi bức Vương tôn đi khiến cho bộ tộc của mình gặp phải tai họa","bridge":true,"khoang":"@c1941"},{"chuong":"@c1944","importance":"bridge","mucCt":"gon","tieuDe":"Theo dõi Vương Lâm phân thần, lộ bí mật","text":"Hoàng tôn già nua than 'Không hổ là Vương tôn' khi Vương Lâm kiên trì 14 tháng. Tháng 30 thường xuyên gọi Kế Đô tới, ánh mắt ẩn chứa điều chỉ mình hắn biết. Khi phân thần thành, đứng bên cửa sổ nhìn hướng Tổ Miếu.","anchor":"Mười bốn tháng. Không hổ là Vương tôn!"},{"mucCt":"gon","text":"Bỏ qua ý nghĩ không thực tế, chậm rãi chuyển ngôi vị hoàng đế cho Kế Đô. Khi quầng sáng biến mất, từ trong hoàng cung ngẩng đầu nhìn pho tượng Cổ Tổ và hít sâu một hơi.","anchor":"chậm rãi chuyển ngôi vị hoàng đế cho Kế Đô","bridge":true,"khoang":"@c1945"},{"importance":"bridge","mucCt":"gon","chuong":"@c1947","tieuDe":"","text":"Hoàng tôn cũ đã già nua, dần giao quyền lực cho Kế Đô và tại đại lễ đăng cơ tuyên bố khi Kế Đô tới thì đó chính là giờ lành.","anchor":"Một khắc khi Kế Đô tới thì đó chính là giờ lành!"}],"nhanMach":[{"ten":"Kế Đô hoàng tử","tag":"cha-me","quanHe":"Con trai","ghiChu":"Chấp nhận Kế Đô bái Vương Lâm làm nghĩa phụ @c1941"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Nghĩa phụ của con trai","ghiChu":"Mời Vương Lâm ở lại và cho vào Tổ Miếu @c1941"},{"ten":"Đại hoàng tử","tag":"cha-me","quanHe":"Con trai","ghiChu":""},{"ten":"Hoàng Man","tag":"cha-me","quanHe":"Con trai","ghiChu":""}],"tuViMoc":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1941","@c1943","@c1944","@c1945","@c1947"]},{"id":"tong-ngoc","name":"Tống Ngọc","cn":"宋玉","aliases":["Thê tử Kế Đô"],"gioiTinh":"nu","theLuc":[{"ten":"Thủy Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Hậu nhân của Tống Thiên, nữ tử được Tống Thiên cưng chiều dạy bảo. Thê tử và hoàng hậu tương lai của Kế Đô hoàng tử.","vaiTro":"Thê tử Kế Đô, hoàng hậu tương lai Thủy Cổ nhất mạch","tinhCach":"Dịu dàng; kính nể người bề trên","tabs":{"diem":[{"text":"Hậu nhân Tống Thiên, được lão tổ Tống gia cưng chiều dạy bảo, thành hoàng hậu tương lai của Kế Đô.","chuong":"@c1942"},{"text":"Hậu nhân Tống Thiên, được Tống Thiên cưng chiều dạy bảo, trở thành thê tử Kế Đô hoàng tôn.","chuong":"@c1942"},{"text":"Hậu nhân Tống Thiên, được tuyển chọn làm thê tử Kế Đô, hoàng hậu tương lai Thủy Cổ.","chuong":"@c1942"},{"text":"Hậu nhân Tống Thiên, được gả cho Kế Đô; theo chồng quỳ bái Vương Lâm trước Tổ Miếu, nhớ lại Tống Thiên từng nhắc tên Vương tôn với vẻ kính nể.","chuong":"@c1942"}],"kinhLich":[{"chuong":"@c1942","importance":"normal","mucCt":"vua","tieuDe":"Đại hôn Kế Đô, bái kiến nghĩa phụ","text":"Trở thành thê tử Kế Đô qua đại hôn kéo dài mấy tháng. Đêm đó được Kế Đô dẫn tới trước Tổ Miếu quỳ lạy nghĩa phụ Vương Lâm, ban đầu khó hiểu nhưng cùng quỳ. Nhớ ra Tống Thiên từng nhắc tên Vương tôn với thần sắc phức tạp và kính nể.","anchor":"Nàng mơ hồ nhớ tới Tống Tôn - Lão tổ Tống gia của nàng từng có một lần vô ý nhắc tới một sự kiện, một cái tên."}],"tuViMoc":[],"nhanMach":[{"ten":"Kế Đô hoàng tử","tag":"the-thiep","quanHe":"Phu quân","ghiChu":"Đại hôn, hoàng hậu tương lai"},{"ten":"Tống Thiên","tag":"ho-hang","quanHe":"Lão tổ Tống gia, bề trên","ghiChu":"Được Tống Thiên cưng chiều dạy bảo"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Nghĩa phụ của phu quân","ghiChu":"Cùng Kế Đô quỳ trước Tổ Miếu bái kiến"},{"ten":"Kế Đô","tag":"the-thiep","quanHe":"Phu quân / hoàng tôn tương lai","ghiChu":"Đại hôn tại Thủy Cổ hoàng thành"},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Nghĩa phụ của phu quân","ghiChu":"Chưa gặp mặt trực tiếp, chỉ cùng Kế Đô quỳ bái trước Tổ Miếu."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1942","@c1943"]},{"id":"dai-thien-ton-cuc-co","name":"Đại Thiên Tôn Cực Cổ Nhất Mạch","gioiTinh":"nam","theLuc":[{"ten":"Cực Cổ Nhất Mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Đại Thiên Tôn","trangThai":"song","vaiTro":"Đại Thiên Tôn thần bí thuộc Cực Cổ Nhất Mạch, mang mặt nạ","tinhCach":"Thận trọng; bí ẩn; tự tin nhận định","blurb":"Đại Thiên Tôn thuộc Cực Cổ Nhất Mạch trong Cổ Tộc, luôn mang mặt nạ che mặt. Xuất hiện tại chiến trường Vương Lâm đối đầu Cổ Đạo cùng sáu Đại Thiên Tôn khác.","nguon":["@c1954"],"tabs":{"diem":[{"text":"Đại Thiên Tôn bí ẩn mang mặt nạ thuộc Cực Cổ Nhất Mạch, nhận định sai rằng Cổ Đạo chiến thắng.","chuong":"@c1954"},{"text":"Đại Thiên Tôn thần bí mang mặt nạ thuộc Cực Cổ Nhất Mạch, nhận định sai rằng Cổ Đạo chiến thắng.","chuong":"@c1954"}],"kinhLich":[{"chuong":"@c1954","importance":"normal","mucCt":"gon","tieuDe":"Chứng kiến chiến trường, nhận định sai","text":"Bay tới chiến trường cùng sáu Đại Thiên Tôn khác, ánh mắt rung động khi quan sát dấu vết. Nhận định sai rằng Cổ Đạo chiến thắng, sau bị thần thông nghịch chuyển chứng minh ngược lại.","anchor":"Trận chiến này hiên nhiên là cổ Đạo Đại Thiên Tôn chiến thắng"}],"tuViMoc":[],"nhanMach":[{"ten":"Cổ Đạo Đại Thiên Tôn","tag":"dong-minh","quanHe":"Cùng thuộc Cổ Tộc, coi Cổ Đạo là đệ nhất cường giả"}],"tuiDo":{}}},{"id":"thap-tam","name":"Thập Tam","cn":"十三","aliases":["Vương Thạch"],"gioiTinh":"nam","canhGioiCaoNhat":"Đỉnh bước thứ hai","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1955","importance":"major","mucCt":"ky","tieuDe":"Chuyển thế thành Vương Thạch — được Vương Lâm khôi phục ký ức","text":"Chuyển thế thành cô nhi tên Vương Thạch tại Lô Kim tông ở Vân Đào châu, tự đặt họ Vương vì cảm giác mình vốn họ Vương. Tu vi đỉnh bước thứ hai, đệ nhất nhân Lô Kim tông ngàn năm nay, sát phạt quyết đoán từng giết tu sĩ bước thứ ba. Luôn từ chối gọi đại trưởng lão là sư tôn, khi đả tọa mơ hồ thấy bóng lưng cao lớn quen thuộc. Vương Lâm xuất hiện sau lưng, điểm ngón tay vào mi tâm khôi phục ký ức — Thập Tam quỳ xuống bái kiến sư tôn, rơi lệ kích động.","anchor":"Sư. Sư tôn! Thập Tam bái kiến sư tôn!"}],"tuViMoc":[],"nhanMach":[{"ten":"Đại trưởng lão Lô Kim tông","tag":"su-mon","quanHe":"Người truyền thụ thần thông cho Vương Thạch tại Lô Kim tông","ghiChu":"Vương Thạch luôn từ chối gọi là sư tôn, cảm thấy sư tôn thật sự không phải người này"}],"tuiDo":{},"diem":[{"text":"Chỉ tu luyện Luyện Hồn Yêu Thuật ba tháng đã đạt giai đoạn ba, chế thành hồn phiên bảy thước đầu tiên","chuong":"@c0505"},{"text":"Bị phế tu vi vẫn không cam lòng, mỗi đêm chịu đau luyện thể theo pháp Cự Ma Tộc, tự phát gần đạt yêu lực nhị tinh","chuong":"@c0508"},{"text":"Nhận truyền thừa Cự Linh Cửu Tu, kích động quỳ đập đầu tôn Vương Lâm làm Lão tổ, thề cả đời trung thành","chuong":"@c0530"},{"text":"Ngồi dưới tượng đá Vương Lâm suốt hơn hai nghìn ngày đêm không nhúc nhích, canh giữ động khẩu cho sư tôn","chuong":"@c1018"},{"text":"Là người sớm nhất rời Vũ Giới, mang theo pho tượng Vương Lâm dựa cảm ứng mơ hồ khổ tìm sư tôn khắp nơi","chuong":"@c1440"},{"text":"Chuyển thế thành cô nhi Vương Thạch, được Vương Lâm khôi phục ký ức, tiếp tục theo sư tôn vào Tiên giới thi triển Cực Hỏa Đạo","chuong":"@c1955"}]},"nguon":["@c1955"],"vaiTro":"Đại đệ tử của Vương Lâm — thiên tài Luyện Hồn Yêu Thuật kiêm thủ lĩnh bộ lạc Luyện Hồn","tinhCach":"Trầm ổn kiên nghị, càng trải biến cố càng vững chí; bất khuất không cam lòng, phế tu vi vẫn tự luyện thể mỗi đêm; trung thành tận tụy tuyệt đối, nguyện theo sư tôn dù chuyển thế đầu thai; cảnh giác điềm tĩnh trong hiểm cảnh","blurb":"Kính Thập Tam là đại đệ tử của Vương Lâm, trời sinh ngộ tính với Luyện Hồn Yêu Thuật — chỉ ba tháng đã đạt giai đoạn ba. Sau khi bị phế tu vi, gã không cam lòng mà tự phát luyện thể theo pháp Cự Ma Tộc, quỳ bái Vương Lâm làm Lão tổ, nhận truyền thừa Cự Linh Cửu Tu rồi trưởng thành thành thủ lĩnh thần thông kinh người của bộ lạc Luyện Hồn, thân thể được rèn bằng máu Cự Ma Tộc và máu vương tộc Cổ Thần đến gần cảnh giới Tiên vệ Ngân Thi. Gã là người sớm nhất rời Vũ Giới mang theo pho tượng Vương Lâm khổ tìm sư tôn, cuối cùng nguyện theo sư phụ chuyển thế đầu thai, chuyển thế thành Vương Thạch rồi"},{"id":"ly-thien-mai","name":"Lý Thiến Mai","cn":"李倩梅","aliases":[],"gioiTinh":"nu","canhGioiCaoNhat":"khong-ro","trangThai":"mat-tich","tabs":{"kinhLich":[{"chuong":"@c1955","importance":"major","mucCt":"vua","tieuDe":"Vương Lâm quét toàn Tiên Cương — không tìm được ấn ký","text":"Vương Lâm khuếch tán thần thức bao phủ toàn bộ Tiên Cương đại lục nhiều lần nhưng không tìm được ấn ký của Lý Thiến Mai. Suy đoán nàng đã tự khôi phục trí nhớ kiếp trước sớm khiến ấn ký tiêu tán, tránh mặt không gặp Vương Lâm.","anchor":"Nàng là vì hắn mới tới Tiên Cương đại lục này"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"the-thiep","quanHe":"Người yêu","ghiChu":"Nàng vì hắn mà tới Tiên Cương đại lục, cô độc chuyển thế chờ đợi"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người nàng vì đó mà tới Tiên Cương đại lục, cô độc chuyển thế chờ đợi","ghiChu":"Vương Lâm quét toàn đại lục không tìm được, suy đoán nàng tránh mặt"},{"ten":"Lý Mộ Uyển","tag":"ho-hang","quanHe":"Bản thể/hồn gốc — Lý Thiến Mai là thân ảnh chuyển thế của Lý Mộ Uyển","ghiChu":"Vương Lâm tìm được hồn Lý Mộ Uyển nhưng mất thân ảnh Lý Thiến Mai"}],"tuiDo":{},"diem":[{"text":"Luận đạo cùng Vương Lâm tại Bồng Lai, đặt ba câu hỏi về thiên, đạo, ý — khởi đầu mối tri kỷ xuyên suốt","chuong":"@c1096"},{"text":"Bất chấp tông lệnh và cảnh cáo đào ngũ, rời chiến trường Yêu Tông sau trăm năm chém giết mãnh thú để tìm Vương Lâm","chuong":"@c1163"},{"text":"Bị sư tôn Phá Thiên Tông vây khốn, phá trận pháp rời tông, bị đoạn tuyệt sư đồ vĩnh viễn","chuong":"@c1200"},{"text":"Suốt mười năm hy sinh máu tươi, tinh huyết chăm sóc tượng đá Vương Lâm tại đại lục hoang dã đến kiệt quệ mất trí nhớ","chuong":"@c1214"},{"text":"Nguyện chuyển thế đầu thai chờ Vương Lâm trong luân hồi, là người cuối cùng rời đi với nụ cười","chuong":"@c1697"},{"text":"Sau khi đầu thai, cố ý ẩn mình không tản ấn ký, lặng lẽ chúc phúc Vương Lâm từ xa","chuong":"@c1969"}]},"nguon":["@c1955"],"vaiTro":"Nữ tu sĩ Phá Thiên Tông — thiên chi kiêu nữ Vân Hải tinh vực, tri kỷ của Vương Lâm","tinhCach":"ham hỏi đạo, trọng bản tâm; nặng tình và giữ hẹn; kiên định trước sư mệnh, tông lệnh; sẵn sàng hy sinh vì người mình chọn","blurb":"Lý Thiến Mai, bí danh Lý Oánh Chi, là thiên chi kiêu nữ Vân Hải tinh vực xuất thân Phá Thiên Tông, năm tuổi nhập đạo, hơn 1200 năm tu luyện đạt Toái Niết hậu kỳ. Nàng kết giao với Vương Lâm qua luận đạo tại Bồng Lai, trải trăm năm chém giết mãnh thú tại chiến trường Yêu Tông rồi bất chấp tông lệnh vượt tinh vực tìm hắn, bị đoạn tuyệt sư đồ và hy sinh máu tươi, tinh huyết chăm sóc tượng đá Vương Lâm suốt mười năm đến kiệt quệ mất trí nhớ. Sau khi dần khôi phục ký ức và được Vương Lâm tiếp nhận, nàng quyết định chuyển thế đầu thai, nguyện chờ hắn trong luân hồi; tính đến chương gần nhất, Vương L"},{"id":"thanh-thuy","name":"Thanh Thủy","cn":"清水","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1955","importance":"normal","mucCt":"gon","tieuDe":"Ấn ký mỏng manh — có thể đã tự khôi phục trí nhớ","text":"Vương Lâm phát hiện ấn ký trên người Trúc Lâm Thiên Tôn đã rất mỏng manh, nếu tu vi không cao hơn xưa thì không thể phát hiện. Có khả năng Thanh Thủy đã tự khôi phục trí nhớ kiếp trước.","anchor":"ấn ký trên người Trúc Lâm Thiên Tôn đã rất mỏng manh, khó có thể tra nổi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Thái tử Thanh Thủy Quốc, sau khi cố quốc bị diệt vong đã thức tỉnh Cực Cảnh, bảy ngày đẫm máu tàn sát kẻ thù rồi mang sát nghiệp cùng cực, tự phong ấn bản thân","chuong":"@c1462"},{"text":"Truyền thừa cho Vương Lâm hai tiên thuật đại tiên đế Hoán Vũ và Tát Đậu Thành Binh, công khai nhận Vương Lâm là sư đệ trước Lôi Tiên Điện","chuong":"@c0816"},{"text":"Dùng sát lục bổn nguyên ngưng tụ hắc kiếm phá Không Môn, đột phá Không Niết Sơ Kỳ — bước thứ ba tu hành","chuong":"@c1467"},{"text":"Hóa thân thành Vương Lâm bế quan trấn thủ đài chiến Vân Hải, bị Hư Thần Thiên Tôn trọng thương gần chết vì thay mặt sư đệ","chuong":"@c1516"},{"text":"Được xác nhận là phách thứ nhất của Thất Thải Tiên Tôn; cùng con gái Hồng Điệp bước vào chuyển thế đầu thai, nhờ Vương Lâm chiếu cố nữ nhi","chuong":"@c1696"},{"text":"Sau chuyển thế, ấn ký tự tiêu tan, khôi phục ký ức kiếp trước, rời tông môn tìm đến Thất Đạo Tông và thề cứu thê tử Hàm Yên","chuong":"@c1961"}]},"nguon":["@c1955"],"vaiTro":"Phách thứ nhất Thất Thải Tiên Tôn — sư huynh đồng mạch Bạch Phàm của Vương Lâm, Tiên Quân mang sát nghiệp viễn cổ","tinhCach":"trọng nghĩa đồng môn, nhiều lần xả thân bảo hộ Vương Lâm không tính được mất; sát phạt quyết liệt, mang sát nghiệp cùng cực từ viễn cổ; thận trọng đa nghi, không dễ tin người nhưng giữ chữ tín; nặng tình thân, nguyện cùng con gái chuyển thế đầu thai","blurb":"Thanh Thủy vốn là thái tử Thanh Thủy Quốc trong thượng cổ tu chân giới; sau khi cố quốc bị diệt vong, trong tuyệt vọng bị truy sát đã thức tỉnh Cực Cảnh, quay về tàn sát kẻ thù rồi mang sát nghiệp cùng cực, tự phong ấn bản thân. Là sư huynh đồng mạch Bạch Phàm của Vương Lâm, ông nhiều lần hiện thân bảo hộ, truyền thừa tiên thuật Hoán Vũ và Tát Đậu Thành Binh, về sau dùng sát lục bổn nguyên phá Không Môn bước vào Không Niết Sơ Kỳ. Được xác nhận là phách thứ nhất của Thất Thải Tiên Tôn; cuối cùng ông cùng con gái Hồng Điệp bước vào chuyển thế, tự khôi phục ký ức kiếp trước và thề cứu thê tử Hàm "},{"id":"chu-dat","name":"Chu Dật","cn":"朱逸","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1955","importance":"normal","mucCt":"gon","tieuDe":"Tu vi đã đề cao","text":"Vương Lâm cảm nhận tu vi Chu Dật đã đề cao.","anchor":"Chu Dật và Thanh Sương tu vi đã đề cao rồi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Thiêu đốt Nguyên Thần đột phá Vấn Đỉnh kỳ ngay trước lúc chết, giao phó Vũ Chi Tiên Kiếm và di nguyện cho Vương Lâm","chuong":"@c0293"},{"text":"Nguyên Thần nhập kiếm, hóa thành Kiếm Tiêu Chi Hồn trong Vũ Chi Tiên Kiếm","chuong":"@c0294"},{"text":"Bị phong ấn trăm năm trong Luyện Tiên Hóa Ma đại trận, linh thể hao tổn chỉ còn sót lại, vẫn cứu Vương Lâm","chuong":"@c0594"},{"text":"Hóa kiếm quang đánh thẳng Hư Không Tử, dẫn phát thương thế cũ của đối phương, linh thể hao tổn nghiêm trọng","chuong":"@c0991"},{"text":"Nhìn Thanh Sương phủ nhận và quên lãng mình, vẫn ngồi bên cạnh không rời mắt — bi kịch si tình ngàn năm","chuong":"@c1046"},{"text":"Cuối cùng đạt viên mãn hạnh phúc bên Thanh Sương sau nhiều năm khổ luyện và chờ đợi","chuong":"@c1961"}]},"nguon":["@c1955"],"vaiTro":"Phụ — si tình kiếm tu, Kiếm Tiêu Chi Hồn của Vũ Chi Tiên Kiếm, ân nhân bảo hộ Vương Lâm","tinhCach":"Si tình bền bỉ, ngàn năm không đổi dù người xưa đã quên lãng; trọng nghĩa xả thân, sẵn sàng thiêu đốt Nguyên Thần vì người; kiên nghị chịu phong ấn trăm năm không oán hận; trầm mặc bi ai trước bi kịch tình duyên không trọn nhưng vẫn thủ hộ lặng lẽ","blurb":"Chu Dật vốn là đệ tử tư chất xuất sắc của Ngũ Hành Tông xuất thân Chu Tước tinh, về sau trở thành đại trưởng lão Thi Âm Tông, cả đời mang theo nữ thi tiên nhân Đình Nhi và ôm mối si tình ngàn năm với Thanh Sương. Vì cứu Đình Nhi, y thiêu đốt Nguyên Thần đột phá Vấn Đỉnh kỳ ngay trước lúc thân thể cháy tàn, giao phó Vũ Chi Tiên Kiếm cùng di nguyện cho Vương Lâm rồi Nguyên Thần nhập kiếm hóa thành Kiếm Tiêu Chi Hồn. Từ đó, Chu Dật dĩ thân phận kiếm linh nhiều lần trợ chiến bảo hộ Vương Lâm qua vô số kiếp nạn, chịu phong ấn trăm năm không oán, đánh thương Hư Không Tử để hộ chủ, lặng lẽ theo sau T"},{"id":"thanh-suong","name":"Thanh Sương","cn":"青霜","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1955","importance":"normal","mucCt":"gon","tieuDe":"Không tu tiên — chuyển thế nhiều lần như phàm nhân","text":"Thanh Sương không chọn con đường tu tiên, giống phàm nhân chuyển thế mấy lần.","anchor":"Thanh Sương. Hắn cũng không lựa chọn con đường tu tiên mà giống như phàm nhân, chuyển thế mấy lần rồi"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Từng bày kế áp chế đối thủ khi động phủ mở ra và là người duy nhất có thể tiến vào động phủ thứ năm — cấm địa bế quan tuyệt mật của Thanh Lâm","chuong":"@c0952"},{"text":"Thân thể bị Cổ Ma Tháp Già chi phối và tranh đoạt sau khi đứng dậy trong tầng chín của tiên tháp","chuong":"@c0996"},{"text":"Hồn phách tụ lại trong thức hải Thanh Lâm, dung nhập thể Vương Lâm và thức tỉnh tại Tân Vũ Giới, hóa băng sơn","chuong":"@c1046"},{"text":"Được Vương Lâm thu hồi vận mệnh trong mặt trời thứ chín","chuong":"@c1540"},{"text":"Thần sắc lạnh lùng bước theo Thanh Lâm vào con đường chuyển thế, quay đầu nhìn Chu Dật trước khi biến mất","chuong":"@c1696"},{"text":"Không chọn tu tiên, chuyển thế nhiều lần như phàm nhân, cuối cùng ở bên Chu Dật hạnh phúc","chuong":"@c1961"}]},"nguon":["@c1955"],"vaiTro":"Tiên quân Vũ Tiên Giới — con gái Tiên Đế Thanh Lâm","tinhCach":"mưu lược, từng bày kế áp chế đối thủ và bố trí cấm địa bế quan tuyệt mật; nặng tình nhưng ẩn nhẫn, nén đau đớn trước Chu Dật; lạnh lùng, ít để lộ cảm xúc","blurb":"Thanh Sương là Tiên quân của Vũ Tiên Giới, con gái Tiên Đế Thanh Lâm — vị Tiên Đế chí tôn từng bước vào bước tu đạo thứ ba. Di thể nàng được Chu Dật gửi gắm cho Vương Lâm mang theo với hy vọng phục sinh, trải qua nhiều biến cố bị Cổ Ma Tháp Già chi phối trước khi hồn phách tụ lại trong thức hải Thanh Lâm, dung nhập thể Vương Lâm và thức tỉnh tại Tân Vũ Giới. Sau khi được thu hồi vận mệnh trong mặt trời thứ chín, nàng trở lại tiên giới với ký ức chưa hoàn toàn phục hồi, rồi bước theo Thanh Lâm vào con đường chuyển thế, không chọn tu tiên mà sống như phàm nhân qua nhiều kiếp, cuối cùng ở bên Chu"},{"id":"chu-nhu","name":"Chu Như","cn":"朱茹","aliases":[],"gioiTinh":"nu","tabs":{"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Nguyên Anh Lý Mộ Uyển đầu thai vào bào thai sơn thôn Hạnh Hoa Thôn, chuyển sinh thành Chu Như với tư chất bách mạch đều thông","chuong":"@c0314"},{"text":"Hồn phách bị Lý Mộ Uyển chấn ra khỏi nhục thân, được Vương Lâm triệu hồi sống sót, từ đó tồn tại với thân phận độc lập","chuong":"@c0381"},{"text":"Ký ức phong ấn được giải phóng tại đỉnh Chu Tước Sơn khi mở túi trữ vật Vương Lâm lưu lại","chuong":"@c0663"},{"text":"Tái ngộ Vương Lâm tại Côn Hư cảnh sau thời gian dài xa cách, đau lòng nhìn tóc bạc trắng của hắn","chuong":"@c1053"},{"text":"Được Vương Lâm thu hồi vận mệnh trong mặt trời thứ chín, thoát khỏi sự chi phối của thiên mệnh","chuong":"@c1540"},{"text":"Chuyển thế đầu thai thành thiếu nữ hơn mười tuổi tại sơn thôn Sơn Nhạc Châu, từ chối tu tiên, sống giản dị cùng cha mẹ","chuong":"@c1956"}]},"nguon":["@c1955"],"vaiTro":"Chuyển sinh phàm nhân của Nguyên Anh Lý Mộ Uyển — nghĩa nữ được Vương Lâm bảo hộ suốt nhiều kiếp","tinhCach":"Quyến luyến sâu sắc, nhiều lần bất chấp tìm kiếm Vương Lâm và không nỡ rời xa; hồn nhiên bộc trực, hay hờn dỗi giận lẫy; dã tính phóng khoáng, gắn bó với hổ Tiểu Bạch như bạn đồng hành; chí tu luyện kiên định, lấy việc tìm lại thúc thúc làm mục đích","blurb":"Chu Như là thân xác phàm nhân do Nguyên Anh Lý Mộ Uyển chuyển sinh tại Hạnh Hoa Thôn, mang tư chất tuyệt hảo bách mạch đều thông, từ nhỏ được Vương Lâm âm thầm bảo hộ rồi nuôi dưỡng trong Tiên Ngọc Bảo Tháp. Sau khi hồn phách được tách khỏi Nguyên Anh Lý Mộ Uyển và ký ức bị xóa, nàng đoàn tụ phụ mẫu rồi tự mình tu luyện đến cảnh Anh Biến, suốt đời lấy việc tìm lại thúc thúc Vương Lâm làm tâm nguyện duy nhất. Trải qua nhiều lần tái ngộ và chia ly, Chu Như cuối cùng được thu hồi vận mệnh trong mặt trời thứ chín, ở bên Vương Lâm như cô con gái trước khi quyết định chuyển thế đầu thai, tái sinh th"},{"id":"dong-tu-dau-to","name":"Đồng tử đầu to","cn":"","aliases":["Đầu to"],"gioiTinh":"nam","tabs":{"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Dẫn quân La Thiên xâm phạm Chu Tước Tinh, bị Vương Lâm đánh bại rồi phong ấn nguyên thần thu phục","chuong":"@c0838"},{"text":"Mang quá khứ bị gia tộc đuổi đi trong đêm mưa, mẫu thân phiền chán đánh đập, tạo nên tính cách cô độc trầm mặc","chuong":"@c0856"},{"text":"Định tự bạo nguyên thần khi bị sáu phân thân Khuy Niết sơ kỳ của Vu Phi dồn ép đến tuyệt vọng","chuong":"@c0853"},{"text":"Nhục thân cũ sụp đổ tại Yêu Linh chi địa, được trợ giúp ngưng tụ thân thể mới tại Chu Tước Thánh Tông","chuong":"@c1016"},{"text":"Được Vương Lâm trả hồn huyết và giải phong ấn, hoàn toàn tự do nhưng vẫn chọn ở lại","chuong":"@c1621"},{"text":"Chuyển thế thành tu sĩ đầu cực to, được Vương Lâm tìm tới khôi phục ký ức kiếp trước","chuong":"@c1959"}]},"nguon":["@c1955"],"vaiTro":"Thiên Cương tiên La Thiên — thuộc hạ trung thành của Vương Lâm","tinhCach":"ngoài mặt cười ngây ngô nhưng nội tâm thận trọng, quan sát tinh tế; trung thành tuyệt đối với Vương Lâm, sẵn sàng tự bạo nguyên thần khi nguy cấp; cô độc trầm mặc do quá khứ bị gia tộc ruồng bỏ; am hiểu cấm chế và phá trận","blurb":"Đồng tử đầu to là tu sĩ Khuy Niết thuộc La Thiên Bắc Vực, một trong số ít Thiên Cương tiên có thể khắc tên lên Phong Tiên thạch. Từ kẻ dẫn quân xâm phạm Chu Tước Tinh, hắn bị Vương Lâm đánh bại và phong ấn nguyên thần thu phục, về sau nhiều lần hộ pháp, trợ chiến và theo hầu qua vô số tử địa. Dù nhục thân cũ sụp đổ rồi được tái tạo, dù được trả hồn huyết và giải phong ấn hoàn toàn tự do, hắn vẫn chọn ở lại bên Vương Lâm, và sau khi chuyển thế vẫn được Vương Lâm tìm tới khôi phục ký ức kiếp trước."},{"id":"than-cong-ho","name":"Thân Công Hổ","cn":"申公豹","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1955","importance":"normal","mucCt":"gon","tieuDe":"Lại trở thành tông chủ một tông","text":"Thân Công Hổ sau chuyển thế lại trở thành tông chủ một tông phái.","anchor":"Thân Công Hổ? Lại trở thành tông chủ một tông!"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Dâng đạo hồn quỳ bái Vương Lâm, tự nguyện xưng Tôn Chủ và trở thành tuỳ tùng","chuong":"@c0681"},{"text":"Kiên quyết tiến cử Hứa Mộc có tư cách tranh đệ nhất nhân La Thiên Tinh Vực","chuong":"@c0808"},{"text":"Từ chối bước vào Thăng Tiên trì, giữ con đường tu đạo bản thân thay vì đổi ý cảnh thành tiên nguyên","chuong":"@c0826"},{"text":"Quyết định chuyển thế đầu thai, tới bên cạnh Vương Lâm trước khi rời đi","chuong":"@c1694"},{"text":"Sau chuyển thế lại trở thành tông chủ một tông phái","chuong":"@c1955"}]},"nguon":["@c1955"],"vaiTro":"Tuỳ tùng trung thành của Vương Lâm — Nhị cấp sứ giả Lôi Tiên Điện, người Thân Công tộc nam vực La Thiên","tinhCach":"biết nắm thời cơ nương tựa cường giả, dâng đạo hồn quy phục không do dự; sùng kính Vương Lâm đến mức cuồng nhiệt, lấy đó làm tín niệm tu hành; kiên định với con đường tu đạo bản thân, từ chối cơ duyên đổi ý cảnh; phản ứng nhanh nhạy khi lâm nguy","blurb":"Thân Công Hổ là tu sĩ Thân Công tộc ở nam vực La Thiên, Nhị cấp sứ giả Lôi Tiên Điện, tự xưng tu vi Dương Thật. Sau khi bị uy thế Vương Lâm áp chế tại Lôi Trì trong Lôi Ngục, hắn dâng đạo hồn xin nương tựa, từ đó trở thành tuỳ tùng trung thành theo Vương Lâm quan chiến và tham chiến qua nhiều biến cố lớn từ Lôi Tiên Giới sụp đổ đến tranh đoạt phong hào Nam vực. Hắn kiên quyết giữ con đường tu đạo bản thân khi từ chối bước vào Thăng Tiên trì, cuối cùng quyết định chuyển thế đầu thai và sau đó lại trở thành tông chủ một tông phái."},{"id":"hong-diep","name":"Hồng Điệp","cn":"红蝶","aliases":[],"gioiTinh":"nu","tabs":{"kinhLich":[{"chuong":"@c1955","importance":"normal","mucCt":"gon","tieuDe":"Ấn ký không cần mở","text":"Vương Lâm phát hiện Hồng Điệp qua thần thức, ấn ký trên người nàng không cần mở ra.","anchor":"Nàng là Hồng Diệp sao. Ấn kỳ kia không cần mở ra"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{},"diem":[{"text":"Sở hữu Thiên Tiên Ngũ Linh thể, tiềm năng Hóa Thần hậu kỳ đỉnh phong, từng cầm Vũ Tiên Thạch bay lên tiên giới rồi trở về với tu vi hao tổn","chuong":"@c0268"},{"text":"Giao chiến Vương Lâm nhiều lần, bị mất cánh tay phải bởi Cấm Khí Trường Thương và Tuế Nguyệt, từ chối dùng Đông Hải Chi Linh mọc lại tay để giữ ý chí","chuong":"@c0317"},{"text":"Đại chiến quyết tử tại Chu Tước quốc: triệu Băng Thần, hy sinh Anh Hài phát động Phân Thần Biến, lĩnh ngộ Tuyệt Tình ý cảnh nhưng bại trước Sinh Tử Luân Hồi của Vương Lâm","chuong":"@c0339"},{"text":"Bị Kiền Phong đoạt tuyệt tình ý cảnh cùng tứ linh, biến thành con rối trống rỗng mắt vô thần, bị đổi tên thành Tuyệt Tình","chuong":"@c0340"},{"text":"Chết dưới chiến phủ Vương Lâm — chọn không chống cự, không né tránh, mỉm cười kiêu hãnh, thân thể nứt vỡ","chuong":"@c0428"},{"text":"Hồn phách được Hồn Truyền Tống Trận bảo toàn, chuyển thế tái sinh tại Tuyết Vực; sau cùng phụ thân Thanh Thủy chuyển thế đầu thai tại tiên giới","chuong":"@c1696"}]},"nguon":["@c1955"],"vaiTro":"Thiên chi kiêu nữ Tuyết Vực — đối thủ định mệnh và nhân duyên chưa dứt của Vương Lâm","tinhCach":"Kiêu hãnh bất khuất, giữ tôn nghiêm đến tận lúc chết; hiếu chiến cố chấp, nhiều lần chủ động khiêu chiến dù biết bất lợi; tàn nhẫn quyết đoán, sẵn sàng hy sinh pháp bảo và Anh Hài để phát động tuyệt chiêu; cương liệt trọng khí tiết, từ chối phục hồi cánh tay cụt để giữ ý chí","blurb":"Hồng Điệp là nữ tu thiên tài của Tuyết Vực quốc, sở hữu Thiên Tiên Ngũ Linh thể với tiềm năng Hóa Thần hậu kỳ đỉnh phong, từng vượt tiên giới rồi trở về với tu vi hao tổn nghiêm trọng. Xuyên suốt nhiều lần giao tranh với Vương Lâm — từ đánh lén trên sa mạc, đấu pháp tại tế đàn đến đại chiến quyết tử tại Chu Tước quốc — nàng lĩnh ngộ Tuyệt Tình ý cảnh nhưng bại trước Sinh Tử Luân Hồi, rồi bị Kiền Phong đoạt ý cảnh cùng tứ linh, biến thành con rối trống rỗng và cuối cùng chết dưới chiến phủ của Vương Lâm trong tư thế không chống cự, mỉm cười kiêu hãnh. Về sau nhờ Hồn Truyền Tống Trận mà hồn phác"},{"id":"hong-sam-tu","name":"Hồng Sam Tử","cn":"红衫子","aliases":[],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c1955","importance":"normal","mucCt":"gon","tieuDe":"Chuyển thế vẫn giữ dáng vẻ cũ","text":"Vương Lâm dùng thần thức phát hiện Hồng Sam Tử sau chuyển thế vẫn giữ dáng vẻ cũ.","anchor":"Hắn hẳn là Hồng Sam Tử. Sau khi chuyển thể lại vẫn có dáng vẻ đó"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"ban-be","quanHe":"Người quen cũ","ghiChu":"Được Vương Lâm tìm thấy qua thần thức @c1955"}],"tuiDo":{},"diem":[{"text":"Được chủ nhân Phong Giới nhắc tên, lệnh Huyền Bỉnh đi tìm để thông báo ước định hợp nhất Tứ Đại Tiên Giới","chuong":"@c1233"},{"text":"Dẫn mấy vạn tu sĩ Vân Hải từ tinh không bất ngờ xuất hiện tiếp viện giới nội trong đại chiến","chuong":"@c1425"},{"text":"Lộ danh hiệu Huyết Sam Đồng Tử, phá sát giới mấy vạn năm, một mình đối đầu nhiều cao thủ bước thứ ba giới ngoại","chuong":"@c1427"},{"text":"Bị phong ấn tại Thất Thải Giới trong đại chiến thứ hai, sau đó được Vương Lâm giải cứu khỏi đạo quả giam cầm","chuong":"@c1469"},{"text":"Chọn chuyển thế đầu thai, sau đó được Vương Lâm dùng tinh quang điểm mi tâm khôi phục ký ức kiếp trước","chuong":"@c1959"}]},"nguon":["@c1955"],"trangThai":"song","vaiTro":"Cường giả Vân Hải tinh vực — người được ủy thác ước định hợp nhất Tứ Đại Tiên Giới","tinhCach":"Dũng mãnh không sợ chết, sẵn sàng xả thân vì đại cục; quyết đoán trên chiến trường, không lùi dù đối mặt cường địch áp đảo; trọng nghĩa khí, giữ sát giới mấy vạn năm nhưng phá giới khi cần; trung thành tận tụy, hết lòng phò tá Vương Lâm trong mọi trận quyết chiến","blurb":"Hồng Sam Tử, biệt hiệu Huyết Sam Đồng Tử, là cường giả Không Huyền Trung Kỳ trú tại tầng thứ nhất Vân Hải tinh vực, một trong những người được chủ nhân Phong Giới ủy thác ước định hợp nhất Tứ Đại Tiên Giới. Khi Phong Giới Đại Trận hiện hình và chiến tranh giới nội–giới ngoại bùng nổ, Hồng Sam Tử dẫn mấy vạn tu sĩ Vân Hải tiếp viện, một mình đối đầu nhiều cao thủ bước thứ ba, phá sát giới mấy vạn năm để chiến đấu, đóng vai trò then chốt trong nhiều trận quyết chiến bảo vệ giới nội. Sau đại chiến thứ hai bị phong ấn tại Thất Thải Giới, được Vương Lâm giải cứu, tiếp tục tham chiến trong các trận "},{"id":"dai-truong-lao-lo-kim-tong","name":"Đại trưởng lão Lô Kim tông","cn":"","aliases":[],"gioiTinh":"nam","trangThai":"song","canhGioiCaoNhat":"khong-ro","blurb":"Đại trưởng lão của Lô Kim tông ở Vân Đào châu, tự mình truyền thụ cho Vương Thạch (Thập Tam chuyển thế) nhưng không được hắn gọi sư tôn.","vaiTro":"Trưởng lão truyền thụ cho Thập Tam kiếp chuyển thế","tinhCach":"Kiên nhẫn; quý trọng nhân tài","tabs":{"diem":[{"text":"Tự mình truyền thụ thần thông cho Vương Thạch, muốn nhận đệ tử nhưng bị từ chối","chuong":"@c1955"},{"text":"Nhiều năm muốn nhận Vương Thạch làm đệ tử nhưng bị từ chối gọi sư tôn, vẫn kiên nhẫn truyền thụ","chuong":"@c1955"}],"kinhLich":[{"chuong":"@c1955","importance":"normal","mucCt":"gon","tieuDe":"Giao nhiệm vụ cho Vương Thạch","text":"Hiện hư ảnh giao việc ba ngày sau đưa lễ vật tới Đạo Vân tông cho Vương Thạch.","anchor":"Ngươi vẫn không chịu gọi ta một tiếng sư tôn sao"}],"tuViMoc":[],"nhanMach":[{"ten":"Thập Tam","tag":"su-mon","quanHe":"Muốn nhận Vương Thạch (Thập Tam) làm đệ tử, tự mình truyền thụ","ghiChu":"Vương Thạch không chịu gọi sư tôn"},{"ten":"Vương Thạch","tag":"su-mon","quanHe":"Đệ tử (tự nhận, chưa được gọi sư tôn)","ghiChu":"Vương Thạch chính là Thập Tam chuyển thế"}],"tuiDo":{}},"nguon":["@c1955"],"theLuc":[{"ten":"Lô Kim tông","trangThai":"gan-bo"}]},{"id":"the-tu-ke-do","name":"Thê tử Kế Đô","cn":"","aliases":[],"gioiTinh":"nữ","theLuc":[{"ten":"Thủy Cổ nhất mạch","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Thê tử của Kế Đô hoàng tử, thuộc hoàng cung Thủy Cổ.","vaiTro":"Thê tử Kế Đô, cùng hắn quan sát Vương Lâm độ kiếp.","tinhCach":[{"text":"Nhu hòa, ánh mắt dịu dàng khi nắm tay Kế Đô"}],"tabs":{"diem":[],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Kế Đô","tag":"the-thiep","quanHe":"Phu quân","ghiChu":"Cùng nhìn về Tổ Miếu khi Vương Lâm độ kiếp (@c1943)"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1943"]},{"id":"diep-mich","tabs":{"kinhLich":[{"chuong":"@c1942","importance":"bridge","mucCt":"gon","bridge":true,"khoang":"@c1942","text":"Hậu nhân của Diệp Mịch — nam tử trung niên tướng mạo rất giống Diệp Mịch từ Đạo Cổ nhất mạch tới dự đại hôn Kế Đô.","anchor":"Tướng mạo người này nếu Vương Lâm có thể nhìn thấy thì sẽ nhận ra là rất giống Diệp Mịch."}],"diem":[{"text":"Trong vùng đất cổ mộ từng hóa thân thể khổng lồ chém giết, khí tức biến đổi giữa Cổ Thần – Cổ Ma – Cổ Yêu, nhưng bị bắn rơi mắt trái khiến truyền thừa không hoàn chỉnh","chuong":"@c1481"},{"text":"Khí tức Đạo Cổ bùng phát từ chín quan tài trên tấm bia đá khổng lồ, biến đổi giữa ba dạng Cổ Thần – Cổ Ma – Cổ Yêu","chuong":"@c1576"},{"text":"Nguyên thần ẩn trong huyết ngưng tụ thành thực chất, mưu đoạt xá Vương Lâm nhưng thất bại và tiêu tán vĩnh viễn","chuong":"@c1672"},{"text":"Trái tim khổng lồ trăm trượng ở tầng cuối cổ mộ — di thể cuối cùng mang thần niệm thê lương oán hận — được truyền thừa cho Vương Lâm","chuong":"@c1680"},{"text":"Truyền thừa vẫn thiếu phần mắt trái chưa tìm được, khiến ký ức Vương Lâm nhận từ Diệp Mịch chưa trọn vẹn","chuong":"@c1729"},{"text":"Được Vương Lâm dùng làm mốc suy xét hệ thống lực lượng Cổ Tộc, thực lực được xem là tương đương Thiên Tôn","chuong":"@c1903"}]},"nguon":["@c1942"],"vaiTro":"Đạo Cổ — chủ nhân cổ mộ truyền thừa, nguồn gốc sức mạnh thể chất mà Vương Lâm thừa kế","tinhCach":"kiên ngạnh bất khuất, dù thất bại vẫn lưu lại truyền thừa cho hậu nhân; mưu tính thâm viễn, ẩn giấu nguyên thần trong huyết mưu đoạt xá người thừa kế; oán niệm dai dẳng, thần niệm thê lương tồn tại đến tận di thể cuối cùng","blurb":"Diệp Mịch, được gọi là Đạo Cổ, là chủ nhân vùng đất cổ mộ và nguồn gốc toàn bộ truyền thừa thể chất mà Vương Lâm tiếp nhận. Năm xưa từng hóa thân thể khổng lồ chém giết trong cổ mộ, khí tức biến đổi giữa Cổ Thần – Cổ Ma – Cổ Yêu, nhưng bị bắn rơi mắt trái khiến truyền thừa không hoàn chỉnh; di thể gồm đầu lâu, hai cánh tay, trái tim cùng lầu các địa phủ chứa ba thần hồn lần lượt được Vương Lâm dung hợp. Nguyên thần ẩn trong huyết từng mưu đoạt xá Vương Lâm nhưng thất bại và tiêu tán vĩnh viễn; trái tim khổng lồ trăm trượng ở tầng sâu nhất cổ mộ mang thần niệm oán hận trở thành di sản truyền th"}]};
